-- Poems batch 104
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0e6e93ae-a196-429c-bf57-cb36f714b2c2','送程給事中知越州','曾公亮','宋','宋诗','song-poetry','','[]','山陰地勝冠江吳，今得賢侯自禁途。',64,'全唐诗/poet.song.12000.json','["山陰地勝冠江吳，今得賢侯自禁途。", "侍從暫虛青瑣闥，藩宣新剖玉麟符。", "移時前席辭旒扆，不日重城歌袴襦。", "想到蓬萊游未徧，已應歸步在雲衢。"]'),
('82a94574-e9c5-42e1-8edb-366211719625','宿甘露僧舍','曾公亮','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u5199\u666f", "\u519c\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u8c6a\u8fc8", "\u5b8b\u8bd7"]','枕中雲氣千峰近，牀底松聲萬壑哀。',32,'全唐诗/poet.song.12000.json','["枕中雲氣千峰近，牀底松聲萬壑哀。", "要看銀山拍天浪，開窗放入大江來。"]'),
('0e433f64-6c34-4235-813b-d8cb167260c8','輓老蘇先生','曾公亮','宋','宋诗','song-poetry','','[]','立言高往古，抱道鬰當時。',48,'全唐诗/poet.song.12000.json','["立言高往古，抱道鬰當時。", "鉛槧方終業，風燈忽遘悲。", "名垂文苑傳，行紀太丘碑。", "後嗣皆鸞鷟，吾知慶有詒。"]'),
('fe632ee1-f15c-4ffe-b19e-acea1e570825','句','曾公亮','宋','宋诗','song-poetry','','[]','飯思白石紅桃米，菜憶黄龍紫芥心。',16,'全唐诗/poet.song.12000.json','["飯思白石紅桃米，菜憶黄龍紫芥心。"]'),
('a2ec2e1d-e3d1-428e-a25c-e9e49fc8743a','謫袁州道中寄蘇子美','張群','宋','宋诗','song-poetry','','[]','憶昨共繫吳門舟，我獨千里君獨留。',64,'全唐诗/poet.song.12000.json','["憶昨共繫吳門舟，我獨千里君獨留。", "江花粲爾不同醉，野月娟然增此愁。", "談笑還令舌本强，詩篇頓覺筆鋒柔。", "滄浪書信無消息，鴻雁來時數舉頭。"]'),
('a56b6321-76cf-4c28-a20e-4a9b81c45317','謫袁州寄子美','張群','宋','宋诗','song-poetry','','[]','去年醉到江花老，憂患相寬獨與君。',64,'全唐诗/poet.song.12000.json','["去年醉到江花老，憂患相寬獨與君。", "今日天涯又春色，却尋高處望吳雲。", "青紅染出化成寺，羅縠翻開秀水紋。", "風物感人音信少，眼前雙燕謾紛紛。"]'),
('c6044559-0c6c-4a4e-b701-857470949175','離郭店馬上迴寄鄉知','陳洎','宋','宋诗','song-poetry','','[]','迴望離亭映楚山，慨然西笑入長安。',64,'全唐诗/poet.song.12000.json','["迴望離亭映楚山，慨然西笑入長安。", "貪程野僕擔書引，惜別鄉人駐足觀。", "霞襯曙光烘積靄，柳和春雨蕩輕寒。", "遥期此地歸來日，迎取相如駟馬看。"]'),
('6a70bc25-88f4-42d2-a15a-3d56af4aa8f1','黄鵠','陳洎','宋','宋诗','song-poetry','','[]','呼樹止陵陽，逢辰下建章。',72,'全唐诗/poet.song.12000.json','["呼樹止陵陽，逢辰下建章。", "奇姿標上瑞，正色麗中央。", "昭祀祠壇畔，聲歌太液傍。", "鳳教鴻作侶，天與菊爲裳。", "神雀非靈異，流鶑愧采章。", "集汙寧我類，一舉戛雲翔。"]'),
('569b1a9a-b1ca-47e0-93c8-262f9a2aa3ad','過項羽廟','陳洎','宋','宋诗','song-poetry','','[]','八千子弟已投戈，夜帳猶聞怨楚歌。',32,'全唐诗/poet.song.12000.json','["八千子弟已投戈，夜帳猶聞怨楚歌。", "學敵萬人成底事，不思一箇范增多。"]'),
('f6bfaf1d-922f-4b38-9ef3-c6fe12926824','寄寶臣寺丞','陳洎','宋','宋诗','song-poetry','','[]','萬里扶靈宅壽阡，謝公純孝是家傳。',64,'全唐诗/poet.song.12000.json','["萬里扶靈宅壽阡，謝公純孝是家傳。", "廬開四尺成寒士，榱列三圍陋昔賢。", "先域定生連理樹，門人多廢蓼莪篇。", "我心罔極君應念，露白霜清泣昊天。"]'),
('8a63e973-0309-4cbe-b6c7-ec0a15188448','藍溪閒居','陳洎','宋','宋诗','song-poetry','','[]','白鹿原東虎候西，結廬岑寂映藍溪。',64,'全唐诗/poet.song.12000.json','["白鹿原東虎候西，結廬岑寂映藍溪。", "露侵僧履蘭三逕，春入農歌雨一犁。", "聒枕溜聲疑水宿，拂檐山色類巖棲。", "閉門養拙無人問，揭盡陳編日又低。"]'),
('18488735-2574-4bc7-9dcb-ce62b7d27d44','開元寺凌虛閣對雪寄解唐卿','陳洎','宋','宋诗','song-poetry','','[]','璚滴琳華一夜凝，凌虛雕檻曉來凭。',64,'全唐诗/poet.song.12000.json','["璚滴琳華一夜凝，凌虛雕檻曉來凭。", "眼觀銀色三千界，身到瑶臺十二層。", "玉灑砌塵供庾斛，粉融檐水妒房陵。", "化人宮好分明在，恨不同君把袂登。"]'),
('db37cc1b-22e5-49cc-b746-31f630e7f5d6','雉媒','陳洎','宋','宋诗','song-poetry','','[]','朱冠衮背一何鮮，聲厲情驕目悍然。',32,'全唐诗/poet.song.12000.json','["朱冠衮背一何鮮，聲厲情驕目悍然。", "若道物情皆錫類，雉媒爭似鴆媒賢。"]'),
('29518b42-9ee8-413c-b55d-a4f069db6f72','還劉處士先令公','陳洎','宋','宋诗','song-poetry','','[]','當年力戰蕩妖氛，十萬雄師四七勳。',64,'全唐诗/poet.song.12000.json','["當年力戰蕩妖氛，十萬雄師四七勳。", "將略妙欺班定遠，家聲高過李將軍。", "銘圖魏鼎文猶在，筆勒燕山蹟尚分。", "今日閑披有遺恨，可憐生不遇明君。"]'),
('83daaffe-5a78-431a-ae22-b49591dcb226','讀劉蕡策','陳洎','宋','宋诗','song-poetry','','[]','藥石危言治亂箴，賈生晁錯是知音。',32,'全唐诗/poet.song.12000.json','["藥石危言治亂箴，賈生晁錯是知音。", "可憐當日司文者，不畏人言合愧心。"]'),
('2a8dfb53-6ab4-4cef-ac0f-42a89efc6973','謝人惠三峰朱柿','陳洎','宋','宋诗','song-poetry','','[]','烏椑珍果益丹名，新折紅林蔕尚青。',64,'全唐诗/poet.song.12000.json','["烏椑珍果益丹名，新折紅林蔕尚青。", "漿冷夜凝仙掌露，味甘秋割楚江萍。", "圓堆玉盌櫻難並，賸薦金樽酒易醒。", "應念茂陵消渴者，整籃封貯到雲扃。"]'),
('1ceb7c5e-f2b5-44aa-936d-58c138bca1a3','過田文墓','陳洎','宋','宋诗','song-poetry','','[]','當年聞奏雍門琴，話著池臺淚滿襟。',32,'全唐诗/poet.song.12000.json','["當年聞奏雍門琴，話著池臺淚滿襟。", "何況今朝陵谷畔，池臺無迹可追尋。"]'),
('afd8c7a6-cb00-4685-990f-ac8b7bfd3408','對雪寄崔仲裕','陳洎','宋','宋诗','song-poetry','','[]','奪鶴韜霞勢漸濃，卷簾庭館好支筇。',64,'全唐诗/poet.song.12000.json','["奪鶴韜霞勢漸濃，卷簾庭館好支筇。", "乘查路闊寒凝凍，種玉畦平曉被封。", "天上瑶宮當月圃，海中銀闕聳鼇峰。", "思君不得同吟賞，知在旗亭第幾重。"]'),
('70340efc-4d53-441b-b00a-8920ab56eea5','南齊','陳洎','宋','宋诗','song-poetry','','[]','曲江歡宴侍華裾，舞拍琴歌藝有餘。',32,'全唐诗/poet.song.12000.json','["曲江歡宴侍華裾，舞拍琴歌藝有餘。", "獨有純臣王叔寶，解陳封禪一篇書。"]'),
('1d0b3002-5588-47c4-87e5-090d35ede44b','湖上逢漁者','陳洎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雨蓑烟笠洞庭秋，獨繭綸輕一葉舟。',32,'全唐诗/poet.song.12000.json','["雨蓑烟笠洞庭秋，獨繭綸輕一葉舟。", "擬共停橈醉天幕，緩歌濯足不迴頭。"]'),
('e31a4d4e-3d07-4da7-b49b-35b25d28315b','秋日端居','陳洎','宋','宋诗','song-poetry','','[]','暑退蚊雷靜，門閒雀到稀。',48,'全唐诗/poet.song.12000.json','["暑退蚊雷靜，門閒雀到稀。", "露莎蛩自急，星樹鵲何依。", "井臼貧雖樂，溪山遠未歸。", "時情似秋雁，一一背寒飛。"]'),
('665192c2-8819-43e1-942f-b167505c1181','讀子虛賦','陳洎','宋','宋诗','song-poetry','','[]','聽辭深悵不同時，及到同時位大卑。',32,'全唐诗/poet.song.12000.json','["聽辭深悵不同時，及到同時位大卑。", "爭似唐皇將頗牧，禁中言下用無疑。"]'),
('37789875-2bcd-45f0-abfc-1d92e28e639d','句  其一','陳洎','宋','宋诗','song-poetry','','[]','四壁舊貧寧畏盜，一枝雖小易容巢。',16,'全唐诗/poet.song.12000.json','["四壁舊貧寧畏盜，一枝雖小易容巢。"]'),
('053e0c54-08a2-4e98-8a27-ff4ce048557c','句  其二','陳洎','宋','宋诗','song-poetry','','[]','他年遠公社，若箇是遺民。',12,'全唐诗/poet.song.12000.json','["他年遠公社，若箇是遺民。"]'),
('24b40101-c0a0-4e44-892e-61fb448dffa0','許希','顔太初','宋','宋诗','song-poetry','','[]','京城名利塗，車馬相奔馳。',288,'全唐诗/poet.song.12000.json','["京城名利塗，車馬相奔馳。", "其間取富貴，往往輸巫醫。", "前後十數輩，身沒名已隳。", "獨有許希者，藴蓄何瑰奇。", "始自下蔡來，所處尤喧卑。", "西市三十年，汩汩無人知。", "一朝仗至藝，驟登文石墀。", "三鍼愈上疾，神速不移時。", "酬以六尚官，著籍通端闈。", "旌以三品服，佩紫垂金龜。", "于時稱謝畢，西向復陳儀。", "當宁驚且問，歷歷宣其辭。", "臣傳扁鵲術，遇主今得施。", "特此一展謝，臣心不自私。", "主上惜其意，擊賞爲噓唏。", "仍給水衡錢，國西命立祠。", "復加靈應號，金額照華榱。", "自此輦轂下，求禱何祁祁。", "我過慶成坊，見之心且悲。", "秦醫術雖妙，五腑及四肢。", "所習得其人，千齡祀不虧。", "魯聖術至大，帝道與民彝。", "所習非其人，一朝反相持。", "小吏師荀況，竊爲辨說資。"]'),
('81a5dd83-2b36-4b89-ba5b-7dc1b3e2306d','東州逸黨','顔太初','宋','宋诗','song-poetry','','[]','天之有常度，躔次絕乖離。',288,'全唐诗/poet.song.12000.json','["天之有常度，躔次絕乖離。", "地之有常理，沈潜無變虧。", "人之有常道，高下遵軌儀。", "三才各定位，萬古永不移。", "二儀設有變，修德可以祈。", "人道或反常，其亂何由支。", "昔在典午朝，國祚向陵夷。", "日向中夜出，赫赫來東陲。", "地向太極裂，中有蒼鵝飛。", "高厚災且異，人妖亦繁滋。", "始有竹林民，怪誕名不羈。", "次有夷甫輩，高談慕無爲。", "沈湎多越禮，阮籍兼輔之。", "虛名能飾詐，光逸與王尼。", "何曾有先見，不能救其衰。", "張華徒竭力，無以扶其危。", "至今西晉書，讀之堪涕洟。", "爾來歷千年，炎宋運重熙。", "東州有逸黨，尊大自相推。", "號曰方外交，蕩然絕四維。", "六籍被詆訶，三皇遭毀訾。", "坑儒愚黔首，快哉秦李斯。", "與世立憲度，迂哉魯先師。", "流宕終忘反，惡聞有民彝。"]'),
('c797b3bf-6966-4f71-ae7d-72cb3fdd1c25','壽馮北部','顔太初','宋','宋诗','song-poetry','','[]','五百年終遘聖朝，相門何日降英髦。',64,'全唐诗/poet.song.12000.json','["五百年終遘聖朝，相門何日降英髦。", "星杓影射金樞正，月魄光浮碧漢高。", "三世密傳張顥印，貳車新得呂虔刀。", "他年善繼良弓慕，金字重重有賜袍。"]'),
('1e2ae94c-08e4-4af9-9969-86b46170814b','詩一首','鮮于至','宋','宋诗','song-poetry','','[]','當時未識紫微星，獨□漁陽燕此亭。',32,'全唐诗/poet.song.12000.json','["當時未識紫微星，獨□漁陽燕此亭。", "今日園林爲勝地，好將前事載圖經。"]'),
('f66030eb-715e-4604-b6e2-0bcf91d6fa6b','題溪口廣慈寺','葉清臣','宋','宋诗','song-poetry','','[]','雲中江樹冷蕭蕭，溪上僧歸倚畫橈。',32,'全唐诗/poet.song.12000.json','["雲中江樹冷蕭蕭，溪上僧歸倚畫橈。", "誰爲秋風乘興去，松窗先聽富陽潮。"]'),
('7cce365d-546b-4439-be9a-6dcc23665992','送餘姚知縣陳最寺丞','葉清臣','宋','宋诗','song-poetry','','[]','舊見恩初渥，新遊刃久虛。',48,'全唐诗/poet.song.12000.json','["舊見恩初渥，新遊刃久虛。", "官曹鵲樹下，民版象耕餘。", "山迥人逢麂，江清客厭魚。", "送君多悵望，雲外是親居。"]'),
('90fc7f8e-496d-4a11-bd40-f63aa36483ea','送梵才大師歸天台','葉清臣','宋','宋诗','song-poetry','','[]','江水望不極，楊花江面飛。',48,'全唐诗/poet.song.12000.json','["江水望不極，楊花江面飛。", "春風自無定，遠客又言歸。", "景勝詩逾老，心冥語亦稀。", "從來林下意，爲謝北山薇。"]'),
('a039daf5-408a-4214-8853-04af45efa116','先照寺','葉清臣','宋','宋诗','song-poetry','','[]','一徑凉飈響萬松，青霞紫霧祕靈峰。',64,'全唐诗/poet.song.12000.json','["一徑凉飈響萬松，青霞紫霧祕靈峰。", "寒生列洞前溪雨，聲到諸天午夜鐘。", "仙頂月高猶駕鶴，陰潭雲起舊降龍。", "出塵境界無多地，已上金庭第七重。"]'),
('50174813-a862-4d22-baf5-5d15e218bf80','國清寺','葉清臣','宋','宋诗','song-poetry','','[]','紺宇初成國已清，千靈慈護屬仁明。',32,'全唐诗/poet.song.12000.json','["紺宇初成國已清，千靈慈護屬仁明。", "山僧了得真空觀，好續爐薰傲太平。"]'),
('fa6e21e8-e6d2-402d-a978-e7e6fa44d478','大慈寺','葉清臣','宋','宋诗','song-poetry','','[]','佛隴光沉茂草平，樹林猶作誦經聲。',32,'全唐诗/poet.song.12000.json','["佛隴光沉茂草平，樹林猶作誦經聲。", "一心三觀休分別，秋靜山高海月明。"]'),
('85419bda-8b61-4d91-b911-709b2fb5de85','題石橋','葉清臣','宋','宋诗','song-poetry','','[]','覺雄示入滅，尊者俱授記。',48,'全唐诗/poet.song.12000.json','["覺雄示入滅，尊者俱授記。", "現彼聲聞身，護此濁惡地。", "他方自感通，此地真靈祕。", "一路指橋西，誰明導師意。"]'),
('b2b57421-3440-4d69-a391-3235865f2354','遊攝山棲霞寺','葉清臣','宋','宋诗','song-poetry','','[]','仙峰多靈草，近在東北維。',120,'全唐诗/poet.song.12000.json','["仙峰多靈草，近在東北維。", "僧紹昔捨宅，總持嘗作碑。", "高風一緬邈，廢宇亦陵遲。", "清泉潄白石，霏霧蒙紫芝。", "松蘿日蕭寂，猿鳥自追隨。", "遊人尠或詣，隠者誰與期。", "支郎篤清尚，千里孤雲飛。", "覽古玩青簡，尋幽窮翠微。", "顧予荷戟守，出宿簡書違。", "憑師訪陳迹，賸作攝山詩。"]'),
('b8b2db69-3851-4640-9e24-5ab40218ee2e','東池詩','葉清臣','宋','宋诗','song-poetry','','[]','園林日將暮，緬懷池上酌。',48,'全唐诗/poet.song.12000.json','["園林日將暮，緬懷池上酌。", "輕烟隠孤嶼，綠水摇虛閣。", "人閑山鳥靜，風餘岸花落。", "稚子晚盪歸，扁舟自飄泊。"]'),
('1041f914-bad9-4afc-a7e5-3c8f4b4a953e','得請宣城府','葉清臣','宋','宋诗','song-poetry','','[]','理劇慙心計，承顔念遠遊。',48,'全唐诗/poet.song.12000.json','["理劇慙心計，承顔念遠遊。", "時情自輕外，天幸復臨州。", "霜館殘梨曉，風淮水桂秋。", "官勤詩意減，先愧謝公樓。"]'),
('56012d10-9b73-482f-a6cc-cde636e9d689','累日前伏蒙袖書臨訪并小文編及明堂圖披玩尋繹彌增景服偶書二百四十言以伸謝臆伏惟采覽','葉清臣','宋','宋诗','song-poetry','','[]','進士不讀書，明經不根義。',288,'全唐诗/poet.song.12000.json','["進士不讀書，明經不根義。", "詬病君子儒，于今作文弊。", "禮部右詞賦，諸生竊科第。", "從道不違人，追趨斯近利。", "李生何爲者，力學務遜志。", "羞恥事章句，深湛刺經藝。", "常惟天子貴，無大明堂位。", "邈焉三代風，尠矣百世繼。", "去聖日逾遠，攻端非其致。", "公玉既妄圖，戴德亦繆記。", "漢唐盛容典，規畫不足示。", "其間區區者，何暇盛德事。", "確論無甚高，闊講寖而墜。", "披文會今古，援筆攷同異。", "面勢本周官，纖悉探呂氏。", "挽拾林甫長，仰擿康成盩。", "昭發老生矇，冥符作者意。", "聖期接千統，縟禮恢萬祀。", "無文既已秩，同節此云備。", "寧當總章法，未擥雲臺議。", "廢興有時合，聰明自民視。", "成厦繄衆材，至理豈一士。", "南闕朝奏書，中朝夕鳴佩。", "行矣無自遺，日中今可熭。"]'),
('41a3d12a-8a98-4d2b-8d3e-7142010e2a10','句','韓宗彥','宋','宋诗','song-poetry','','[]','凝峰畫旛轉，交鍛彩支繁。',12,'全唐诗/poet.song.12000.json','["凝峰畫旛轉，交鍛彩支繁。"]'),
('ec40b4e7-6336-4b41-933c-6de94e87614d','送曲江知縣趙節推','余靖','宋','宋诗','song-poetry','','[]','命將久征蠻，騷然數載間。',48,'全唐诗/poet.song.12000.json','["命將久征蠻，騷然數載間。", "一言巢穴破，千里鼓旗閑。", "刀盾無私蓄，耕桑有復還。", "居民此休息，遺惠重丘山。"]'),
('82bb147d-88ad-4ba3-a02c-5edf265ddfaf','寄題廣州田諫議頤堂','余靖','宋','宋诗','song-poetry','','[]','退食公堂暇，應無俗慮侵。',48,'全唐诗/poet.song.12000.json','["退食公堂暇，應無俗慮侵。", "簾開雙燕外，吏散百花陰。", "海域逍遥境，榮途淡泊心。", "政成先養正，惠愛及民深。"]'),
('f6c6253d-1bef-479a-b5e6-62c2326cca1b','送僧惠勤歸鄉','余靖','宋','宋诗','song-poetry','','[]','舊國起歸興，三江一棹輕。',48,'全唐诗/poet.song.12000.json','["舊國起歸興，三江一棹輕。", "夜吟逢月白，曉渡趁潮平。", "楚岸雲藏寺，吳宮水繞城。", "羨師塵外去，何日濯吾纓。"]'),
('91f51fb0-b462-4316-9269-eb3585a23326','題劉太博棲心亭','余靖','宋','宋诗','song-poetry','','[]','宏搆小侯第，避權長掩關。',48,'全唐诗/poet.song.12000.json','["宏搆小侯第，避權長掩關。", "地分金穴貴，人共白雲閑。", "野色春牆外，池香暮雨間。", "燕申忘萬慮，吏隠敵箕山。"]'),
('0d0d722e-dc64-4cb2-86ff-4e8034d404ea','送薛秀才歸鄉','余靖','宋','宋诗','song-poetry','','[]','半歲接高論，一朝歸故關。',48,'全唐诗/poet.song.12000.json','["半歲接高論，一朝歸故關。", "道存慙設醴，別易忍登山。", "進即龜龍瑞，退當江海閑。", "無爲牽俗趣，碌碌利名間。"]'),
('5e87bfb2-1fb1-4c37-b1b4-5086fb0f2f73','雙松','余靖','宋','宋诗','song-poetry','','[]','自古詠連理，多爲豔陽吟。',48,'全唐诗/poet.song.12000.json','["自古詠連理，多爲豔陽吟。", "誰知抱高節，生處亦同心。", "風至應交響，禽棲得並陰。", "歲寒當共守，霜雪莫相侵。"]'),
('babcf9ba-b570-4b67-8726-c87e83f5d799','新息道中遇雪','余靖','宋','宋诗','song-poetry','','[]','寒深雪壓春，去去祗傷神。',48,'全唐诗/poet.song.12000.json','["寒深雪壓春，去去祗傷神。", "巢穴有歸鳥，路岐無住人。", "遠光天共白，夜色月相親。", "獨酌不成醉，自嫌名利身。"]'),
('809ab869-6911-4da8-8302-e1d7784fe46d','次韵酬孫明復見寄','余靖','宋','宋诗','song-poetry','','[]','門外車塵絕，樽前俗慮無。',48,'全唐诗/poet.song.12000.json','["門外車塵絕，樽前俗慮無。", "輕身脫羈絆，曳尾得泥塗。", "出處天真在，炎凉物性殊。", "寄言欽雅意，相望隔江湖。"]'),
('bf2ba935-1ddf-40f6-a601-2a285f2e025a','送海琳遊南海','余靖','宋','宋诗','song-poetry','','[]','觸目盡塵累，如師真不羣。',48,'全唐诗/poet.song.12000.json','["觸目盡塵累，如師真不羣。", "圓明水中月，去住嶺頭雲。", "意爲乘風快，名應過海聞。", "翛然此高迹，世網慢紛紛。"]'),
('44abe85d-2b71-4e4e-9e33-41b823c34c97','荔香亭','余靖','宋','宋诗','song-poetry','','[]','虛亭何所賞，爲愛果中奇。',48,'全唐诗/poet.song.12000.json','["虛亭何所賞，爲愛果中奇。", "氣稟南方秀，生當火王時。", "渡淮嫌橘變，經庾笑梅衰。", "不共花爭豔，殘鶑莫傍枝。"]'),
('445cc792-79d9-4953-b110-42d5ec6e8bf1','送容州杜祕丞','余靖','宋','宋诗','song-poetry','','[]','官滿一舟歸，高懷俗背馳。',48,'全唐诗/poet.song.12000.json','["官滿一舟歸，高懷俗背馳。", "家藏唯翰墨，民政在聲詩。", "氣勁秋霜並，吟多夜月知。", "知賢無路薦，何以報明時。"]'),
('88faf576-68ea-4512-84a5-29b8db82aae7','謝連州沈殿丞惠石','余靖','宋','宋诗','song-poetry','','[]','遺我巖巖石，拜嘉賢使君。',48,'全唐诗/poet.song.12000.json','["遺我巖巖石，拜嘉賢使君。", "何當天共補，應免玉偕焚。", "想自乘槎得，知從飲羽分。", "試將簷畔累，尚带故山雲。"]'),
('d74b6c9a-2fc2-4522-b553-689b23bebc87','寄題寶峰山玩雲亭','余靖','宋','宋诗','song-poetry','','[]','指月猶爲幻，玩雲應强名。',48,'全唐诗/poet.song.12000.json','["指月猶爲幻，玩雲應强名。", "遥思一雨潤，能使六塵清。", "望岫幽人興，觀空達士情。", "何當扣禪闥，高論俯軒楹。"]'),
('0593d4b9-8ebd-4bab-94a0-a3a6c382b8b0','留題龍光禪剎呈周長老','余靖','宋','宋诗','song-poetry','','[]','尋幽逢勝地，方外趣無垠。',48,'全唐诗/poet.song.12000.json','["尋幽逢勝地，方外趣無垠。", "雙澗流寒月，千峰鎖暮雲。", "路盤塵境斷，世係祖燈分。", "却媿留題處，猶須說見聞。"]'),
('e19a9198-d8c0-49a5-9bef-d81faee1b991','送峽州推官','余靖','宋','宋诗','song-poetry','','[]','决科讎漢策，佐郡得荆關。',48,'全唐诗/poet.song.12000.json','["决科讎漢策，佐郡得荆關。", "地勝詩鋒銳，兵銷檄筆閑。", "路岐高鳥外，城郭白雲間。", "婉畫應餘刃，何人薦禰還。"]'),
('80c2c015-5501-48c5-8b3a-914667882caf','留題澄虛亭','余靖','宋','宋诗','song-poetry','','[]','湖光湛寒碧，簾影拂莓苔。',48,'全唐诗/poet.song.12000.json','["湖光湛寒碧，簾影拂莓苔。", "魚戲應同樂，鷗閑亦自來。", "雨餘輕靄合，竹外雜花開。", "久欲留詩去，慚無綺靡才。"]'),
('67c698ea-2865-484e-a2c4-d1bcb068519c','靈樹喜長老屬疾見寄次韵酬之','余靖','宋','宋诗','song-poetry','','[]','鳴韶山下客，多病似吾身。',48,'全唐诗/poet.song.12000.json','["鳴韶山下客，多病似吾身。", "每想彌天辯，誰爲問疾人。", "泉清偏照月，松瘦不知春。", "未遂尋高論，相遥一水濱。"]'),
('232e3f40-8e01-48cf-98e9-a61ebf4d0b6b','和伯恭殿丞登武江門樓懷楊叔武太保','余靖','宋','宋诗','song-poetry','','[]','徙倚江邊檻，旌旗望處遥。',48,'全唐诗/poet.song.12000.json','["徙倚江邊檻，旌旗望處遥。", "交情深慕藺，風韵渴聞韶。", "寄遠緘靈藥，迎歸艤畫橈。", "伏波新蕩寇，氣入嶺雲飄。"]'),
('2601bde1-c1d3-4db7-9b17-965a88638c8e','同李祕校譚員外宿月華上方','余靖','宋','宋诗','song-poetry','','[]','上方逢夏夕，月色遍千山。',48,'全唐诗/poet.song.12000.json','["上方逢夏夕，月色遍千山。", "但覺星河近，偶同江海閑。", "事拋興廢外，談極有無間。", "却笑明朝俗，紅塵隨馬還。"]'),
('9db8d222-94d1-4f86-9c6d-941572453a23','同李祕校譚員外月華長老謁慈濟禪師會宿寶林道場','余靖','宋','宋诗','song-poetry','','[]','祖堂留勝迹，再宿此登臨。',48,'全唐诗/poet.song.12000.json','["祖堂留勝迹，再宿此登臨。", "雲月自明暗，山川無古今。", "谷聲猿嘯遠，泉脈虎跑深。", "共到忘言處，休論佛與心。"]'),
('1acdb6a9-4cc7-4001-97ae-188a245011a8','送施屯田知太平州','余靖','宋','宋诗','song-poetry','','[]','天閣漢郎居，新榮刻兔符。',48,'全唐诗/poet.song.12000.json','["天閣漢郎居，新榮刻兔符。", "趨曹蘭在握，到境弩先驅。", "地望遥分楚，州封半入吳。", "仙科存俊望，歸路約蓬壺。"]'),
('625c6032-53df-469f-bd71-304dd2b0feff','送欒駕部','余靖','宋','宋诗','song-poetry','','[]','賦政古循良，恩威著一方。',72,'全唐诗/poet.song.12000.json','["賦政古循良，恩威著一方。", "疲民戀冬日，黠吏畏秋霜。", "直道經摧折，公心愈激昂。", "米鹽躬細務，繩墨謹周防。", "度嶺囊裝簡，攀轅父老忙。", "採詩如有詔，持此續甘棠。"]'),
('06b52e42-7afb-421c-a051-49f31b5f8d56','寄題田待制廣州西園','余靖','宋','宋诗','song-poetry','','[]','善政徧修舉，增完池館清。',96,'全唐诗/poet.song.12000.json','["善政徧修舉，增完池館清。", "地含春氣早，月映暮潮生。", "石有羣星象，花多外國名。", "與民同雉兔，邀客醉蓬瀛。", "翰墨資吟興，雲泉適野情。", "鎮應持左蟹，快欲鱠長鯨。", "積靄藏樓閣，馴鷗識旆旌。", "甘棠留美蔭，高倚越王城。"]'),
('dafa7572-cc67-4957-952e-268afeb3e28c','酬和蘇夢得運使','余靖','宋','宋诗','song-poetry','','[]','選任逢明主，休嗟尚散郎。',96,'全唐诗/poet.song.12000.json','["選任逢明主，休嗟尚散郎。", "遠均天雨露，全撫越封疆。", "早振連城價，嘗陪照乘光。", "宦途更險易，人事變炎凉。", "遽喜輶軒至，同期遠俗康。", "交情重推致，民意樂舒長。", "況有江山助，無懷節物傷。", "罇前且歡醉，一別久相望。"]'),
('fc28cb4a-9567-4be7-a2cd-9dca609ea5ad','塞上','余靖','宋','宋诗','song-poetry','','[]','漢使重頒朔，胡臣舊乞盟。',48,'全唐诗/poet.song.12000.json','["漢使重頒朔，胡臣舊乞盟。", "烽煙虛晝望，刁斗絕宵驚。", "虎落雲空鎖，龍堆月自明。", "祁連山更北，新築受降城。"]'),
('29717e6a-f22c-421a-903d-b84f336fa453','送李廷評知福清縣','余靖','宋','宋诗','song-poetry','','[]','世閥茂儒紳，甌閩寵命新。',48,'全唐诗/poet.song.12000.json','["世閥茂儒紳，甌閩寵命新。", "縣圖遥盡海，鄉樹密藏春。", "供帳鶑將老，登車雉已馴。", "行聞趨召節，舊美政如神。"]'),
('0062889b-9a16-4678-9d5a-487af41b585a','子規','余靖','宋','宋诗','song-poetry','','[]','一叫一聲殘，聲聲萬古冤。',48,'全唐诗/poet.song.12000.json','["一叫一聲殘，聲聲萬古冤。", "疏煙明月樹，微雨落花村。", "易墮將乾淚，能傷欲斷魂。", "名韁慙自束，爲爾憶家園。"]'),
('c3d7989e-2df6-408a-978f-dfa03e148f92','桂源早行','余靖','宋','宋诗','song-poetry','','[]','聞雞已行邁，策馬更徘徊。',48,'全唐诗/poet.song.12000.json','["聞雞已行邁，策馬更徘徊。", "月色依山盡，秋聲带雨來。", "自堪悲玉璞，誰復築金臺。", "薄宦空羈束，西齋長綠苔。"]'),
('cff2b8fe-5dce-4e27-9573-f60caac8a995','桂源曉別秦玨河隄','余靖','宋','宋诗','song-poetry','','[]','迴館逢清論，長亭慘別襟。',48,'全唐诗/poet.song.12000.json','["迴館逢清論，長亭慘別襟。", "亡羊南北路，躍馬利名心。", "酒市摇風幟，花村鎖霧林。", "行行俱得意，結綬有知音。"]'),
('de36dafe-a916-4e65-89c2-5a988f5b45b5','山館','余靖','宋','宋诗','song-poetry','','[]','野館蕭條晚，憑軒對竹扉。',48,'全唐诗/poet.song.12000.json','["野館蕭條晚，憑軒對竹扉。", "樹藏秋色老，禽带夕陽歸。", "遠岫穿雲翠，畬田得雨肥。", "淵明誰送酒，殘菊遶牆飛。"]'),
('9a326644-52b3-44a8-88a3-b3aff4592878','微凉','余靖','宋','宋诗','song-poetry','','[]','鮫綃蟬翅薄，湘簟水紋流。',48,'全唐诗/poet.song.12000.json','["鮫綃蟬翅薄，湘簟水紋流。", "雨送三金伏，風生一葉秋。", "檀欒疏影亂，菡萏遠香浮。", "飛蓋宜清夜，天高挂玉鈎。"]'),
('18c55090-645d-4eaf-8e52-f4ed4e0d5b23','晚至松門僧舍懷寄李太祝','余靖','宋','宋诗','song-poetry','','[]','日暮倦行役，解鞍初息肩。',48,'全唐诗/poet.song.12000.json','["日暮倦行役，解鞍初息肩。", "霧昏臨水寺，風勁欲霜天。", "蓼浦初聞鴈，人家半在船。", "思君正怊悵，黄葉正翩翩。"]'),
('fac660ed-67ff-4688-a4c5-288c6defb8e0','湘中送人','余靖','宋','宋诗','song-poetry','','[]','離謳方揭耳，別緒已凄然。',48,'全唐诗/poet.song.12000.json','["離謳方揭耳，別緒已凄然。", "草蔚湘纍浦，花殘蜀魄天。", "嶷山晴拂漢，啼竹冷澄煙。", "後夜思君意，空歌皓月篇。"]'),
('65d7156b-adbe-4304-80a2-32cb561d28b9','慧照大師','余靖','宋','宋诗','song-poetry','','[]','已向南宗悟，尤於外學精。',48,'全唐诗/poet.song.12000.json','["已向南宗悟，尤於外學精。", "士林傳字法，僧國主詩盟。", "初地形容古，彌天語論清。", "因君支遁輩，徒擅養鷹名。"]'),
('e8c5d009-9abe-45b0-ad07-b49da2e746d8','遊水南寺','余靖','宋','宋诗','song-poetry','','[]','雙剎聳浮雲，層軒絕世塵。',48,'全唐诗/poet.song.12000.json','["雙剎聳浮雲，層軒絕世塵。", "松溪千蓋雨，茶圃一旗春。", "夜梵龕燈暗，朝香篆火新。", "暫來猶永日，堪羨白蓮人。"]'),
('079f1fc6-de9f-4668-b006-29eed479d53e','暮春','余靖','宋','宋诗','song-poetry','','[]','草带全鋪翠，花房半墜紅。',48,'全唐诗/poet.song.12000.json','["草带全鋪翠，花房半墜紅。", "農家榆莢雨，江國鯉魚風。", "堤柳綿爭撲，山櫻火共烘。", "長安少年客，不信有衰翁。"]'),
('f8c2bd3d-161f-470c-b1a0-9661e7dd81d6','宿山觀','余靖','宋','宋诗','song-poetry','','[]','孤枕秋宵永，山寒夢不成。',48,'全唐诗/poet.song.12000.json','["孤枕秋宵永，山寒夢不成。", "殘燈背窗影，急雨带溪聲。", "未分山中老，空思日下名。", "區區如逆旅，此際若爲情。"]'),
('d8537bb5-ae8f-408f-a0df-6add9da1ffb4','和伯恭殿丞遊西蓉山寺','余靖','宋','宋诗','song-poetry','','[]','休澣約過從，寧論隘與恭。',216,'全唐诗/poet.song.12000.json','["休澣約過從，寧論隘與恭。", "溪光染醽淥，山色秀芙蓉。", "乍霽千絲雨，齊張萬蓋松。", "岫孤如欲遁，逕曲似相逢。", "共怏雲霞志，更尋麋鹿蹤。", "氅披吳國紵，杖拄蜀郊筇。", "奕布東西剎，鱗差遠近峰。", "禽喧五色聚，鐘迥六時樁。", "興廢雖留目，榮枯莫蕩胸。", "忽驚雷出地，未省雪經冬。", "陰谷鳴歸鶴，靈湫起應龍。", "跳梁窺果狖，縹緲入花蜂。", "磴滑并蘿躡，巖幽半蘚葑。", "竹間泉繚繞，煙外草蒙茸。", "民樂謳謠洽，春和氣象濃。", "吟多資雅興，望極動離悰。", "有語嫌雙燕，無虞羨大槦。", "歸來却回睇，暮霧已重重。"]'),
('17979779-c8aa-43a2-b7b6-7f12765caaa1','送岳師歸贛川','余靖','宋','宋诗','song-poetry','','[]','千里起歸思，翛然物外身。',48,'全唐诗/poet.song.12000.json','["千里起歸思，翛然物外身。", "海山經處霧，梅嶺到時春。", "藥更開新楮，庭應長舊筠。", "年衰重方術，聊此送行人。"]'),
('460d5c67-3b46-435a-8c71-9cbc3ff5041a','謝伯恭篆屏蟾硯','余靖','宋','宋诗','song-poetry','','[]','古硯蟾蜍滴，文屏薤葉書。',24,'全唐诗/poet.song.12000.json','["古硯蟾蜍滴，文屏薤葉書。", "世間多倚伏，休歎橐中虛。"]'),
('b7c62fc9-7a77-407a-a50e-918d6ab08de5','享廟詩','余靖','宋','宋诗','song-poetry','','[]','祼獻遵彝典，時思展聖謨。',72,'全唐诗/poet.song.12000.json','["祼獻遵彝典，時思展聖謨。", "猗那百世祀，孝愛萬邦孚。", "禮盛郊丘配，感因霜露濡。", "承祧光德劭，進冊報仁劬。", "想見先猷遠，恢弘介福俱。", "明靈欽至治，純嘏被歡呼。"]'),
('5a53766a-d6c0-421d-94e2-be0e0a68a244','禋郊詩','余靖','宋','宋诗','song-poetry','','[]','函夏恢文治，禋燔講禮隆。',72,'全唐诗/poet.song.12000.json','["函夏恢文治，禋燔講禮隆。", "物兼明德薦，天以至誠通。", "制度親祠盛，威儀陟配崇。", "戎容儼仙仗，霽色照郊宮。", "國典書昭事，神禧報屢豐。", "端闈宣大號，王澤浸無窮。"]'),
('0f43b301-7506-417e-a95d-dab3b0be1340','仁宗皇帝挽詩二首  其一','余靖','宋','宋诗','song-poetry','','[]','丕承三后績，盛烈古難陪。',48,'全唐诗/poet.song.12000.json','["丕承三后績，盛烈古難陪。", "納諫書囊集，談經殿閣開。", "御弧圓月滿，宸翰舞鸞回。", "冠劍雖歸葬，英風萬祀恢。"]'),
('cd01a176-8113-4507-8dc2-479ab0a01169','仁宗皇帝挽詩二首  其二','余靖','宋','宋诗','song-poetry','','[]','四十載居尊，勤勞滌化源。',48,'全唐诗/poet.song.12000.json','["四十載居尊，勤勞滌化源。", "精禋敦舜孝，至治布堯言。", "武尚包戈節，刑寬解網恩。", "遺弓初奉諱，雨淚徧乾坤。"]'),
('e6a0beb3-361e-45d2-b6e9-838356157260','遊韶石','余靖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','世務常喧囂，物外有真賞。',288,'全唐诗/poet.song.12000.json','["世務常喧囂，物外有真賞。", "結友探勝槩，放情諧素想。", "韶山南國鎮，靈蹤傳自曩。", "雙闕倚天秀，一徑尋雲上。", "長江遠縈带，衆巒疑負襁。", "千里眇平視，萬形羅怪象。", "日影避崑崙，鼇頭冠方丈。", "青螺佛髻高，羣玉仙都敞。", "霞城晴煜爚，桃溪春浩蕩。", "仰攀霄漢近，俯瞰神魂怳。", "澗深溜如織，巖虛動成響。", "造化與真質，妙畫胡能倣。", "賤子生海隅，逢辰辱朝奬。", "靡成彝鼎勳，甘從丘壑往。", "驚禽戀故林，困驥畏羈鞅。", "茲遊得幽深，同懷樂清曠。", "世言帝有虞，朔南聲教廣。", "丹冥卜巡幸，翠華臨蒼莽。", "簫韶曾此奏，鐘石無遺像。", "但覺薰風存，翛然天籟爽。", "姬公著治典，歷代所遵仗。", "九野奠山川，萬靈通肸蠁。", "醫閭與吳嶽，半列戎夷壤。", "四時迎氣祠，猶煩禮官掌。"]'),
('74820560-0580-497f-a8b6-89edff7f6149','南齋新植牡丹初冬忽開數朵愛玩不已因而感咏呈知郡中舍','余靖','宋','宋诗','song-poetry','','[]','嶠南足暄候，秋葉不凋霜。',192,'全唐诗/poet.song.12000.json','["嶠南足暄候，秋葉不凋霜。", "孤根自北來，繡蘂忽葩張。", "嗟爾本國艷，秀色含天香。", "淑氣入春萼，園苑生輝光。", "豪家走鈿車，珠翠妍新妝。", "貴門陳廣宴，金碧開華堂。", "惟恐風雨至，不羞歌舞狂。", "意態占韶景，衆媚曷能妨。", "今茲植荒圃，空齋圍短牆。", "節物寒蟬後，林木野梅傍。", "胡爲吐奇卉，特此昧溫凉。", "祇知逢日暖，豈測非春陽。", "蜂蝶不爾採，壞欄啼夜螿。", "伊予久杜門，荆榛三徑荒。", "獨酌難成醉，徙倚徒徬徨。", "憐爾守常性，幽叢不改芳。"]'),
('c7ddd303-8d7e-486a-a9c8-50df37fd3574','遊山五題 題白蓮庵','余靖','宋','宋诗','song-poetry','','[]','掩室昔宴居，冥心遺萬化。',72,'全唐诗/poet.song.12000.json','["掩室昔宴居，冥心遺萬化。", "菡萏本無染，紛華共高謝。", "夜禪杉月落，晨齋庭鳥下。", "棟間雲氣浮，地面秋香詫。", "演法辭故棲，幽蹤賁寒野。", "蠟屐此同遊，願結宗雷社。"]'),
('e878d45d-5947-4cdd-8da7-17013c583b71','遊山五題 題憩賢亭','余靖','宋','宋诗','song-poetry','','[]','虛亭遲嘉客，登臨日相繼。',48,'全唐诗/poet.song.12000.json','["虛亭遲嘉客，登臨日相繼。", "松篁夏吹寒，煙霞暮江霽。", "高興山光遠，急影波聲細。", "區區榮利途，扁舟暫時憩。"]'),
('5e8b3ed6-889b-4e39-89b9-74fcd88550ae','遊山五題 贈青林菴主','余靖','宋','宋诗','song-poetry','','[]','佛性深如海，中邊見各異。',96,'全唐诗/poet.song.12000.json','["佛性深如海，中邊見各異。", "道在有無間，語論皆兒戲。", "幾多名利僧，妄習諸家氣。", "貪嗔尚纏牽，生滅何由離。", "三世古今佛，豈離根本智。", "捨此覓菩提，誰證菩提位。", "吾師識自心，有爲皆委棄。", "冥坐不知年，了了忘言意。"]'),
('105a0af4-3f8a-4205-8cfe-0064640dd6de','遊山五題 遊大峒山','余靖','宋','宋诗','song-poetry','','[]','十里松檜風，萬仞斗峭壁。',120,'全唐诗/poet.song.12000.json','["十里松檜風，萬仞斗峭壁。", "陽崖雷自奔，陰壑雪猶積。", "勢爭衡霍雄，地控楚越扼。", "胡爲千載間，名未光圖籍。", "物乃因人彰，聞人於在昔。", "不逢巢許高，箕山亦頑碧。", "我今共遊覽，逍遥非俗格。", "劇論窮古今，玄談叩虛寂。", "攀蘿躡孤峰，和雲坐幽石。", "濯纓清泠泉，留爲不朽迹。"]'),
('75a63309-875b-481f-a078-ea8153dd31a5','遊山五題 留題龍潭','余靖','宋','宋诗','song-poetry','','[]','峭嶺盤遠郊，幽泉生石罅。',96,'全唐诗/poet.song.12000.json','["峭嶺盤遠郊，幽泉生石罅。", "沮洳成深潭，神龍隠其下。", "氣昏雲霧朝，光寒風雨夜。", "絕境鄰梵宮，餘波沃農稼。", "秋態月色澄，晴蛟虹影射。", "勢非蛟室卑，名將鳳池亞。", "存身此蟠蟄，得時扶造化。", "何當歲大旱，移湫救函夏。"]'),
('2c0fe935-4714-44b6-8f96-cbb1dbf7dd5d','送陳京廷評','余靖','宋','宋诗','song-poetry','','[]','曲江居嶺阨，楚越封疆間。',120,'全唐诗/poet.song.12000.json','["曲江居嶺阨，楚越封疆間。", "異時置冶官，歲入不盈萬。", "將漕擇材能，招徠委成算。", "扇橐大野烘，鑿礦重崖斷。", "閩吳荆廣人，奔走通昏旦。", "千夫即山鑄，畢給未酬半。", "三監居江湄，僦輦日充羨。", "地官奏計最，遂爲天下冠。", "嘗聞卜大夫，名聲傳史漢。", "素履騁修程，逸足何由絆。"]'),
('ac9c6177-d275-4456-ab9e-c54435dc655b','酬黄都官舟次近垌見寄次韵','余靖','宋','宋诗','song-poetry','','[]','南州苦炎酷，薄宦淹翹雋。',120,'全唐诗/poet.song.12000.json','["南州苦炎酷，薄宦淹翹雋。", "怡然賢者心，五稔若一瞬。", "歸程江海遥，永日風波進。", "屢經溪壑險，且樂帆檣順。", "忽傳郵驛音，雅什渾金振。", "披襟許見過，握蘭欣入覲。", "衡門久索居，黄陂渴餘潤。", "覯止君子容，玉光窺千仞。", "高談盡今古，不獨期廉藺。", "相逢勿惜醉，別去生蒙吝。"]'),
('81e2b33f-49c9-4479-baae-a86555943c87','和王子元過大庾嶺','余靖','宋','宋诗','song-poetry','','[]','秦皇戍五嶺，茲爲楚越隘。',72,'全唐诗/poet.song.12000.json','["秦皇戍五嶺，茲爲楚越隘。", "尉佗去黄屋，舟車通海外。", "峭巘倚雲漢，推輪日傾害。", "賢哉張令君，鎸鑿濟行邁。", "地失千仞險，途開九野泰。", "安得時人心，盡夷陰險閡。"]'),
('ace581a8-6226-4c86-8c18-6bae87b0f993','湖鄉檢旱回入南路夜宿江寺對望郛郭','余靖','宋','宋诗','song-poetry','','[]','高城鎖夕靄，遠水浮秋空。',96,'全唐诗/poet.song.12000.json','["高城鎖夕靄，遠水浮秋空。", "此時行役心，展轉如飛蓬。", "路入淺沙斷，堪慟車轍窮。", "豈無舟楫利，枉道非所從。", "雖有泉石趣，暫到徒匆匆。", "兒啼不入門，敢辭身狥公。", "夢歸身未歸，薄宦真池龍。", "披衣復起坐，驚鴻鳴西風。"]'),
('dcfd7092-d9ab-4656-93fc-ee2f74785f6a','送林秀才歸南海','余靖','宋','宋诗','song-poetry','','[]','紅塵倦客遊，綵衣歸故山。',96,'全唐诗/poet.song.12000.json','["紅塵倦客遊，綵衣歸故山。", "凜凜朔風勁，携手江之干。", "江聲萬雷震，帆影孤鴻翻。", "修途南盡海，冰雪凄人肝。", "不但川陸險，所思在承顔。", "親膳足甘滑，家居富林泉。", "懷安實敗名，無爲樂丘園。", "好爵縻英賢，早奮沖天翰。"]'),
('15d41b26-7685-4d2c-9dc5-1b39f3297eda','松門守風','余靖','宋','宋诗','song-poetry','','[]','彭蠡古來險，湯湯貫侯衛。',240,'全唐诗/poet.song.12000.json','["彭蠡古來險，湯湯貫侯衛。", "源長雲共浮，望極天無際。", "傳聞五月交，茲時一陰至。", "颶風生海隅，餘力千里曀。", "萬竅爭怒號，驚濤得狂勢。", "涌恐楚山拔，聲疑夏鼎沸。", "妖蜃吐濃烟，層臺誇壯麗。", "奔雷鳴大車，連鼓聲粗厲。", "豈誠陰陽爭，長憂天地閉。", "孤舟一葉輕，飄如斿在綴。", "所以泝沿人，未嘗貪既濟。", "逆猶上坂丸，順比飛鴻翅。", "直待浮雲收，乾坤廓然霽。", "湖光百里平，波色連天翠。", "然後榜蘭橈，以避蛟龍害。", "進退甘遲留，克保無祇悔。", "我願修身者，體此操舟態。", "動靜惟時幾，畏慎存纖芥。", "跬足雖平易，盡心防曖昧。", "長如履險時，終身不危殆。"]'),
('5f65f619-ad38-4bcc-915f-e14e3b5c078a','夏日江行','余靖','宋','宋诗','song-poetry','','[]','解組趨宸闕，扁舟泛江練。',216,'全唐诗/poet.song.12000.json','["解組趨宸闕，扁舟泛江練。", "健艣鴈齊鳴，輕帆雲一片。", "水闊煙難收，雨昏風易轉。", "曲浦逗留多，修程夢魂倦。", "舟子怯風波，終朝股交戰。", "預憂雷電驚，先喜虹蜺斷。", "安知農夫望，只顧行人便。", "愚儒有所思，自愧心如面。", "追惟亡異才，承恩得爲縣。", "盤錯非所長，耕桑當勉勸。", "十日愆一雨，災恐延農畔。", "靡愛幣與牲，羣望走之徧。", "山川未應誠，兼晨不敢飯。", "霈然得嘉澍，荷天如免譴。", "何以迅流間，遽逐庸夫變。", "江淮民荐饑，糟糠未充膳。", "粢盛苟無害，豈將風雨怨。", "玉燭長均調，寸進真君願。"]'),
('d2a71215-636c-4759-8470-9e888da5886b','過大孤山','余靖','宋','宋诗','song-poetry','','[]','有形天地分，設險山河壯。',240,'全唐诗/poet.song.12000.json','["有形天地分，設險山河壯。", "孤山鎮南服，峨峨楚之望。", "中立亡所倚，屹然怪其狀。", "石嵾入春空，翠柱搘秋浪。", "片時起雪痕，萬頃排霜杖。", "噫氣專呼吸，橫流以溟漲。", "行人多躁進，那解明得喪。", "不顧風濤險，半就江魚葬。", "挂席經其旁，往往乞靈貺。", "遂因孤獨名，塑立輕盈像。", "綽約姑射姿，夢魂巫峽想。", "如何方面祠，終古承其妄。", "五嶽視三公，降殺不過兩。", "不然爲子男，何以通祀享。", "四氣均分風，條融各有掌。", "避其狂怒勢，亦可利攸往。", "亭育天地心，憑險恣蕩漾。", "正直鬼神德，非名奚獨饗。", "不使悔吝侵，庶幾忠信仗。", "在人不在神，勿爲虛稽顙。"]'),
('28ecf2f1-a3d4-493a-94dd-57f0c3562fa2','觀釣','余靖','宋','宋诗','song-poetry','','[]','趨塵寒浦波，桂子秋空月。',96,'全唐诗/poet.song.12000.json','["趨塵寒浦波，桂子秋空月。", "煙溼釣綸輕，雨濺苔磯滑。", "健鯉吞香鈎，錦文紅鱍鱍。", "將爲沸鼎遊，勢窮猶喣沫。", "搘頤閑悵望，江湖晴蕩漾。", "奮鬣就其深，族類能相忘。", "胡爲貪一餌，委身刀机上。", "寄言洗耳翁，逃名真可尚。"]'),
('65bbef65-ceec-4712-9dcf-f49d38046e56','讀車千秋傳','余靖','宋','宋诗','song-poetry','','[]','漢武好迂誕，江充專險賊。',192,'全唐诗/poet.song.12000.json','["漢武好迂誕，江充專險賊。", "引對大臺宮，君臣自相得。", "世亂讒人勝，姦謀多造飾。", "元良天下本，掘蠱遭熒惑。", "春坊一動摇，前星冷無色。", "恐爲扶蘇誅，掘節儲君側。", "屈氂亡廟謀，轉戰同昏蝕。", "臣心無以明，野死不容息。", "千秋初奏疏，翩翩舉其直。", "一言能悟主，破怒成悽惻。", "歸來及望思，層臺起東域。", "徒步取卿相，分茅非舊德。", "因思壺關老，先此陳奇策。", "嘉言若時用，生歸當有益。", "徙薪不蒙賞，焦頭爲上客。", "漢道用人輕，取笑羞夷狄。"]'),
('5daca84f-56f8-4cec-9d9a-5f2882fca28b','送希昱上人永嘉覲親','余靖','宋','宋诗','song-poetry','','[]','閶闔西風高，振錫吳門去。',168,'全唐诗/poet.song.12000.json','["閶闔西風高，振錫吳門去。", "三江碧浸天，惟持一杯渡。", "敗葉梧桐秋，雲中永嘉樹。", "借問何言歸，親齒桑榆暮。", "再懷生育仁，聊爲馨潔具。", "聆師金石詞，鄭重加欽慕。", "陸梁原上獸，羣居先識母。", "嗷嗷林中烏，歛翼受子哺。", "云何蚩蚩輩，勝衣復能語。", "口腹徒自豐，骨肉如行路。", "師本談空人，浮雲無去住。", "未出輪回身，歸心應有悟。", "臨岐索贈言，愧乏雕章句。", "願達採詩官，當令不孝懼。"]'),
('eb0dd21f-0af5-47f9-a552-3d04758d1562','山寺獨宿','余靖','宋','宋诗','song-poetry','','[]','柴車走縣封，窮途秋耿耿。',48,'全唐诗/poet.song.12000.json','["柴車走縣封，窮途秋耿耿。", "急雨带溪聲，殘燈背窗影。", "驅馳下士身，凄凉旅人景。", "山寒夢不成，愁多知夜永。"]'),
('9936f2ac-b001-428e-b723-5381397fce53','詠史','余靖','宋','宋诗','song-poetry','','[]','王氏席世寵，垂組馳朱輪。',48,'全唐诗/poet.song.12000.json','["王氏席世寵，垂組馳朱輪。", "五侯同日拜，四塞黄霧昏。", "妖氣徒勃勃，爵王各終身。", "富貴若在天，禍淫真謬云。"]'),
('13a03f52-b1d7-4117-b88b-a3b7e99f4c23','寄韶石長老求柏栽','余靖','宋','宋诗','song-poetry','','[]','森然桃李陰，當春皆手植。',24,'全唐诗/poet.song.12000.json','["森然桃李陰，當春皆手植。", "更求青青枝，要見歲寒色。"]'),
('cb37c376-38ee-4391-9225-6320ffa8ea0a','寄鄧秀才求桃枝接頭','余靖','宋','宋诗','song-poetry','','[]','自慚閑索居，豈貪顔色盛。',24,'全唐诗/poet.song.12000.json','["自慚閑索居，豈貪顔色盛。", "愛渠真不言，可以通三徑。"]'),
('4bd10159-5302-42de-89d8-063e4199fe64','和王子元中秋會飲','余靖','宋','宋诗','song-poetry','','[]','混元鼓橐四氣平，西商之氣爽且輕。',224,'全唐诗/poet.song.12000.json','["混元鼓橐四氣平，西商之氣爽且輕。", "望舒按轡出東海，孤輪斲冰碾太清。", "碧落坦夷輪不停，銀河浩蕩波無聲。", "千家萬家調管絃，唯恐遊氛翳至明。", "秋深夜永景澄霽，老兔不死穴青冥。", "世間榮謝易反掌，得意難與良辰并。", "我謫閑官歸故里，君承新渥來江城。", "相逢並座敘離闊，把酒共見圓蟾生。", "嫦娥耐閒不肯嫁，破鑑再合光熒熒。", "白露乍零羣動息，浮雲一開萬目傾。", "但知吟處罇前樂，勿問區區時世情。", "高人洗耳讓天下，下士紾臂爭杯羹。", "賢愚相遠九牛毛，寵辱去就何足驚。", "醉鄉無關好遊處，勞生萬慮徒營營。"]'),
('9820c74e-64ec-494a-ac91-6df2eb0f4786','代贈','余靖','宋','宋诗','song-poetry','','[]','幽房寂寞時，香散輕袿衣。',60,'全唐诗/poet.song.12000.json','["幽房寂寞時，香散輕袿衣。", "可憐夜永不成寐，苦恨春殘猶未歸。", "歸來一見伸修眉，寶柱新聲逐調移。", "多少相思說不盡，淚滿玉壺著自知。"]'),
('05ea9dd7-612d-43d0-abbb-6ef5cc7f7481','送溫陵莊君崇班赴長樂都尉','余靖','宋','宋诗','song-poetry','','[]','新命升鵷序，辦嚴辭浚都。',48,'全唐诗/poet.song.12000.json','["新命升鵷序，辦嚴辭浚都。", "去乘關吏傳，歸握戍兵符。", "雲闊逢鄉樹，風和見海桴。", "南枝羨君樂，遣我憶蓴鱸。"]'),
('0bb95195-7143-4f57-876f-f1e6d32a08bc','留題許國博申申堂','余靖','宋','宋诗','song-poetry','','[]','宴居瀟灑一齋寬，每到高談暮忍還。',64,'全唐诗/poet.song.12000.json','["宴居瀟灑一齋寬，每到高談暮忍還。", "境勝自容巢燕託，時清誰顧卧龍閑。", "橋前水石紛華外，窗下琴書寂寞間。", "兼濟未成歸有地，羨君因此轉思山。"]'),
('4c42d5ac-d0a3-4c70-b342-ab2ba9ea461c','送凌屯田知和州','余靖','宋','宋诗','song-poetry','','[]','粉署仙郎守一麾，都門別岸柳依依。',64,'全唐诗/poet.song.12000.json','["粉署仙郎守一麾，都門別岸柳依依。", "定知春雨隨車至，且喜秋風破浪歸。", "仁政便當聞虎渡，治聲猶在隔牛磯。", "儂今亦懇懷章請，假道尚應鱸正肥。"]'),
('8f67ed4c-fb0f-4cec-a2ae-aa916a6ae3d2','送任祕丞知長興縣','余靖','宋','宋诗','song-poetry','','[]','懿文通籍氣飄飄，二十年來困下僚。',64,'全唐诗/poet.song.12000.json','["懿文通籍氣飄飄，二十年來困下僚。", "吾道本將忠許國，世途休歎老登朝。", "囊裝冷落堆青簡，衙署幽深枕畫橋。", "預想吳人蒙美化，海鷗桑雉共逍遥。"]'),
('ce11d767-3046-448f-899d-517f23890b34','迴鴈','余靖','宋','宋诗','song-poetry','','[]','暗隨春力起冥冥，微物寧知造化情。',64,'全唐诗/poet.song.12000.json','["暗隨春力起冥冥，微物寧知造化情。", "律變慚逢冰雪解，風和應助羽毛輕。", "塞雲空闊歸猶遠，魚網稀疏意尚驚。", "不學鷹鸇因肉飽，背人颺去恣飛鳴。"]'),
('2d9b6f08-b234-4bbd-b15e-39bf9d3b6dbe','謹吟五十六字攀送仲求殿丞之任贛川竊惟嚴君國博挂冠歸閑而仲求兄弟爲鄰部守倅其榮至矣誠欲賦述詞不逮意','余靖','宋','宋诗','song-poetry','','[]','一門三組序西雝，又見雙旌並訓農。',64,'全唐诗/poet.song.12000.json','["一門三組序西雝，又見雙旌並訓農。", "三釜親庭交祿養，夾河子舍接鄰封。", "酒闌風雪催行色，吟際江山助筆鋒。", "我亦思親求郡紱，東湖南浦好過從。"]'),
('b651a74f-a020-4764-addd-cce0922ffdca','和王子元同歸曲江有感','余靖','宋','宋诗','song-poetry','','[]','年少登科今白頭，不才多病分歸休。',64,'全唐诗/poet.song.12000.json','["年少登科今白頭，不才多病分歸休。", "深恩未報雲天施，弱質易驚蒲柳秋。", "進退無機常蹭蹬，窮通知命自夷猶。", "相逢莫問市朝事，綠水青山是勝遊。"]'),
('17c2a81d-07e6-4772-b5e2-7bac57da349a','齋中芍藥與千葉御米花對發招伯恭飲','余靖','宋','宋诗','song-poetry','','[]','嶺南卉木少珍奇，且喜逢春具數枝。',64,'全唐诗/poet.song.12000.json','["嶺南卉木少珍奇，且喜逢春具數枝。", "百祿大來唯酒美，一年全盛是花時。", "芳心未吐蜂先到，秀色如凝露暗滋。", "猶倚欄干忍虛過，可能垂顧習家池。"]'),
('52084acb-96e4-4ba3-88f3-d209deebe643','賀運使學士分散傜人','余靖','宋','宋诗','song-poetry','','[]','狂傜數載擾湘東，多謝招降息戰攻。',64,'全唐诗/poet.song.12000.json','["狂傜數載擾湘東，多謝招降息戰攻。", "千里山川還漢界，萬人戈甲卷秋風。", "牛羊野放狼心伏，鷹犬閒眠兔穴空。", "不獨事寧論爵賞，須知全活有陰功。"]'),
('26c513fe-f10b-467f-aa04-e615a9181c52','聞欒駕部度嶺見寄','余靖','宋','宋诗','song-poetry','','[]','久接賢規見準繩，還朝猶聽頌聲騰。',64,'全唐诗/poet.song.12000.json','["久接賢規見準繩，還朝猶聽頌聲騰。", "安民慮遠疆封靜，富國材高帑藏增。", "野老賡歌除橫斂，侍臣交表薦殊能。", "嶺頭若著關官籍，可察孤清節似冰。"]'),
('2773d828-86c8-4e3a-9de3-f77157ab89c4','同黄宰遊寶林精舍書祐長老壁','余靖','宋','宋诗','song-poetry','','[]','浮生萬慮日營營，同訪禪居耳目醒。',64,'全唐诗/poet.song.12000.json','["浮生萬慮日營營，同訪禪居耳目醒。", "尋勝已窮煙靄外，談空應有鬼神聽。", "松筠不變春長在，風雨無時地本靈。", "便擬搆菴來結社，莫嫌頻此扣巖扃。"]'),
('e4d87136-644e-4cf6-b7be-6e1e66a85635','恩守贛上謝和叔見寄次韵','余靖','宋','宋诗','song-poetry','','[]','六載心閑類死灰，豈期朝奬念麤材。',64,'全唐诗/poet.song.12000.json','["六載心閑類死灰，豈期朝奬念麤材。", "鳳銜君命從天降，鵲喜郵音度嶺來。", "恩重乍驚三采綬，使專仍咏一枝梅。", "切磋甫得依賢檢，疾惡剛腸愈不回。"]'),
('8e34062e-da8b-4ed0-b428-834055c009c9','寄題宋職方翠樓','余靖','宋','宋诗','song-poetry','','[]','層樓幽趣稱登臨，望遠憑高豁素襟。',64,'全唐诗/poet.song.12000.json','["層樓幽趣稱登臨，望遠憑高豁素襟。", "棋酒等閒忘世慮，溪山最樂是家林。", "松聲带雨千峰外，潭影涵虛落照深。", "此景爲君珍賞甚，起余歸興欲抽簪。"]'),
('f98f65a0-b5e7-4978-acbd-4a4f84d9cae6','酬蕭閣副惠末利花栽','余靖','宋','宋诗','song-poetry','','[]','素艷南方獨出羣，只應瓊樹是前身。',64,'全唐诗/poet.song.12000.json','["素艷南方獨出羣，只應瓊樹是前身。", "自緣香極宜晨露，勿謂開遲怨晚春。", "欄檻故將賓榻近，丹青重整畫圖新。", "移根得地無華裔，從此飛觴不厭頻。"]'),
('87d63730-c62c-4ffa-86e5-8a01c8ba83d1','先賞牡丹寄提刑考功','余靖','宋','宋诗','song-poetry','','[]','花期何事早追陪，鶑未遷喬燕未來。',64,'全唐诗/poet.song.12000.json','["花期何事早追陪，鶑未遷喬燕未來。", "曲檻爲逢春日暖，香苞先逐曉風開。", "旋邀歌舞同儕樂，却歎光陰急景催。", "可惜韶妍莫虛擲，餘芳留待使車回。"]'),
('73be387b-ba15-453b-a02c-8cb3cc97a489','又和寄提刑太保','余靖','宋','宋诗','song-poetry','','[]','常記臨岐把酒杯，芳心應得見歸來。',64,'全唐诗/poet.song.12000.json','["常記臨岐把酒杯，芳心應得見歸來。", "不從去日丁寧約，已向東風取次開。", "清燕固難停燭待，雕鞍須是著鞭催。", "欄邊殘艷猶堪賞，莫使韶光過了回。"]'),
('12251400-5308-43ef-b1ed-36e2a520f8d4','和伯恭自造新茶','余靖','宋','宋诗','song-poetry','','[]','郡庭無事即仙家，野圃栽成紫筍茶。',96,'全唐诗/poet.song.12000.json','["郡庭無事即仙家，野圃栽成紫筍茶。", "疏雨半晴回暖氣，輕雷初過得新芽。", "烘褫精謹松齋靜，採擷縈迂澗路斜。", "江水對煎萍彷彿，越甌新試雪交加。", "一槍試焙春尤早，三盞搜腸句更加。", "多謝彩牋貽雅貺，想資詩筆思無涯。"]'),
('eefcd715-c554-48e6-8cce-bda869eec687','和王子元重陽日千善寺會飲','余靖','宋','宋诗','song-poetry','','[]','人生聚散苦難期，且喜清遊酒滿巵。',64,'全唐诗/poet.song.12000.json','["人生聚散苦難期，且喜清遊酒滿巵。", "秋徑却逢黄菊日，春風休惜落花時。", "仙翁有讖應須避，楚客多悲亦强爲。", "好景莫教容易過，醉吟何必遶疏籬。"]'),
('6db6dad9-4ceb-4e8e-85a4-3832065fc52c','謝祖太博見訪西園','余靖','宋','宋诗','song-poetry','','[]','初聞結駟訪幽齋，拂曙呼童掃綠苔。',64,'全唐诗/poet.song.12000.json','["初聞結駟訪幽齋，拂曙呼童掃綠苔。", "方愧蓬蒿開徑晚，已驚騶馭過江來。", "林間載酒情偏厚，門外回舟事可咍。", "交態于今易離合，感君敦舊重徘徊。"]'),
('e89bffb5-c9eb-418a-a1a0-f7bad8cdc165','答祖太博借山居要術','余靖','宋','宋诗','song-poetry','','[]','經濟諒周當世務，收藏敢祕老農書。',32,'全唐诗/poet.song.12000.json','["經濟諒周當世務，收藏敢祕老農書。", "相逢莫羨山居好，歸去蓬山有直廬。"]'),
('3dc84ce9-bd7a-4b60-82b0-9278357577e6','送張如京知安肅軍','余靖','宋','宋诗','song-poetry','','[]','賜戟銜恩出斗城，塞門迢遞草初青。',64,'全唐诗/poet.song.12000.json','["賜戟銜恩出斗城，塞門迢遞草初青。", "新提司馬臨戎節，舊應衣烏近極星。", "叔子戍吳長緩带，單于歸漢已空庭。", "圯橋自得家傳策，不問人間太白經。"]'),
('ca0bf696-54d0-4a15-a933-d8d5d3aab5fb','送劉學士知衡州','余靖','宋','宋诗','song-poetry','','[]','朱轓新命漢諸侯，地扼荆湘占上游。',64,'全唐诗/poet.song.12000.json','["朱轓新命漢諸侯，地扼荆湘占上游。", "醽淥水聲侵古堞，祝融峰色入晴樓。", "晝垂三組鄉枌過，春擁雙旌嶽寺遊。", "番直星垣歸緩步，謫仙通籍著瀛洲。"]'),
('1651f4d5-195b-4a2e-954a-4cdfe0d3800e','送黄祕校南劍州司法','余靖','宋','宋诗','song-poetry','','[]','早年援筆氣飄飄，尚屈區區補郡寮。',64,'全唐诗/poet.song.12000.json','["早年援筆氣飄飄，尚屈區區補郡寮。", "苦掾去平三尺法，急賢期赴一封軺。", "舟衝柳市吟春晝，帆卷江風宿暮潮。", "及著萊衣過鄉梓，循陔多羨擷蘭苕。"]'),
('7da11674-e54f-4b15-a1d5-dd43a11778c6','送蘇祠部通判洪州','余靖','宋','宋诗','song-poetry','','[]','天家頓網極詳延，果見鴻風頌得賢。',64,'全唐诗/poet.song.12000.json','["天家頓網極詳延，果見鴻風頌得賢。", "庭拜外官聊試治，史分新策入編年。", "江淹賦筆雖傷別，郭泰歸舟只恐仙。", "南國勿思終計最，蓬丘番直即和鉛。"]'),
('c5f19f7d-fb91-4eba-a82d-77486cf5bfdf','和胡學士館中庭樹','余靖','宋','宋诗','song-poetry','','[]','仙材封植九重深，苒苒何年別故林。',64,'全唐诗/poet.song.12000.json','["仙材封植九重深，苒苒何年別故林。", "曉色半籠青瑣闥，春光長在玉山岑。", "靜臨高閣飜清吹，坐見羈禽息密陰。", "休羨井梧能待鳳，凌霜堅守歲寒心。"]'),
('e1b39d6a-224a-428f-b2d3-525cd4174745','送楊學士益州路轉運','余靖','宋','宋诗','song-poetry','','[]','芝函新命直仙蓬，又見岷山叱馭忠。',64,'全唐诗/poet.song.12000.json','["芝函新命直仙蓬，又見岷山叱馭忠。", "玉佩曉班辭日下，水牛秋粟轉褒中。", "花時井邑蠶叢富，徼外人家棧道通。", "奇技刺文頻詔約，此行應更變民風。"]'),
('10b20282-03fb-411b-971f-603ca9158e98','思壽陽寓居高氏園亭','余靖','宋','宋诗','song-poetry','','[]','嘗借芳園石友家，幽棲無復羨紛華。',64,'全唐诗/poet.song.12000.json','["嘗借芳園石友家，幽棲無復羨紛華。", "敞扉氣爽雲生棟，卷箔香微露泫花。", "桂向淮山分月魄，桃從秦洞得仙葩。", "別來追想清閑境，悔褫方中走棧車。"]'),
('e84e83e7-c297-48c3-808c-31f3e86bd6ea','和邃卿張學士暑夕','余靖','宋','宋诗','song-poetry','','[]','危坐空齋暝色低，三金才伏火將西。',64,'全唐诗/poet.song.12000.json','["危坐空齋暝色低，三金才伏火將西。", "煙蒙細草流螢度，月上疏林倦鵲棲。", "荃葛野裳交羽扇，桔槔鄰圃響蔬畦。", "中宵爽氣奪炎熱，却笑班姬謾慘悽。"]'),
('5ab06fb7-97b4-4397-9623-2d7356735b5b','送舒太博通判眉州','余靖','宋','宋诗','song-poetry','','[]','通守方忻再命新，東風疏雨拂行塵。',64,'全唐诗/poet.song.12000.json','["通守方忻再命新，東風疏雨拂行塵。", "封疆遠入魚鳬國，岐路正逢蠶市春。", "彭岫曉嵐迎畫隼，錦江晴綠照朱輪。", "歸期不待更書至，舊有清名在縉紳。"]'),
('0b0da851-2098-4785-995a-03cba5fcc3a3','送鄧祕丞知德安縣','余靖','宋','宋诗','song-poetry','','[]','里閈俊遊心久降，越臺成政俗敦龐。',64,'全唐诗/poet.song.12000.json','["里閈俊遊心久降，越臺成政俗敦龐。", "香爐山下重爲縣，閶闔風高還渡江。", "且喜恩威長及物，莫嫌功業未經邦。", "公齋更近淵明宅，寄傲情應卧北窗。"]'),
('47c95342-c7a6-4d5c-8fe9-bd8d0f513c02','送張屯田通判益州','余靖','宋','宋诗','song-poetry','','[]','數載關中聞美名，可憐隨調却西征。',64,'全唐诗/poet.song.12000.json','["數載關中聞美名，可憐隨調却西征。", "天臺晚帳含香別，棧閣秋霜叱馭行。", "杜曲尚逢樽酒樂，回溪應望白雲生。", "相期勉力宣新政，側耳民謠起少城。"]'),
('b4b7f217-fda5-40e7-9a7d-296cc247bd99','送蓋太博通判定州','余靖','宋','宋诗','song-poetry','','[]','墨詔殷勤擢俊賢，精求毗佐四方翰。',64,'全唐诗/poet.song.12000.json','["墨詔殷勤擢俊賢，精求毗佐四方翰。", "封疆謹守盧奴塞，旌旆仍親上將壇。", "衰草带霜秋馬健，黄雲遮日暮城寒。", "燕南趙北邊之要，旅拒憑君一策安。"]'),
('8a70c589-8df9-4236-9d13-b87763040e78','哭王子野待制','余靖','宋','宋诗','song-poetry','','[]','赤墀趨步近相陪，邸吏俄傳遠訃來。',64,'全唐诗/poet.song.12000.json','["赤墀趨步近相陪，邸吏俄傳遠訃來。", "方冀君心辨忠義，豈知天意奪賢材。", "堪傷棣萼同時葬，空想銘旌此日回。", "謫宦無緣親漬酒，江邊長慟獨徘徊。"]'),
('ef607d63-ae85-441a-a12c-0375665a09ac','靖啟伏蒙觀文相公以靖忝承善政特寄嘉篇謹依嚴韵和酬','余靖','宋','宋诗','song-poetry','','[]','幸奉前規盡所懷，閒身吏隠裕春臺。',64,'全唐诗/poet.song.12000.json','["幸奉前規盡所懷，閒身吏隠裕春臺。", "山迴翠幌憑欄見，花簇紅房遶郭開。", "愛樹細民思美化，續貂孤迹愧非才。", "南河舊事依然在，禊飲杯盤恥盡罍。"]'),
('20491e24-080e-4942-87bd-ac9bcf48b17f','次韵奉和到塞下有懷青社之作','余靖','宋','宋诗','song-poetry','','[]','十二山河壯東夏，黄扉當日建行臺。',64,'全唐诗/poet.song.12000.json','["十二山河壯東夏，黄扉當日建行臺。", "封陲自此赭衣盡，黌校于今絳帳開。", "負海遂成安堵俗，濟川元是代天才。", "耆明雖樂歸閒趣，睿睠巖廊徯再來。"]'),
('e8301732-9f3e-48a5-bc61-183532fcebfc','和運使張學士惠詩','余靖','宋','宋诗','song-poetry','','[]','澄清數路擁輕軒，列郡欽瞻已歷年。',64,'全唐诗/poet.song.12000.json','["澄清數路擁輕軒，列郡欽瞻已歷年。", "談劇乍欣傾蓋日，酒深因惜落花天。", "偶迴風鑒憐孤拙，能聚星文愧昔賢。", "明旦吏迎山驛去，不須容易到罇前。"]'),
('e6f9c9f9-152b-4b73-b5ec-8a5862810948','九日賞池會上酬王職方','余靖','宋','宋诗','song-poetry','','[]','雅集高談思豁然，齊山依約對疏煙。',64,'全唐诗/poet.song.12000.json','["雅集高談思豁然，齊山依約對疏煙。", "江城泛菊逢佳節，禁苑聞韶憶去年。", "久厭風波驚世路，且同樽酒醉凉天。", "今來古往情何異，弄水亭邊艤畫船。"]'),
('a08ee3e4-3e89-4889-bb77-85236310b864','和董職方見賀誕子詩','余靖','宋','宋诗','song-poetry','','[]','天幸依仁守列藩，佳篇爲貺荷謙尊。',64,'全唐诗/poet.song.12000.json','["天幸依仁守列藩，佳篇爲貺荷謙尊。", "固慙彝鼎無勳閥，且喜桑弧有子孫。", "豈比芳蘭庭下秀，預知苦李道傍繁。", "日臨庶獄虞陰譴，敢望高開納駟門。"]'),
('76746894-b221-4b55-bb75-2c1aeb40a47f','和董職方見示初到番禺詩','余靖','宋','宋诗','song-poetry','','[]','五方殊俗古難并，千載猶存古越城。',64,'全唐诗/poet.song.12000.json','["五方殊俗古難并，千載猶存古越城。", "客聽潮雞迷早夜，人瞻颶母識陰晴。", "波濤洶湧天邊闊，犀象斕斒徼外生。", "太守不才當遠寄，惟憂南畝廢農耕。"]'),
('1af9ca3b-3cea-48ad-a9f6-749f98bc6ad1','題庾嶺三亭詩 叱馭樓','余靖','宋','宋诗','song-poetry','','[]','山巔層搆與雲平，賢者新題叱馭名。',64,'全唐诗/poet.song.12000.json','["山巔層搆與雲平，賢者新題叱馭名。", "爲要澄清歸治道，不辭艱險表忠誠。", "南枝初見梅林秀，九折遥思劍棧橫。", "若使當時嫌遠宦，海隅何得有歡聲。"]'),
('c23cb7d4-8210-4610-aa4e-1a49d09b0ae1','題庾嶺三亭詩 來鴈亭','余靖','宋','宋诗','song-poetry','','[]','南方舊說無燕鴈，歲序嚴凝亦暫來。',64,'全唐诗/poet.song.12000.json','["南方舊說無燕鴈，歲序嚴凝亦暫來。", "天外每隨寒雨過，春前先逐暖風回。", "人稀弋射矰休避，俗厭魚餐網莫猜。", "況是弟兄封境接，登臨因此幾徘徊。"]'),
('4b3ec85a-9986-43c4-9074-5af8bd351bd4','題庾嶺三亭詩 通越亭','余靖','宋','宋诗','song-poetry','','[]','行盡章江庾水濱，南踰梅館陟嶙峋。',64,'全唐诗/poet.song.12000.json','["行盡章江庾水濱，南踰梅館陟嶙峋。", "城中紹祚千年聖，海外占風九譯人。", "嶠嶺古來稱絕徼，梯山從此識通津。", "輿琛輦賮無虛歲，徒說周朝白雉馴。"]'),
('fee248ef-1153-4583-b243-dfd738574c5c','靜臺','余靖','宋','宋诗','song-poetry','','[]','江城吏隠敞朱扉，旋築高臺望翠微。',64,'全唐诗/poet.song.12000.json','["江城吏隠敞朱扉，旋築高臺望翠微。", "景對雲山詩筆健，政移風俗訟筩稀。", "那將塵慮干方寸，但覺仙蹤在四圍。", "花木陰森魚鳥樂，暫來猶擬便忘機。"]'),
('3f3bb07e-e601-49c3-9659-d8dff39e15f5','贛石','余靖','宋','宋诗','song-poetry','','[]','萬堆頑碧聳嶢嶕，壅遏江流氣勢驕。',64,'全唐诗/poet.song.12000.json','["萬堆頑碧聳嶢嶕，壅遏江流氣勢驕。", "鐵馬陣橫秋戰苦，水犀軍亂夜聲囂。", "呂梁謾記莊篇險，灧澦休誇蜀道遥。", "怒激波聲猶可避，中傷榮路不相饒。"]'),
('474ddb1f-5fa6-43d7-a4b1-b3349503c857','落花','余靖','宋','宋诗','song-poetry','','[]','小園斜日照殘芳，千里傷春意未忘。',64,'全唐诗/poet.song.12000.json','["小園斜日照殘芳，千里傷春意未忘。", "金谷已空新步障，馬嵬徒見舊香囊。", "鶑來似結啼鸞怨，蝶散應知夢雨狂。", "清賞又成經歲別，却歌團扇寄迴腸。"]'),
('e264445d-3497-4bd8-af60-641adac6d059','遊應聖宮','余靖','宋','宋诗','song-poetry','','[]','驅羸遠遠出嚴闉，雲搆祠宮絕世塵。',64,'全唐诗/poet.song.12000.json','["驅羸遠遠出嚴闉，雲搆祠宮絕世塵。", "伴鶴不知龜甲子，斸山多見藥君臣。", "雨昏仙穴丹砂井，雲映樓居玉洞人。", "只待策勳書竹帛，抽簪來此卜比鄰。"]'),
('0a278711-95c1-4bfc-a16b-0801a6874c54','西山','余靖','宋','宋诗','song-poetry','','[]','萬壑千巖鬭物華，搘筇閒訪道生涯。',64,'全唐诗/poet.song.12000.json','["萬壑千巖鬭物華，搘筇閒訪道生涯。", "一壇星斗修真館，數里雲煙斸藥家。", "魚戲竹溪寒影碎，路穿松塢翠陰斜。", "桃源自有神仙宅，未信明河八月槎。"]'),
