('34ae47d4-b4ab-46a9-ba39-4d26dbdd4554','留題龍隠巖','章峴','宋','宋诗','song-poetry','','[]','碧崖石室俯清漣，蟠蟄靈虬不記年。',64,'全唐诗/poet.song.12000.json','["碧崖石室俯清漣，蟠蟄靈虬不記年。", "委蛻去爲天下雨，抱珠歸作洞中眠。", "照開霧脚澄溪月，滴破雲根暗穴泉。", "負郭勝遊雖信美，桑間留愛我無緣。"]'),
('719ae358-fbc8-4294-8e29-fc1a57861211','治平丙午仲冬中澣遊釋迦寺登環翠閣','章峴','宋','宋诗','song-poetry','','[]','吏局區區得暇難，倚崖高閣暫登攀。',64,'全唐诗/poet.song.12000.json','["吏局區區得暇難，倚崖高閣暫登攀。", "羣峰半出重林外，小艇橫浮一水間。", "霜葉信風隨鳥逝，晚雲沉石伴僧閑。", "夕陽欲下猶迴戀，更鼓清琴數弄還。"]'),
('7ba7ffee-2cf9-4a4e-83d5-ae6f0edc2785','丁未上巳重遊龍隠巖','章峴','宋','宋诗','song-poetry','','[]','溪干艤棹訪巖扉，危磴攀緣不欲歸。',64,'全唐诗/poet.song.12000.json','["溪干艤棹訪巖扉，危磴攀緣不欲歸。", "垂乳滴聲當佛座，宿雲留潤在僧衣。", "聊開禊席臨流水，閑擲文竿到落暉。", "旅宦天涯甘寂寞，送春無意惜芳菲。"]'),
('c1b184da-4665-4189-8ac4-6fe4b6778d40','和李昇之夜遊漓江上','章峴','宋','宋诗','song-poetry','','[]','自笑無錢對菊花，天寒欲冷慢令賒。',64,'全唐诗/poet.song.12000.json','["自笑無錢對菊花，天寒欲冷慢令賒。", "桄榔葉暗臨江圃，茉莉香來釀酒家。", "月霧空濛螢照水，霜風蕭瑟鷺眠沙。", "歸尋獨秀山前路，城角參橫斗柄斜。"]'),
('f5f06a4e-2356-4701-8fff-f4be59f634a7','雉山','章峴','宋','宋诗','song-poetry','','[]','營邱水墨師，不識桂林山。',144,'全唐诗/poet.song.12000.json','["營邱水墨師，不識桂林山。", "半世閱渠畫，今始陋堅頑。", "嶺邊千奇峰，濃紺梳雲鬢。", "肩輿兀醉夢，所窺纔一斑。", "偶投雉巖宿，洞穴窮孱顔。", "旁通赤明天，南極地所寰。", "更登雲外頂，下視江灣灣。", "羣仙無我笑，畏汝碧玉環。", "我久墮塵網，歲晚嗟良難。", "往來等幻化，南北俱鄉關。", "却憐雪花兒，三生此山閒。", "願力不汝無，永悟無所還。"]'),
('11d66b17-b6e9-4fa5-bc0e-e0530d6c4fcc','夜遊灕江上','李昇之','宋','宋诗','song-poetry','','[]','灕江開遍四時花，遊覽都忘屐齒賒。',64,'全唐诗/poet.song.12000.json','["灕江開遍四時花，遊覽都忘屐齒賒。", "風景雖宜秋向老，關山無奈客思家。", "漏傳樓上三通鼓，水落灘頭幾尺沙。", "京國未歸鄉信斷，陣鴻何處貼雲斜。"]'),
('6d934485-1ec0-43b4-bb65-246f328c37df','與宋景文公唱酬牡丹詩','朱公綽','宋','宋诗','song-poetry','','[]','仁帥安全蜀，祥葩育至和。',48,'全唐诗/poet.song.12000.json','["仁帥安全蜀，祥葩育至和。", "地寒開既晚，春曙力終多。", "翠幕遮蜂蝶，朱闌隔綺羅。", "殷懃憑驛使，光景易蹉跎。"]'),
('bc23ac97-4faf-4695-a9cd-1ef7085b9934','句','朱公綽','宋','宋诗','song-poetry','','[]','諫草焚來應見史，橐金散盡只留書。',16,'全唐诗/poet.song.12000.json','["諫草焚來應見史，橐金散盡只留書。"]'),
('56ce682f-f3e9-460c-b3d9-0f5062369dc5','荔支七絕 奪先紅','王十朋','宋','宋诗','song-poetry','','[]','閩中荔子說莆中，闕下奇包又不同。',32,'全唐诗/poet.song.120000.json','["閩中荔子說莆中，闕下奇包又不同。", "正向鈴齋想風味，奪先人送奪先紅。"]'),
('f58dc754-f8ee-4a24-b40c-e839d10f5323','荔支七絕 七夕紅','王十朋','宋','宋诗','song-poetry','','[]','宅堂荔子無名字，自我呼爲七夕紅。',32,'全唐诗/poet.song.120000.json','["宅堂荔子無名字，自我呼爲七夕紅。", "記得去冬初到日，家人指樹語衰翁。"]'),
('9d070915-ae07-43b0-bad3-b973b8d3adc8','貢院垂成雙蓮呈瑞因成鄙語勉士子','王十朋','宋','宋诗','song-poetry','','[]','大厦垂垂就，嘉蓮得得開。',48,'全唐诗/poet.song.120000.json','["大厦垂垂就，嘉蓮得得開。", "雙雙戴千物，兩兩應三臺。", "歡意重重合，香風比比來。", "人人宜自勉，舉舉有廷魁。"]'),
('7d340afc-98bb-4f51-a3c6-bef1149c7d35','陳賀州賦雙蓮詩不言祥瑞次韻以酬','王十朋','宋','宋诗','song-poetry','','[]','紅蕖明鏡兩鮮鮮，中有雙頭更穎然。',64,'全唐诗/poet.song.120000.json','["紅蕖明鏡兩鮮鮮，中有雙頭更穎然。", "天産人才兼産物，公祥和氣不祥蓮。", "耻談子厚表中瑞，肯詠章安橋畔篇。", "何日相呼登泰華，采華食實藕如船。"]'),
('b8f8f1c2-0c6e-4d69-8ffa-aab15d88dd00','郡圃有荔支名白蜜者熟最晚戲成一絕','王十朋','宋','宋诗','song-poetry','','[]','紛紛蜂采百花歸，蜜在枝頭竟不知。',32,'全唐诗/poet.song.120000.json','["紛紛蜂采百花歸，蜜在枝頭竟不知。", "造物要令甜在後，時人莫訝熟何遲。"]'),
('0ade3f80-d7d8-430c-aec5-062ceee7466f','送王提幹','王十朋','宋','宋诗','song-poetry','','[]','昔年王儉客，今共阿戎游。',48,'全唐诗/poet.song.120000.json','["昔年王儉客，今共阿戎游。", "嘗藥子當去，請祠予欲休。", "過從都幾日，離別况逢秋。", "歸上雙親壽，塗中莫逗留。"]'),
('464b81d1-1bf7-4fdf-a1af-da60fe2ccea8','觀貢院畫春景圖','王十朋','宋','宋诗','song-poetry','','[]','梁棟翬飛氣象新，畫工妙思亦通神。',32,'全唐诗/poet.song.120000.json','["梁棟翬飛氣象新，畫工妙思亦通神。", "要令寒士皆春色，四景之中獨畫春。"]'),
('c0f2e48d-060d-4723-9b6d-7a9ab5926013','韓魏公生于泉南州宅故未有祠於典爲闕郡圃有庵名大隠即之以祠八月戊子率同僚祀之','王十朋','宋','宋诗','song-poetry','','[]','天開我宋太平基，紫府真人下應期。',64,'全唐诗/poet.song.120000.json','["天開我宋太平基，紫府真人下應期。", "河朔魁梧出真相，泉南葱鬰産奇兒。", "夢符蚌腹生珠夜，事應台躔捧日時。", "紫帽清源發光采，郡園深處立新祠。"]'),
('ba181c22-7622-406e-82e7-03be379d86bc','陳提刑永仲以清名室志先德也詩以美之','王十朋','宋','宋诗','song-poetry','','[]','龐公嘗有言，我獨遺以清。',156,'全唐诗/poet.song.120000.json','["龐公嘗有言，我獨遺以清。", "賢者於子孫，所遺良不輕。", "潁川老龍公，落落前朝英。", "帝命作南伯，清德如廣平。", "宸翰一字褒，不啻華衮榮。", "是以自賢孫，持節蜚英聲。", "結廬桐城隅，室以清爲名。", "仰不忝厥祖，俯能規後生。", "我來聚星地，喜見此老成。", "公清不自言，藹然著鄉評。", "時焉訪其室，鄙吝不敢萌。", "如覿任棠水，似濯滄浪纓。", "願移清室風，于以清寰瀛。"]'),
('b448038b-c219-4971-a8bc-0f9c47387189','樸鄉釣隠圖','王十朋','宋','宋诗','song-poetry','','[]','君不見少陵先生詩有說，淳樸之處山川別。',283,'全唐诗/poet.song.120000.json','["君不見少陵先生詩有說，淳樸之處山川別。", "廣文示我樸鄉圖，山水高長景奇絕。", "嚴坂疑爲子陵隠，昆溪想自崑崙决。", "漁人欵乃山水間，抱璞含淳釣清潔。", "九仙高舉留遺躅，三徑名家出人傑。", "早將樸直取巍科，行展樸忠立奇節。", "鳴琴百里邑，既以樸化民。", "橫經泮水宮，又以樸誨人。", "他年致君堯舜上，坐使風俗俱還淳。", "功成名遂却歸去，漁釣重尋舊隠淪。", "廣文笑我言，公樸甚我樸。", "聞公家左原，四面擁山岳。", "迴隠如愚溪，窈深若盤谷。", "人皆樸其貌，公又樸其學。", "君子以爲古，先進於禮樂。", "公鄉真樸鄉，胡爲不自覺。", "願公著隠服，歸尋舊盤旋。", "酌酒梅溪上，把釣蓴湖邊。", "更畫左原山水圖，與此樸鄉圖並傳。", "天下大樸散已久，二鄉猶在羲皇前。"]'),
('832decee-f4ef-43a2-967a-f74d4356ba92','八月十五日貢院落成賓僚咸集斥世俗之樂不用飲文字也把盃邀月誦香滿一輪中句即席賦詩以勉多士','王十朋','宋','宋诗','song-poetry','','[]','揚輝秋月懸青天，今夕何夕光更圓。',128,'全唐诗/poet.song.120000.json','["揚輝秋月懸青天，今夕何夕光更圓。", "瓊爲樓臺玉爲宇，廣寒境界移清泉。", "月斧雲斤天上手，萬間突兀摩星斗。", "白頭郡守呼衆賓，共飲落成文字酒。", "龍虎群仙上界還，手移桂種栽泉山。", "千枝萬枝香不斷，人人有分行當攀。", "姮娥慇勤寄消息，科第要從勤苦得。", "丹桂在君書卷中，不須遥向蟾宮覓。"]'),
('ce6f8528-4301-492f-b298-7dc333231f52','送薛士昭  其一','王十朋','宋','宋诗','song-poetry','','[]','相逢一笑慰衰遲，問政論交兩不疑。',64,'全唐诗/poet.song.120000.json','["相逢一笑慰衰遲，問政論交兩不疑。", "直諒多聞三益友，清新俊逸百篇詩。", "瓜猶未及去何速，橘已成懷喜可知。", "一薛居州非易得，危言行見造朝時。"]'),
('b4e586c9-f2d2-4b13-b9fc-22141b422be8','送薛士昭  其二','王十朋','宋','宋诗','song-poetry','','[]','記得祥符識面時，回頭二十二年非。',64,'全唐诗/poet.song.120000.json','["記得祥符識面時，回頭二十二年非。", "羨君學似川方至，顧我身如鳥倦飛。", "老境天教重會合，異鄉心最惜分違。", "雁山親舊如相問，征雁歸時我亦歸。"]'),
('92b440e3-3536-4cbb-8b33-e22586e240c0','愛松堂前有綠竹一叢可愛旁有鷹爪花頗礙眼移去之','王十朋','宋','宋诗','song-poetry','','[]','窗前栽植不宜繁，松竹相依妙意存。',32,'全唐诗/poet.song.120000.json','["窗前栽植不宜繁，松竹相依妙意存。", "不許閑花放鷹爪，要看高節迸龍孫。"]'),
('fa71bd57-8134-449d-91cb-0b33234bb4c4','提舶送菊酒有詩次韻','王十朋','宋','宋诗','song-poetry','','[]','鈴齋午睡夢魂驚，僮僕歡呼洗破觥。',64,'全唐诗/poet.song.120000.json','["鈴齋午睡夢魂驚，僮僕歡呼洗破觥。", "酒是爛柯山下法，詩如藍水坐間成。", "謾同陶令浮黄菊，也勝蘇仙嗅落英。", "蓬鬢蕭踈對佳節，因公撩起故鄉情。"]'),
('29bdafc3-fe8a-4009-8783-ccf0451ffb4e','九日登雲榭','王十朋','宋','宋诗','song-poetry','','[]','九日無悰懶出關，强登雲榭望泉山。',32,'全唐诗/poet.song.120000.json','["九日無悰懶出關，强登雲榭望泉山。", "傷心不忍看茱菊，蓬鬢蕭踈淚點班。"]'),
('35060093-8c6f-421a-8442-2bc8203818b1','十日同知宗提舶游九日山延福寺','王十朋','宋','宋诗','song-poetry','','[]','十日同游九日山，山中好處畧躋攀。',64,'全唐诗/poet.song.120000.json','["十日同游九日山，山中好處畧躋攀。", "桑田改變松猶在，車馬徃來心自閑。", "昨日風應吹紫帽，今朝菊已带衰顔。", "登臨稱愜南來意，好逐飛飛倦鳥還。"]'),
('2e0ebdea-3fe0-457b-914c-d8217cd99f63','御書閣','王十朋','宋','宋诗','song-poetry','','[]','黄龍溪上祥雲覆，紫帽山頭瑞氣蒙。',32,'全唐诗/poet.song.120000.json','["黄龍溪上祥雲覆，紫帽山頭瑞氣蒙。", "俗眼驚傳佛光現，不知宸翰在山中。"]'),
('b4dc14f5-7a82-44ca-8111-140525c252ea','思古堂','王十朋','宋','宋诗','song-poetry','','[]','孤嶼游人思謝公，天台禪客亦思豐。',32,'全唐诗/poet.song.120000.json','["孤嶼游人思謝公，天台禪客亦思豐。", "黄花境界誰思古，堂在烟霞縹緲中。"]'),
('689a6be9-4f46-4598-9cd8-676f664f62af','善利王廟','王十朋','宋','宋诗','song-poetry','','[]','有德於民廟貌崇，我來端爲謝年豐。',32,'全唐诗/poet.song.120000.json','["有德於民廟貌崇，我來端爲謝年豐。", "曰暘曰雨皆神力，不止南風與北風。"]'),
('4bf01437-0f68-427d-802b-ae3d6f3a064e','晉時松','王十朋','宋','宋诗','song-poetry','','[]','孤山陳柏已物化，九日晉松猶後生。',32,'全唐诗/poet.song.120000.json','["孤山陳柏已物化，九日晉松猶後生。", "欲問東南兩朝事，風枝瀟洒似談清。"]'),
('3e62327b-533a-48d1-96d3-92612206752f','秦君亭','王十朋','宋','宋诗','song-poetry','','[]','山中高隠欲逃名，不謂名隨隠處成。',32,'全唐诗/poet.song.120000.json','["山中高隠欲逃名，不謂名隨隠處成。", "鑿石一泓詩數首，也曾攻破五言城。"]'),
('9f489a76-b9b9-4c52-b99f-0585fa531c91','姜相峯','王十朋','宋','宋诗','song-poetry','','[]','相國忠如宋廣平，危言流落晉江城。',32,'全唐诗/poet.song.120000.json','["相國忠如宋廣平，危言流落晉江城。", "天資自直無心賣，何事青山亦得名。"]'),
('8c5b343e-c3a3-45d3-a7fa-6e40c8e71a32','無名木','王十朋','宋','宋诗','song-poetry','','[]','一木蒼然老更奇，肯將名與世人知。',32,'全唐诗/poet.song.120000.json','["一木蒼然老更奇，肯將名與世人知。", "我來不具知名眼，深愧平生不學詩。"]'),
('f06df5e2-df90-4cdc-b012-d72b10cff271','姜秦峯','王十朋','宋','宋诗','song-poetry','','[]','郡侯不識國元勳，釋子那知姜與秦。',32,'全唐诗/poet.song.120000.json','["郡侯不識國元勳，釋子那知姜與秦。", "隠士有靈應撫掌，相公死亦不容身。"]'),
('f41b6d07-eb9d-4dff-83fb-a3d5ce9f71f8','陳公祠','王十朋','宋','宋诗','song-poetry','','[]','九年地主百年祠，民自元豐結去思。',32,'全唐诗/poet.song.120000.json','["九年地主百年祠，民自元豐結去思。", "善政在人宜有後，堂堂忠肅見公兒。"]'),
('2445786b-fc0b-443f-a7b4-29b843306886','蔡端明詩','王十朋','宋','宋诗','song-poetry','','[]','賢侯去久迹猶遺，乞雨詩奇字更奇。',32,'全唐诗/poet.song.120000.json','["賢侯去久迹猶遺，乞雨詩奇字更奇。", "世俗妄論公政猛，愛民心有彼蒼知。"]'),
('61cc906f-fae4-4351-beea-146d176446f2','石佛','王十朋','宋','宋诗','song-poetry','','[]','卧草埋雲不記秋，忽然成佛坐巖幽。',32,'全唐诗/poet.song.120000.json','["卧草埋雲不記秋，忽然成佛坐巖幽。", "紛紛香火來求福，不悟前時是石頭。"]'),
('8f867787-996e-4cba-8ff4-ef8da47aa9dd','聚秀閣','王十朋','宋','宋诗','song-poetry','','[]','清源山遠水流長，九日溪山更異常。',32,'全唐诗/poet.song.120000.json','["清源山遠水流長，九日溪山更異常。", "高閣摩雲聚秀氣，禪僧秀氣聚中藏。"]'),
('d63ee7d7-c045-4054-8ca7-23b70eb1164f','提舶送巖桂','王十朋','宋','宋诗','song-poetry','','[]','晉堂巖桂脫秋芳，濃綠枝頭萬粟黄。',32,'全唐诗/poet.song.120000.json','["晉堂巖桂脫秋芳，濃綠枝頭萬粟黄。", "堂上主人分贈我，要令燕寢有天香。"]'),
('f6ef08f7-a22d-4d79-84f9-bad85508adf0','寄南安鹿宰','王十朋','宋','宋诗','song-poetry','','[]','春秋重復古，二賢還舊祠。',48,'全唐诗/poet.song.120000.json','["春秋重復古，二賢還舊祠。", "直道不終廢，高風宜見思。", "古墓出荆榛，孤亭起頹隳。", "更將碧紗籠，覆護端明詩。"]'),
('61c7ec0d-55d3-4d48-9d82-2ac590b62ba4','貢院圖','王十朋','宋','宋诗','song-poetry','','[]','陳君少年登甲科，紅蓮首泛清源波。',128,'全唐诗/poet.song.120000.json','["陳君少年登甲科，紅蓮首泛清源波。", "清源貢宇高嵳峩，同僚宣力陳君多。", "鞭朴不施成不日，首夏上梁秋半畢。", "一點靈臺輪奐飛，十幅生綃畫圖出。", "蒼蒼嘉木森千株，新堤步步穿芙蕖。", "移下蟾宮古丹桂，飛來海上真蓬壺。", "他年君來作地主，記得親曾視斤斧。", "雁過山中寄我書，要知多少新龍虎。"]'),
('23af5033-6b46-4404-8811-e8aa1191323a','去年','王十朋','宋','宋诗','song-poetry','','[]','去年今日別吾家，我鬢蒼然爾未華。',32,'全唐诗/poet.song.120000.json','["去年今日別吾家，我鬢蒼然爾未華。", "日似去年人不見，鬢毛白盡眼添花。"]'),
('94813e22-3496-4af8-a37b-f3866bfcbaec','不求人','王十朋','宋','宋诗','song-poetry','','[]','牙爲指爪木爲身，撓癢工夫似有神。',32,'全唐诗/poet.song.120000.json','["牙爲指爪木爲身，撓癢工夫似有神。", "老病不能親把握，不求人又却求人。"]'),
('e1ef4d6a-56a3-4d3c-a6c0-d4fc1fe9b3c7','興化簿葉思文吾鄉老先生也比沿檄見訪既別寄詩二十八韻次韻以酬','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','暮年初仕塗，暇日但書策。',288,'全唐诗/poet.song.120000.json','["暮年初仕塗，暇日但書策。", "儒生餘氣習，筆端事揮斥。", "政學兩踈繆，篇章稍沉溺。", "楚東會詩豪，酬唱奏金石。", "逢場爭出奇，遇險或遭厄。", "忽泝三峽流，遥經數州驛。", "廬山看未足，巫峯過尤惜。", "西郊祠卧龍，東屯弔詩伯。", "飛飛猶倦鳥，秋風送歸翮。", "同行得嘉友，鏖戰交鋒鏑。", "弛檐白蘋洲，天日去咫尺。", "忠誼懷魯公，覇業悲項籍。", "奉詔還故鄉，齒落肌瘦瘠。", "涕泗拜松楸，荒蕪翦荆棘。", "心期樂田里，誓不綰銅墨。", "橐雖無陸金，歸幸全趙璧。", "陛下忽誤恩，泉南又分職。", "入閩如入蜀，枯腸復冥索。", "腰緣病減圍，髮爲悲添白。", "風仰秦君高，節慕姜相直。", "惡語誰流傳，同僚誤刊刻。", "吾鄉老先生，吏事以儒飾。", "新篇似庭燎，遠寄箴我癖。", "把酒欲細論，何時再沿檄。"]'),
('c8be7f40-4aa7-47c7-a560-4516afccf0bd','送陸通判  其一','王十朋','宋','宋诗','song-poetry','','[]','劇郡元非老手便，庶民安我貳車賢。',64,'全唐诗/poet.song.120000.json','["劇郡元非老手便，庶民安我貳車賢。", "二年不肯足到邑，千里寧容吏索錢。", "坐變池塘成貢宇，平分風月上吟篇。", "弟兄不減雲間陸，拭目看君日九遷。"]'),
('cf82d047-b2af-4b8d-9a63-ec7a5c9300c4','送陸通判  其二','王十朋','宋','宋诗','song-poetry','','[]','我十年前游會稽，堂名民事寓招提。',64,'全唐诗/poet.song.120000.json','["我十年前游會稽，堂名民事寓招提。", "去尋神禹藏書穴，歸泝子猷乘興溪。", "萬壑千巖形夢寐，十峯雙澗記留題。", "鑑湖倘許知章乞，首訪故人尊共携。"]'),
('e91bf9c8-48bc-4c92-b3ac-f00a34920828','觀郡守題名','王十朋','宋','宋诗','song-poetry','','[]','春秋美惡不嫌同，老子韓非一傳中。',32,'全唐诗/poet.song.120000.json','["春秋美惡不嫌同，老子韓非一傳中。", "壁上題名二百輩，卓然名世兩三公。"]'),
('9e6170ec-7f5b-4655-8b1b-0033e0202e17','龍眼','王十朋','宋','宋诗','song-poetry','','[]','絕品輕紅掃地無，紛紛萬木以龍呼。',32,'全唐诗/poet.song.120000.json','["絕品輕紅掃地無，紛紛萬木以龍呼。", "實如益智本非藥，味比荔支真是奴。"]'),
('2e9d799d-27fc-43f9-a273-d511320da1fb','金橘','王十朋','宋','宋诗','song-poetry','','[]','黄柑綠橘未分珍，瑣碎登盤輒獻新。',32,'全唐诗/poet.song.120000.json','["黄柑綠橘未分珍，瑣碎登盤輒獻新。", "正可呼爲木奴子，不知誰是鑄金人。"]'),
('f37b4ee3-8cfe-44c3-87a0-94fe1627e176','清源夫人趙氏挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','全節忠臣配，崇寧宰相家。',48,'全唐诗/poet.song.120000.json','["全節忠臣配，崇寧宰相家。", "哀能變國俗，貴不御鉛華。", "學佛窮三昧，然松教五車。", "遺芳載彤管，名壽兩俱遐。"]'),
('140dd184-32ba-412a-9299-9023fadaf22f','清源夫人趙氏挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','我竊清源祿，欽聞孟母慈。',48,'全唐诗/poet.song.120000.json','["我竊清源祿，欽聞孟母慈。", "符分三子舍，桂櫂兩孫枝。", "方戯黄堂綵，俄豐紫帽碑。", "神州嗟未復，長抱望夫悲。"]'),
('93601f22-ce92-437f-b106-be48082d8b66','食薑','王十朋','宋','宋诗','song-poetry','','[]','辣皺人眉性最良，藥中功效不尋常。',32,'全唐诗/poet.song.120000.json','["辣皺人眉性最良，藥中功效不尋常。", "吾儕自是生無智，夫子何曾食徹薑。"]'),
('7c14997c-d620-468f-8c3e-eeda31c6e49d','食芋','王十朋','宋','宋诗','song-poetry','','[]','我與瓜蔬味最宜，南來喜見大蹲鴟。',32,'全唐诗/poet.song.120000.json','["我與瓜蔬味最宜，南來喜見大蹲鴟。", "歸與傳取東坡法，糝玉爲羹且療饑。"]'),
('87849cc3-455c-47a8-89be-665718913255','夢二叔','王十朋','宋','宋诗','song-poetry','','[]','二叔年皆八十餘，經年不見久無書。',32,'全唐诗/poet.song.120000.json','["二叔年皆八十餘，經年不見久無書。", "江山不隔還鄉夢，昨夜迢迢到佛廬。"]'),
('4e71f159-3e07-4d26-8893-ae3fa8bf4a8c','懷胡侍郎邦衡','王十朋','宋','宋诗','song-poetry','','[]','今世汲長孺，廬陵胡侍郎。',48,'全唐诗/poet.song.120000.json','["今世汲長孺，廬陵胡侍郎。", "孤忠一封事，千載兩剛腸。", "晚節逢明主，丹心契上蒼。", "群兒巧相中，直道亦何傷。"]'),
('33b1c241-2240-4724-b0c1-51350c8eaa94','悼汪舍人養源','王十朋','宋','宋诗','song-poetry','','[]','襆被周廬日，寅緣識偉人。',48,'全唐诗/poet.song.120000.json','["襆被周廬日，寅緣識偉人。", "節因辭辟著，志向得言伸。", "伯仲同持橐，聲名壓縉紳。", "人亡邦國瘁，可贖百其身。"]'),
('a24e22f5-9b87-4955-bae0-7bd28f01eb6c','悼張舍人安國','王十朋','宋','宋诗','song-poetry','','[]','天上張才子，少年觀國光。',48,'全唐诗/poet.song.120000.json','["天上張才子，少年觀國光。", "高名一枝桂，遺愛六州棠。", "出世纔成佛，修文遽作郎。", "長紗屈賈誼，宣室竟凄凉。"]'),
('403eb5c3-4efe-4d39-a578-45c8f55d0b03','黄花','王十朋','宋','宋诗','song-poetry','','[]','溫陵地雖溫，十月初黄花。',48,'全唐诗/poet.song.120000.json','["溫陵地雖溫，十月初黄花。", "天然傲霜性，炎威莫能加。", "不趁重陽摘，自愛晚節嘉。", "宦游胡不歸，三徑荒吾家。"]'),
('fab1f3d0-77cf-40aa-847c-ce9bd2d9df00','飛蚊','王十朋','宋','宋诗','song-poetry','','[]','九月不肅霜，十月猶飛蚊。',48,'全唐诗/poet.song.120000.json','["九月不肅霜，十月猶飛蚊。", "不知從何來，乘昏動成群。", "觜利巧能嘬，類多非可熏。", "青蠅與白鳥，自古常紛紛。"]'),
('e23dae62-2197-4685-9de5-d86277c1ff0b','夫子泉','王十朋','宋','宋诗','song-poetry','','[]','君不見水經品第天下水，康王谷中泉第一。',198,'全唐诗/poet.song.120000.json','["君不見水經品第天下水，康王谷中泉第一。", "但知取水不取人，品第未容無得失。", "又不見武昌山中清泠淵，名因人重逢蘇仙。", "至今人呼作菩薩，淪入異教非吾泉。", "刺桐城中泮宮裏，大成殿下新泉水。", "不須更以品第論，混混源流自夫子。", "諸生游泳芹藻間，日飲一瓢心慕顔。", "聰明不數遠公社，清白大勝卧龍山。", "聖毓尼丘家闕里，泉脈胡爲今在是。", "周流天下皆美泉，浚井得之泉更美。", "我來酌泉仍叩頭，遐想洙泗三千游。", "世間何處有此水，此州無愧名泉州。"]'),
('182e76f6-f014-4d7d-99e6-442b728c5c97','立高桂坊','王十朋','宋','宋诗','song-poetry','','[]','書生未折桂，短檠事然膏。',144,'全唐诗/poet.song.120000.json','["書生未折桂，短檠事然膏。", "一朝桂入手，不記燈窗勞。", "回視紙上語，棄置等弁髦。", "曲學如公孫，高第何足褒。", "溫陵號多士，呦呦食苹蒿。", "臚唱十年間，魁亞出二豪。", "向來此坊中，一門五夢刀。", "月中仙子歸，天香滿藍袍。", "大對壓晁董，同登盡劉曹。", "嘉名換扁榜，鐵畫新揮毫。", "我欲成其美，遠大期伊臯。", "桂高固可喜，更看名節高。"]'),
('b767e243-1099-417e-a611-15e8f459679a','洛陽橋','王十朋','宋','宋诗','song-poetry','','[]','北望中原萬里遥，南來喜見洛陽橋。',64,'全唐诗/poet.song.120000.json','["北望中原萬里遥，南來喜見洛陽橋。", "人行跨海金鼇背，亭壓橫空玉虹腰。", "功不自成因砥柱，患宜預備有風潮。", "蔡公力量真剛者，遺愛勝於鄭國僑。"]'),
('c0993a83-29ae-47c3-b107-42b8cd762791','移庖貢院知宗即席賦詩次韵','王十朋','宋','宋诗','song-poetry','','[]','預讀嘉賓小雅章，銀袍行見鷺成行。',64,'全唐诗/poet.song.120000.json','["預讀嘉賓小雅章，銀袍行見鷺成行。", "彬彬周室士升俊，濟濟禹庭言拜昌。", "落筆詞源俱倒水，何人觜距獨專場。", "清源欲志新人物，定有英才副所望。"]'),
('8eb73d3c-cd9d-4b98-902a-b7b2db028f77','知宗贈金橘報以香橙','王十朋','宋','宋诗','song-poetry','','[]','橘以金爲重，橙因香見奇。',48,'全唐诗/poet.song.120000.json','["橘以金爲重，橙因香見奇。", "拜嘉欣熟早，報貺愧來遲。", "好處君須記，良天我正思。", "聊修往來好，更誦木瓜詩。"]'),
('d03834b5-191d-4c88-8357-87dfdbcb8166','乞祠不允','王十朋','宋','宋诗','song-poetry','','[]','微臣守清源，一歲三乞祠。',288,'全唐诗/poet.song.120000.json','["微臣守清源，一歲三乞祠。", "俞音竟未拜，感荷聖主慈。", "臣家素賤貧，仰祿救啼饑。", "區區六年間，手把四郡麾。", "道途壓奔走，囊橐無餘貲。", "清源乃佳郡，風俗不待移。", "民淳簡獄訟，士盛敦書詩。", "地遠可藏拙，祿厚足自資。", "今歲又豐登，千里人熙熙。", "臣豈不願仕，求閑欲奚爲。", "自憐螻蟻生，福薄命最奇。", "入境身即病，到官日呼醫。", "痰涎每上攻，旋暈勢甚危。", "藥試何止百，灼艾無全肌。", "臂疼如子美，齒落如退之。", "脚患柳州腫，髮垂孟郊絲。", "飲食日減少，跬步須扶持。", "殘喘雖尚延，定非久遠期。", "况臣糟糠妻，蓋棺將及朞。", "旅櫬猶未還，兒女晝夜悲。", "臣今官滿考，臣去有二宜。", "孰謂九重遠，天高而聽卑。", "吾君不之告，肝膽將誰披。", "廟堂二三公，誤辱平日知。"]'),
('a5b9300f-f61a-484c-a12e-c80bb2d62264','次韵陳賀州題姜秦二公祠 姜丞相','王十朋','宋','宋诗','song-poetry','','[]','姓名端合上麒麟，當世那知相是真。',64,'全唐诗/poet.song.120000.json','["姓名端合上麒麟，當世那知相是真。", "遺冢尚餘封馬鬣，孤忠曾記犯龍鱗。", "三巴流落知音士，九日追陪避世人。", "精爽不迷祠宇復，儼然唐室舊冠巾。"]'),
('ea035a60-13e8-4b39-95d3-f31c4b23e2e1','次韵陳賀州題姜秦二公祠 秦隠君','王十朋','宋','宋诗','song-poetry','','[]','去剡游閩避世喧，清風寥邈典刑存。',64,'全唐诗/poet.song.120000.json','["去剡游閩避世喧，清風寥邈典刑存。", "峯前鳥宿無名樹，祠下僧敲有月門。", "高尚端如上九蠱，含章更類六三坤。", "偏師勝後詩無敵，正要公來與共論。"]'),
('1e0d3c6e-c470-46c4-af09-3278fb9c5397','薛士昭寄新柑分贈知宗提舶知宗有詩次韵','王十朋','宋','宋诗','song-poetry','','[]','書後誰題字，鄉人遠寄柑。',120,'全唐诗/poet.song.120000.json','["書後誰題字，鄉人遠寄柑。", "薦新思起孝，知味戒生貪。", "羅帕分猶未，金門獻正堪。", "命名聊別僞，在果獨稱甘。", "白雪初盈樹，黄金忽滿籃。", "霜天欣始熟，茅舍飽相諳。", "客重開須請，兒癡食更婪。", "柳詩吟不厭，謝賦讀常躭。", "若蜜萍難比，如拳栗有慙。", "公家安定法，想見日酣酣。"]'),
('7f419d4d-376c-4716-a0ab-ddf406ae5454','知宗柑詩用韵頗險予既和之復取所未用之韵續賦一首三十韵','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','書閲揚州貢，功觀禹化覃。',288,'全唐诗/poet.song.120000.json','["書閲揚州貢，功觀禹化覃。", "香苞分橘柚，秋色動江潭。", "破暑花凝雪，凌寒葉染藍。", "金衣愛子照，珠實碧波涵。", "未上諸侯計，曾聞四浩談。", "顔歡陸績母，業世李衡男。", "送客愈吟桂，記時坡詠儋。", "洞庭夸浙右，溫郡冠江南。", "節物清霜重，家山綠蒂含。", "青黄出籬落，朱綠耀林嵐。", "昔貢千金顆，遥馳萬里函。", "新宜薦寢廟，香可供瞿曇。", "夔子那能比，羅浮未許叅。", "何人傳黄陸，端類列非聃。", "在品寧爲四，蒙恩或賜三。", "鄉情寄初熟，旅况憶幽探。", "嘉拜親開合，珍藏凈洗甔。", "行將解印綬，歸種當田蠶。", "根向橫陽覓，泥尋斥鹵檐。", "荒蕪耘徑草，封植伴溪楠。", "不用千頭富，聊資一餉湛。", "茅齋闢杜甫，仙井汲蘇躭。", "佳境妙餐蔗，閑庭勝蒔苷。", "雁行三峽荔，奴視四明蚶。"]'),
('e917cec5-ab87-40e7-b7da-1ef94e525737','林主簿明仲挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','齒德尊鄉黨，匈中有古今。',48,'全唐诗/poet.song.120000.json','["齒德尊鄉黨，匈中有古今。", "箕裘傳藴藻，臧否判崔林。", "呼佛知仁政，名軒見道心。", "扁舟欲訪戴，仙去不容尋。"]'),
('237c187d-b53a-4e26-b60e-6c552626a549','林主簿明仲挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','一箭雙鵰手，青衫已白頭。',48,'全唐诗/poet.song.120000.json','["一箭雙鵰手，青衫已白頭。", "硯幾磨鐵盡，官止及瓜休。", "漏斷鄞江夢，風含曲水愁。", "鈞天記白玉，麈世冷西樓。"]'),
('aa06c584-7273-4d75-9a62-cf1fb5ad7394','林主簿明仲挽詞  其三','王十朋','宋','宋诗','song-poetry','','[]','假舘城西日，清談屢獲陪。',48,'全唐诗/poet.song.120000.json','["假舘城西日，清談屢獲陪。", "江湖倦游宦，文字阻銜盃。", "方歎鸞栖棘，俄驚鳳去臺。", "雪梅開舊嶼，無復寄詩來。"]'),
('38df726b-2c6b-45ce-81d1-4c76e9d22480','擬賦江南寄梅花詩','王十朋','宋','宋诗','song-poetry','','[]','蔚宗居壠首，陸凱在江南。',72,'全唐诗/poet.song.120000.json','["蔚宗居壠首，陸凱在江南。", "手折梅花寄，人逢驛使堪。", "吳都尋半吐，楚岸摘新含。", "雪裏開纔一，樓頭弄未三。", "情深殊折柳，意重勝題柑。", "溪上千株玉，歸歟待自探。"]'),
('0162f28a-77e3-409f-9d4c-3f8dc140dec0','十月二十日買菊一株頗佳置于郡齋松竹之間目爲歲寒三友','王十朋','宋','宋诗','song-poetry','','[]','三百青錢一株菊，移置窗前伴松竹。',64,'全唐诗/poet.song.120000.json','["三百青錢一株菊，移置窗前伴松竹。", "鮮鮮正色傲霜性，不逐重陽上醽醁。", "誰云既晚何用好，端似高人事幽獨。", "南來何以慰凄凉，有此歲寒三友足。"]'),
('5ddb54b2-5d44-440b-8b89-642d3fe25f43','重修北樓十一月望日與郡僚同登因書十二韵','王十朋','宋','宋诗','song-poetry','','[]','我昔未作南諸侯，雄文嘗閲龍虎歐。',192,'全唐诗/poet.song.120000.json','["我昔未作南諸侯，雄文嘗閲龍虎歐。", "泉山風物得大畧，夢寐先已登茲樓。", "到官正要訪遺迹，忽見破屋城牆陬。", "欲修不敢遽土木，經歲此志方能酬。", "貢闈之餘材可辦，農事之隙工乃鳩。", "月逢建子飛破鏡，酒呼從事來青州。", "怱怱未暇衆賓集，草草且與同僚游。", "山川城郭壯哉郡，清源紫帽明雙眸。", "却驚雲榭在地底，坐見日轂經簷頭。", "西山端可拄頰視，南海未用乘桴浮。", "東瞻歸路興元亮，北望魏闕心子牟。", "揮毫欲續仲宣賦，假日聊以銷吾憂。"]'),
('474784ca-a460-42cb-8024-bc3c842a0838','諸公和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','欹眠聽詩韓喜侯，鋒難與爭劍鑄歐。',192,'全唐诗/poet.song.120000.json','["欹眠聽詩韓喜侯，鋒難與爭劍鑄歐。", "鈴齋淺陋無處著，挂在縹緲之飛樓。", "茲樓久欠詩酒味，天遣我輩來遐陬。", "塵埃聊用文字洗，瓦礫遂獲瓊瑶酬。", "賓朋未賞合開燕，老病欲登宜杖鳩。", "清風酌別記霅水，制勝領客思夔州。", "一江明月楚東醉，全家終日蓬萊遊。", "南來不謂有此境，四顧亦足窮吾眸。", "朝看日出閩海嶠，夜望斗插泉山頭。", "端如虢郡風月送，不比巴岳乾坤浮。", "登臨懷古甫白適，賦詠聯珠産鞏年。", "私心竊慕范文正，後天下樂先其憂。"]'),
('a5a81574-09cd-4d2b-bd1b-5f3d477bf6e0','哭萬先之','王十朋','宋','宋诗','song-poetry','','[]','太學時名重，吾鄉德譽崇。',48,'全唐诗/poet.song.120000.json','["太學時名重，吾鄉德譽崇。", "才華盍天祿，官職止儒宮。", "相國方知愈，諸公競薦雄。", "天涯忽聞訃，老淚洒西風。"]'),
('4c92e03d-4014-4043-bd7e-3d80aadeae9e','胡邦衡以集英殿修撰知漳州正人起廢有識相賀詩以志喜','王十朋','宋','宋诗','song-poetry','','[]','左右同時兩舍人，莫年得郡偶爲鄰。',64,'全唐诗/poet.song.120000.json','["左右同時兩舍人，莫年得郡偶爲鄰。", "泉山久著癡頑老，漳浦新除正直人。", "熱撰可能酬壯節，炎州聊復屈朱輪。", "拾遺補過須公輩，汲黯行歸侍紫宸。"]'),
('dcf8c7da-9e52-4c1d-bfc6-f65920800363','馮員仲復元官與致仕恩澤','王十朋','宋','宋诗','song-poetry','','[]','謗焰久自熄，果然天聽回。',48,'全唐诗/poet.song.120000.json','["謗焰久自熄，果然天聽回。", "孤忠昭聖代，遺恨釋泉臺。", "伏節同元帥，知音有上台。", "三軍氣應壯，一洗向時哀。"]'),
('db29076f-6deb-42a6-bc7c-08897263d672','次韻提舶見招','王十朋','宋','宋诗','song-poetry','','[]','江梅初破一陽天，詩句清新欲鬭妍。',32,'全唐诗/poet.song.120000.json','["江梅初破一陽天，詩句清新欲鬭妍。", "呼我同來飲文字，定扶衰病到尊前。"]'),
('865efe45-c3f1-4bb0-9fc7-1c90c7ff74c4','令人生日哭以小詩  其一','王十朋','宋','宋诗','song-poetry','','[]','生日今重見，細君嗟不回。',24,'全唐诗/poet.song.120000.json','["生日今重見，細君嗟不回。", "竟孤偕老願，忍看舊時梅。"]'),
('7378710e-69be-403e-b505-d1081477d47f','令人生日哭以小詩  其二','王十朋','宋','宋诗','song-poetry','','[]','去歲一盃酒，遽然生死分。',24,'全唐诗/poet.song.120000.json','["去歲一盃酒，遽然生死分。", "兒孫爲壽地，慟哭不堪聞。"]'),
('9693d15f-8824-4e98-a32c-09b604be6d8f','知宗生日','王十朋','宋','宋诗','song-poetry','','[]','昔年游越絕，首識南枝梅。',72,'全唐诗/poet.song.120000.json','["昔年游越絕，首識南枝梅。", "一麾守清源，再見梅英開。", "顔色宛如故，風霜不能摧。", "玉質長仙葩，芳姿醖詩才。", "其侶乃蟠桃，其根出蓬萊。", "花開三十年，壽薦三千杯。"]'),
('b101c244-b68f-4a29-822e-e8293824a83b','喻叔奇采坡詩一聯云今誰主文字公合把旌旄爲韵作十詩見寄某懼不敢和酬以四十韻','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','斯文韓歐蘇，千載三大老。',289,'全唐诗/poet.song.120000.json','["斯文韓歐蘇，千載三大老。", "蘇門六君子，如籍湜郊島。", "大匠具明眼，一一經選攷。", "豈曰文乎哉，蓋深於斯道。", "諸公既九原，氣象日衰槁。", "山不見泰華，水但識行潦。", "詞人巧駢儷，義理失探討。", "書生蔽時文，習義未易澡。", "著述豈無人，紛紛謾華藻。", "有如分裂時，僭僞各城堡。", "同年廣文君，所作非小好。", "高吟薄風雅，古學窮渾灝。", "讀史正豕亥，觀詩辨形夭。", "千篇冰玉清，萬字波瀾浩。", "心慕大手筆，所恨生不早。", "鄉令門及韓，不類端可保。", "賞識遇歐坡，當爲篋中寶。", "聲名終不掩，光豔姑自葆。", "嗟我最不才，兀兀首空皓。", "半生槐踏黄，晚景蓋張早。", "出守屢及瓜，還家僅嘗稻。", "田園荒淵明，江梅客張鎬。", "塵埃未能脫，憂患苦相惱。", "愁儹卧如蠶眉，痛徹伏犀腦。"]'),
('08eb9c19-874b-4730-bced-4e3acfbcfec6','題徐致政菊坡圖','王十朋','宋','宋诗','song-poetry','','[]','南方有高士，仁義偃王裔。',120,'全唐诗/poet.song.120000.json','["南方有高士，仁義偃王裔。", "家山闢幽坡，手取香草藝。", "秋至有黄華，采采滿衣袂。", "客來酒盈尊，詩出語驚世。", "無心學淵明，偶與淵明契。", "靜者年自長，頹齡不須制。", "高懷恥獨樂，地遠人罕詣。", "丹青寫佳境，有目皆可睨。", "吾家鮮鮮徑，荒蕪屢經歲。", "儒冠誤此身，掛之公得計。"]'),
('82ea06d7-8795-4a57-b58d-e3c0a20bd3ef','次韵吳明可見寄','王十朋','宋','宋诗','song-poetry','','[]','閩楚相望天一涯，思公不見見公詩。',64,'全唐诗/poet.song.120000.json','["閩楚相望天一涯，思公不見見公詩。", "遥知人在凝香處，正是梅逢驛使時。", "紫帽清源游已倦，落霞孤鶩看無期。", "它年杖屨天台去，采藥尋桃薦壽巵。"]'),
('6bea3dea-fde6-4340-ad68-e077861362d3','沈敦謨和詩見寄復用元韵','王十朋','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','天使吾儕復會同，笑談聲落酒筵中。',64,'全唐诗/poet.song.120000.json','["天使吾儕復會同，笑談聲落酒筵中。", "語離江北秋正杪，回首閩南歲又窮。", "春草池邊來好句，木奴皮裏隠仙翁。", "相將再上觀潮閣，我已三章乞道宮。"]'),
('3a3a8d97-a2cd-424b-9561-506445ca875c','曹夢良教授寄柑一百顆報以乾荔支戲成二絕  其一','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','故人書自許峯來，領得黄柑手自開。',32,'全唐诗/poet.song.120000.json','["故人書自許峯來，領得黄柑手自開。", "未滿洞庭三百顆，更看驛使一枝梅。"]'),
('e3b900fb-649e-42d8-8ed1-e5f94fad7827','曹夢良教授寄柑一百顆報以乾荔支戲成二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','絕品知君尚未嘗，三山絳帳喜相將。',32,'全唐诗/poet.song.120000.json','["絕品知君尚未嘗，三山絳帳喜相將。", "冷官豈是淹賢地，尤物聊觀十八娘。"]'),
('f7ffeb16-528b-48b8-8160-a080fbde6909','懷夢齡昌齡弟','王十朋','宋','宋诗','song-poetry','','[]','久別思吾弟，它鄉歲又除。',48,'全唐诗/poet.song.120000.json','["久別思吾弟，它鄉歲又除。", "日吟棠棣句，目斷雁行書。", "老去情尤惡，懷歸語似虛。", "祠章已三上，試爲掃茅廬。"]'),
('9f4d15f2-a458-48bd-85c7-035d58b7f254','臘月二十八日與知宗提舉分歲郡中啜茶于北樓賞梅於忠獻堂知宗即席有詩次韵并簡提舶','王十朋','宋','宋诗','song-poetry','','[]','老病踰年卧晉江，躭詩性癖未能降。',64,'全唐诗/poet.song.120000.json','["老病踰年卧晉江，躭詩性癖未能降。", "園林牢落梅經眼，歲月崢嶸酒滿缸。", "堂上焚香敬勳德，樓頭回首念家鄉。", "黄甘未拜蕭嵩賜，鄉味分珍謾一雙。"]'),
('974391e7-c5fe-4353-866c-d3e9416340f5','曾潮州到郡未幾首修韓文公廟次建貢闈可謂知化本矣某因讀韓公別趙子詩用韵以寄','王十朋','宋','宋诗','song-poetry','','[]','韓公學孔子，不陋九夷居。',204,'全唐诗/poet.song.120000.json','["韓公學孔子，不陋九夷居。", "詆佛譏君王，道大忠有餘。", "南遷八千里，文墨以自娛。", "至今潮陽人，比屋皆詩書。", "蓬茨得趙子，如獲滄海珠。", "臨行贈以言，恨不與之俱。", "德如昌黎公，聖人之徒與。", "比周孔孟軻，不道遷相如。", "韓公不可見，趙子今亦無。", "潮人敬愛公，百世祀不渝。", "英姿入山骨，凜凜蒼眉鬚。", "彼哉逢吉鏄，金章裹猿狙。", "使君藝且賢，所至政績殊。", "下車首風教，廟修庭草除。", "又聞新棘闈，輪奐歸畫圖。", "繼坡當有作，大筆文辭驅。", "惡詩願勿刻，人方笑其愚。"]'),
('24b90652-b082-4849-98ec-3f350bb3d026','送柯教授赴官四明','王十朋','宋','宋诗','song-poetry','','[]','士論鄉評總見欽，古猶難得况於今。',64,'全唐诗/poet.song.120000.json','["士論鄉評總見欽，古猶難得况於今。", "恥干一介將行李，慨爲孤甥罄橐金。", "晉水生徒懷絳帳，賢關故舊仰同襟。", "冷官豈是淹徊地，未到鄞江有召音。"]'),
('7bde6d57-a54b-4c08-93ed-3ed2cd21a079','寄崔肅之','王十朋','宋','宋诗','song-poetry','','[]','懷州別駕生賢丁，盤谷先生有外甥。',32,'全唐诗/poet.song.120000.json','["懷州別駕生賢丁，盤谷先生有外甥。", "暫屈才能居管庫，會看勝蹋繼家聲。"]'),
('42faebfe-b98f-4717-97bc-4b246b092818','燭花','王十朋','宋','宋诗','song-poetry','','[]','郡舍擁爐坐，燭開連夜花。',24,'全唐诗/poet.song.120000.json','["郡舍擁爐坐，燭開連夜花。", "主人無喜事，應是報還家。"]'),
('c8dc3fdb-5e99-4a27-9c3f-48f1d1921d01','次韵表叔賈元範見寄二首  其一','王十朋','宋','宋诗','song-poetry','','[]','華表飛來鶴姓丁，鹿巖依舊故山青。',64,'全唐诗/poet.song.120000.json','["華表飛來鶴姓丁，鹿巖依舊故山青。", "正緣松菊留仙隠，肯爲弓車到郡廳。", "德者能言書有力，仁人自壽藥非靈。", "坐看世事公應笑，落水楊花萬點萍。"]'),
('2446bd00-b591-4ad6-b442-905c529c39b6','次韵表叔賈元範見寄二首  其二','王十朋','宋','宋诗','song-poetry','','[]','記得公歸自汴京，瞭然目爲小生青。',64,'全唐诗/poet.song.120000.json','["記得公歸自汴京，瞭然目爲小生青。", "行能致遠由推轂，到即成渠荷建瓴。", "松柏歲寒知節操，芝蘭室邇化芬馨。", "白圭三復成陳迹，感德傷懷涕泗零。"]'),
('24094155-5a3d-4077-8cde-59985c726c44','人日喜晴','王十朋','宋','宋诗','song-poetry','','[]','元日至人日，幸無陰晦時。',48,'全唐诗/poet.song.120000.json','["元日至人日，幸無陰晦時。", "因思董勛問，却異少陵詩。", "遥想水披凍，坐看梅滿枝。", "明朝如得雨，正與穀相宜。"]'),
('e21bbfc1-6137-4aa3-932a-876f271fde52','元宵貢院張燈會客知宗即席賦詩次韵','王十朋','宋','宋诗','song-poetry','','[]','欲送羣英入帝鄉，預燒燈燭趣仙裝。',64,'全唐诗/poet.song.120000.json','["欲送羣英入帝鄉，預燒燈燭趣仙裝。", "銀花初合萬枝火，金榜已含千佛光。", "出海靈鼇駕蓬島，逐人明月散天香。", "笙歌鼎沸吟篇出，元白於詩媿未昌。"]'),
('be10a3ff-5290-4e5e-a9a6-20a8030a5d2a','送丁惠安','王十朋','宋','宋诗','song-poetry','','[]','把麾平海看操刀，惟我鄉人治最高。',64,'全唐诗/poet.song.120000.json','["把麾平海看操刀，惟我鄉人治最高。", "但見武城人易使，不同梁竦職徒勞。", "民懷其愛祠生立，吏必如公責始逃。", "聞說朝廷考臧否，僉言卓茂德宜褒。"]'),
('4280c3d4-0195-4534-bdd4-cd918c0cd81d','知宗示提舶贈新茶詩某未及和偶建守送到小春分四餠因次其韵','王十朋','宋','宋诗','song-poetry','','[]','建安分送建溪春，驚起松堂午夢人。',64,'全唐诗/poet.song.120000.json','["建安分送建溪春，驚起松堂午夢人。", "盧老書中纔見面，范公碾畔忽飛塵。", "十篇北苑詩無敵，兩腋清風思有神。", "日鑄卧龍非不美，賢如張禹想非真。"]'),
('563845fb-d5b0-4c98-a1cb-fd252fe72314','知宗贈馿肉以膰肉酬之','王十朋','宋','宋诗','song-poetry','','[]','不駿於乘合見烹，鈴齋指動荷分羹。',32,'全唐诗/poet.song.120000.json','["不駿於乘合見烹，鈴齋指動荷分羹。", "區區膰肉非相報，正恐公爲孔子行。"]'),
('2e982d6f-a7a4-406a-b3b8-10460d12a068','次韵贈新筍','王十朋','宋','宋诗','song-poetry','','[]','候屆中和日漸長，籜龍忽到愛松堂。',64,'全唐诗/poet.song.120000.json','["候屆中和日漸長，籜龍忽到愛松堂。", "便驚詩句含蔬味，更覺庖厨有細香。", "未學坡公參玉板，且同韓子賦篔簹。", "筍來茶往非爲禮，端爲詩情故得嘗。"]'),
('33a15332-d401-4bd2-8851-0f1e54bcd09e','曾潮州萬頃增闢貢院以元夕落成寄詩次韵','王十朋','宋','宋诗','song-poetry','','[]','韓公來自九重天，再見潮陽吏部賢。',64,'全唐诗/poet.song.120000.json','["韓公來自九重天，再見潮陽吏部賢。", "唾手渠渠蜚夏屋，揮毫混混寫源泉。", "丹霄有月逢三五，聖世生才協半千。", "太守落成應有語，立朝名節看儒先。"]'),
('3f6a9faa-9e27-4578-9ea6-768acb39c006','題並玉堂','王十朋','宋','宋诗','song-poetry','','[]','仙李門闌秀氣鍾，二山朋盍玉爲容。',160,'全唐诗/poet.song.120000.json','["仙李門闌秀氣鍾，二山朋盍玉爲容。", "晉人瀟灑坐連壁，杜老風流吟兩峯。", "崑府烟霞浮几席，藍田丘壑藴心胸。", "俯容列岫葭相倚，遥許它山石可攻。", "光徹郡城翔白鷺，影摇江水照黄龍。", "價高難把連城易，官冷聊將一穀供。", "疑是璣衡臨處落，端如日月合時逢。", "主賓對面成三友，伯仲摩雲拱九重。", "雁蕩浪誇鸞有侶，庾樓徒詫劍相從。", "綵衣戲罷看山色，不似慈顔喜氣濃。"]'),
('ce854713-e041-4d1e-b66b-6b1a4db2fc20','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其一','王十朋','宋','宋诗','song-poetry','','[]','清源太守鬢如蓬，未遂歸農又勸農。',32,'全唐诗/poet.song.120000.json','["清源太守鬢如蓬，未遂歸農又勸農。", "農事正興天不雨，誰能喚起老黄龍。"]'),
('add61f90-5061-4b1c-b519-6de14d8aa6fc','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其二','王十朋','宋','宋诗','song-poetry','','[]','二麥青黄雨失時，老農相顧但嗟咨。',32,'全唐诗/poet.song.120000.json','["二麥青黄雨失時，老農相顧但嗟咨。", "使君徒用虛文勸，稼穡艱難未必知。"]'),
('653aa034-4fa1-4054-8516-311bba813cf4','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其三','王十朋','宋','宋诗','song-poetry','','[]','我昔躬耕隴畝間，也知農事最艱難。',32,'全唐诗/poet.song.120000.json','["我昔躬耕隴畝間，也知農事最艱難。", "才踈政拙心勞甚，無補於民合掛冠。"]'),
('347ae391-cfed-4971-8a95-348ff0d745ac','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其四','王十朋','宋','宋诗','song-poetry','','[]','賣刀買犢慕龔遂，重穀務農思魯僖。',32,'全唐诗/poet.song.120000.json','["賣刀買犢慕龔遂，重穀務農思魯僖。", "僚友共懷憂國願，守臣非皺職田眉。"]'),
('a08fbe89-d783-4853-8db9-03c9ece6c949','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其五','王十朋','宋','宋诗','song-poetry','','[]','無術能銷旱魃災，吁嗟求雨只空回。',32,'全唐诗/poet.song.120000.json','["無術能銷旱魃災，吁嗟求雨只空回。", "鯫生豈是爲霖手，明日真人出洞來。"]'),
('49f8b00b-8d2f-449a-afc4-a85fd108d5ac','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其六','王十朋','宋','宋诗','song-poetry','','[]','萬歲名山兩度來，精廬瀟灑絕塵埃。',32,'全唐诗/poet.song.120000.json','["萬歲名山兩度來，精廬瀟灑絕塵埃。", "禪師妙得兵家策，杖屨飄然去不回。"]'),
('620e7b39-7c94-4a84-ab31-defa5ac6a707','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其七','王十朋','宋','宋诗','song-poetry','','[]','荔子今亡法石白，江山長带佛頭青。',32,'全唐诗/poet.song.120000.json','["荔子今亡法石白，江山長带佛頭青。", "老僧能說陳王事，遺冢猶傳女子靈。"]'),
('cff0190a-4696-4747-9074-c69a2d75b04b','出郊勸農飯蔬于法石僧舍時方閔雨有無麥之憂因成八絕  其八','王十朋','宋','宋诗','song-poetry','','[]','一徑通幽亭面牆，鳥啼林靜木蒼蒼。',32,'全唐诗/poet.song.120000.json','["一徑通幽亭面牆，鳥啼林靜木蒼蒼。", "礙人眼界宜斤斧，放出山光接海光。"]'),
('7e064726-7996-43a1-9607-2627be9c0453','食筍蕨','王十朋','宋','宋诗','song-poetry','','[]','犢角兒拳共作羹，大勝五鼎八珍烹。',32,'全唐诗/poet.song.120000.json','["犢角兒拳共作羹，大勝五鼎八珍烹。", "要須歸陟南山采，更看新移小竹生。"]'),
('b155dd19-6082-4bfe-8362-d9cc4083e423','悼陳提刑','王十朋','宋','宋诗','song-poetry','','[]','耆舊嗟零落，南來識太丘。',48,'全唐诗/poet.song.120000.json','["耆舊嗟零落，南來識太丘。", "有年兼有德，無怨亦無求。", "清室遺風在，新橋雅志酬。", "誰知燈火散，身世隔明幽。"]'),
('1b170353-3379-4a0b-b9fe-bc4e8d6d6555','聞胡邦衡改知泉州復用前韵','王十朋','宋','宋诗','song-poetry','','[]','上念溫陵爲擇人，知公名節世無隣。',64,'全唐诗/poet.song.120000.json','["上念溫陵爲擇人，知公名節世無隣。", "犯顔合在論思地，起廢聊爲岳牧臣。", "繆政居前誚穅秕，剛腸別久轉車輪。", "天教我輩簪重盍，只恐留中拱帝宸。"]'),
('a912ae3e-559a-445e-8545-599352b948ee','次韵何興化德揚閔雨','王十朋','宋','宋诗','song-poetry','','[]','熒惑照南紀，千里生塵埃。',168,'全唐诗/poet.song.120000.json','["熒惑照南紀，千里生塵埃。", "守臣失其職，閔雨腸空摧。", "奔走佞佛老，吁嗟禱風雷。", "爍石勢愈熾，望霓心可哀。", "民情有愁恨，天意那能回。", "緬懷端明公，豈薄德與才。", "乞雨問山神，胡爲亦遲徊。", "鄰邦賢使君，道妙藏靈臺。", "不待雨催詩，却以詩篇催。", "佇聽瀉糟牀，遥期銜賀盃。", "政理陰陽和，誠加金石開。", "餘波必及我，飄灑桐城隈。", "兩郡桐青青，年豐廩崔嵬。", "普天望作霖，公盍歸乎來。"]'),
('b92fc8bd-8374-42df-8ccc-917d3fc8f983','喜雨再用前韵','王十朋','宋','宋诗','song-poetry','','[]','南國久無雨，渴心欲生埃。',168,'全唐诗/poet.song.120000.json','["南國久無雨，渴心欲生埃。", "麥既枯且死，木亦黄而摧。", "方春雲已火，未夏蚊成雷。", "刺史固有罪，斯民自宜哀。", "真人及大士，久出應思回。", "閉陽縱諸陰，愧無董生才。", "林鳩厭呼喚，石燕徒低徊。", "有日上扶桑，無雲起陽臺。", "方修九淵祀，遽聞尺木催。", "想驚阿香夢，疑噀欒巴盃。", "夜中簷溜響，枕上愁顔開。", "願遍普天下，不止泉山隈。", "莫作鼎湖浪，因風下崔嵬。", "明朝賀雨詩，定自莆中來。"]'),
('ad1b9513-b856-4f80-82b7-49f1e36b3167','次韵龔實之正言見寄  其一','王十朋','宋','宋诗','song-poetry','','[]','堂堂人物冠清流，不減當年宋廣州。',64,'全唐诗/poet.song.120000.json','["堂堂人物冠清流，不減當年宋廣州。", "持節分符聊爾耳，直尋枉尺斷還不。", "初開宣室漢思賈，欲復侵疆魯召丘。", "整頓乾坤趁頭黑，早須歸伴赤松遊。"]'),
('88899f75-71ea-486e-9491-ea6ed3b1f475','次韵龔實之正言見寄  其二','王十朋','宋','宋诗','song-poetry','','[]','諫坡烏府迹相望，眼底何曾識六郎。',64,'全唐诗/poet.song.120000.json','["諫坡烏府迹相望，眼底何曾識六郎。", "去國雅欽龔勝節，得州欣近鄭公鄉。", "尺書遠荷鴻傳至，好句惟憂電取將。", "未見紫芝人已說，天庭喜氣十分黄。"]'),
('11471af7-7834-412c-87aa-f975274a1125','出郊迓客至石塔院憩劉公亭觀石筍橋東望郡城南瞻紫帽即事有作','王十朋','宋','宋诗','song-poetry','','[]','春日西郊外，江亭眼界嘉。',48,'全唐诗/poet.song.120000.json','["春日西郊外，江亭眼界嘉。", "青桐映樓閣，紫帽沒烟霞。", "雨過牛耕野，潮回鷺立沙。", "河梁阻携手，空起逝川嗟。"]'),
('e2c94a19-bd63-42b8-a65e-d58328fd24e6','用喜雨韻呈龔實之','王十朋','宋','宋诗','song-poetry','','[]','請雨徧群望，擾擾衝塵埃。',168,'全唐诗/poet.song.120000.json','["請雨徧群望，擾擾衝塵埃。", "際天麥浪空，刺水秧針摧。", "已近尺五天，未動滿盈雷。", "地欲赤晉國，年將饑魯哀。", "寄牋叩天門，好音清夜回。", "似傳上帝意，頗亦憐不才。", "披衣起視月，在畢方徘徊。", "忽聞蕭蕭聲，高洒熙熙臺。", "雲陣潑墨暗，電光摇幟催。", "燈前落簷花，欣銜少陵盃。", "綠波滿四澤，花柳村村開。", "知有一尺霖，來從傅巖隈。", "不作天寶詞，淋零悲馬嵬。", "定有元和詩，中銜諫書來。"]'),
('3c44abe0-7cb8-4511-a142-363c0f450113','石筍橋','王十朋','宋','宋诗','song-poetry','','[]','刺桐爲城石爲筍，萬壑西來流不盡。',355,'全唐诗/poet.song.120000.json','["刺桐爲城石爲筍，萬壑西來流不盡。", "黄龍窟宅占上游，呼吸風濤勢湍緊。", "怒潮拍岸鳴霹靂，淫潦滔天沒畦畛。", "行人欲渡無翼飛，魚腹蛟涎吁可閔。", "二三大士爲時出，目覩狂瀾心不忍。", "小試閑居濟川手，遠水孤舟寇忠愍。", "亦有山僧願力深，解使邦人指倉囷。", "五丁挽石投浩渺，萬指{石豕}山登嶾嶙。", "辛勤填海效精衛，突兀橫空飛海蜃。", "趾牢千尺鮫人室，護以兩旁獅子楯。", "南通百粵比三吳，檐負輿肩走騋牝。", "論功不減商舟楫，遺利宜書漢平準。", "莫將風月比揚州，二十四橋真蠢蠢。", "我時出郊春雨後，鷺點沙汀颺鷹隼。", "江亭矯首獨遐觀，有客南來盃共引。", "欲詠河梁擬蘇李，頗類鑑湖逢元稹。", "江山不逢賢太守，袖手沉吟覺才窘。", "况無鐵筆擬端明，徒使時人笑蚯蚓。", "綉衣屢約吾來遊，未遂堪嗟德星隕。", "鄉來嘗以記屬我，固避牢辭慙不敏。", "傳聞江欲飛棟初，異論紛紛互矛盾。", "世無剛者橋豈成，名與萬安同不泯。"]'),
('a12ab05d-cc2e-4834-838c-0aa226f5ab1f','林黄中少卿出守吳興芮國器司業以詩送之有今日桐城王刺史異時遺愛在吾州句用韻寄二公  其一','王十朋','宋','宋诗','song-poetry','','[]','出處平時正且嚴，猶於瓜李謹疑嫌。',64,'全唐诗/poet.song.120000.json','["出處平時正且嚴，猶於瓜李謹疑嫌。", "兩溪水照新明月，六客堂逢舊紫髯。", "安定化應孚學校，謝公思已結閭閻。", "湖山清遠使君好，想見邦人慰所瞻。"]'),
('fc229a1e-b524-4bea-978d-92d953fbd1d5','林黄中少卿出守吳興芮國器司業以詩送之有今日桐城王刺史異時遺愛在吾州句用韻寄二公  其二','王十朋','宋','宋诗','song-poetry','','[]','賢關今日陽司業，家在白蘋溪上州。',64,'全唐诗/poet.song.120000.json','["賢關今日陽司業，家在白蘋溪上州。", "筆下波瀾含震澤，胸中意氣屬清流。", "弁山疊拜南金贈，泉嶺遠蒙明月投。", "老矣惟公獨青眼，一言褒惜勝封侯。"]'),
('3e4d5a87-d4cd-4e50-923d-4df7c1ba9403','題蔣元肅藴仁堂','王十朋','宋','宋诗','song-poetry','','[]','人孰無父母，圖報良亦難。',132,'全唐诗/poet.song.120000.json','["人孰無父母，圖報良亦難。", "忽興風樹悲，莫盡菽水歡。", "君羹不易嘗，而况榮以官。", "向來蔣令君，慶具顔方丹。", "手折東堂桂，口詠南陔蘭。", "生封拜君命，戲彩慈顔溫。", "教之由義方，藴之在仁端。", "仁熟椿亦老，親榮心始安。", "堂在人事非，思親誠益殫。", "已足廣文飯，方彈貢公冠。", "願移前日孝，要作忠臣看。"]'),
('43ab0594-6534-4459-b24e-09f9bac41029','李伯時贈英石','王十朋','宋','宋诗','song-poetry','','[]','英石來從並玉堂，鈴齋几案聳鋒鋩。',32,'全唐诗/poet.song.120000.json','["英石來從並玉堂，鈴齋几案聳鋒鋩。", "平生性有好山癖，袖得兩峯歸故鄉。"]'),
('7b20e635-ed4d-406c-8b6a-158c3a2acd30','送潛老赴東禪  其一','王十朋','宋','宋诗','song-poetry','','[]','駐錫清源十五年，月明臺靜忽飄然。',32,'全唐诗/poet.song.120000.json','["駐錫清源十五年，月明臺靜忽飄然。", "禪心莫爲東禪起，南北東西總是禪。"]'),
('4d35fa30-7df3-48db-aec3-6698ef02d832','送潛老赴東禪  其二','王十朋','宋','宋诗','song-poetry','','[]','難弟難兄漢二龔，袈裟縫掖各清風。',32,'全唐诗/poet.song.120000.json','["難弟難兄漢二龔，袈裟縫掖各清風。", "淵明已遂歸田願，蓮社行將訪遠公。"]'),
('a6578725-a230-44fb-80e0-07e66fbfca80','陳提刑挽詞','王十朋','宋','宋诗','song-poetry','','[]','我守桐城公奉祠，登堂猶恨識公遲。',64,'全唐诗/poet.song.120000.json','["我守桐城公奉祠，登堂猶恨識公遲。", "心勞撫字陽司業，獄喜平反雋不疑。", "頭白不忘文字樂，室清宜作子孫規。", "棣華玉潤皆文傑，潛德幽光發妙詞。"]'),
('cd5e8627-788f-4f64-a064-e64169327167','送陳元龍赴封州教官','王十朋','宋','宋诗','song-poetry','','[]','溫陵尊酒偶相逢，記得同年舊日容。',64,'全唐诗/poet.song.120000.json','["溫陵尊酒偶相逢，記得同年舊日容。", "書讀短檠游太學，經傳絳帳適臨封。", "清新得句腸生錦，瘦硬通神筆吐鋒。", "莫向炎州嘆官冷，行看胡海起元龍。"]'),
('76502292-cdc3-4c2c-803c-821a8cc47d04','提舶生日','王十朋','宋','宋诗','song-poetry','','[]','正陽之月慝不作，氣候清和滿寥廓。',192,'全唐诗/poet.song.120000.json','["正陽之月慝不作，氣候清和滿寥廓。", "階餘嘉瑞十莢蓂，牆出新梢半含籜。", "正是生才好時節，化日舒長暑猶薄。", "遥遥華胄馬服君，世有功勳上臺閣。", "耳孫挺秀生東蜀，骨相堂堂人磊落。", "絳帳心潛南郡風，銅柱家傳伏波畧。", "致身朝列貳稷官，銜命江東訪民瘼。", "雍容敷奏天顔喜，小試舶臺良不惡。", "北風航海南風回，遠物來輸商賈樂。", "日邊知己皆達官，行矣歸持紫荷橐。", "平生德性不好飲，今日壽觴宜滿酌。", "爛柯仙侶年自長，不用西山一圓藥。"]'),
('7cd29674-f158-428c-96c0-f8942f997434','得葉飛卿書因寄貢院碑','王十朋','宋','宋诗','song-poetry','','[]','大字雄文照眼明，親題一軸寄松廳。',32,'全唐诗/poet.song.120000.json','["大字雄文照眼明，親題一軸寄松廳。", "千間廣厦能宣力，何止區區不負丞。"]'),
('d92d31e2-9cf9-41c3-bcd2-3b26797084fd','萬桂堂','王十朋','宋','宋诗','song-poetry','','[]','佛國新開選佛場，蟾宮分桂十千章。',64,'全唐诗/poet.song.120000.json','["佛國新開選佛場，蟾宮分桂十千章。", "邦人種德家家熟，仙籍題名葉葉香。", "地占清光一輪滿，門傳盛事五枝芳。", "東堂萬萬高攀手，莫負君恩與義方。"]'),
('d1a1c7b4-af8b-4017-b8ae-f8f9b15da024','表弟萬大年宿郡齋爲鼠蚊蚤所苦夜不安寢目爲三害某輒申造物之意諭之以詩','王十朋','宋','宋诗','song-poetry','','[]','萬子游清源，頗愛風物好。',240,'全唐诗/poet.song.120000.json','["萬子游清源，頗愛風物好。", "胡爲官舍中，害有蚊鼠蚤。", "嚙衣恣掀翻，聒耳倦揮掃。", "跳蟲從何來，出沒席與藁。", "中夜不安寢，披衣起呼皂。", "禽鼠磔其尸，驅蚊熏以草。", "熾炭烘衾禂，蟣虱亦俱薧。", "三害稍稍除，高眠起忘早。", "我時寢凝香，清夢到穹昊。", "仙官爲我言，必大有家寶。", "乃翁多隠德，子籍在蓬島。", "天將成就之，故以此相惱。", "要令坐達旦，萬卷飽探討。", "毋如老外兄，不學首空皓。", "彼蟲類最多，生育自洪造。", "盡殺則傷仁，兼容幸寬抱。", "萬子聞我言，往往笑絕倒。", "燔廬相參元，失馬福塞老。", "宴安生鴆毒，疾患資壽考。", "三害不必除，君言近乎道。"]'),
('32a23cd0-5fb2-427a-bbab-cd84ac04a821','薦新荔支','王十朋','宋','宋诗','song-poetry','','[]','晚年游宦到夔閩，四見輕紅荔子新。',32,'全唐诗/poet.song.120000.json','["晚年游宦到夔閩，四見輕紅荔子新。", "不似蒲萄橘羊棗，向來猶及遺慈親。"]'),
('ce0b1a0e-cb8c-4d34-a264-bed4d8539499','大言獨步郡圃即事有作次韵','王十朋','宋','宋诗','song-poetry','','[]','厭聽桐城雨，頻瞻雁蕩雲。',48,'全唐诗/poet.song.120000.json','["厭聽桐城雨，頻瞻雁蕩雲。", "它鄉見子面，好句張吾軍。", "草木心知敬，桑榆景未曛。", "淹留不須嘆，雞鶴偶同群。"]'),
('f1f56fb7-6e0e-458c-bfa0-e9a7c3be1ee0','早起','王十朋','宋','宋诗','song-poetry','','[]','老欲投閑尚未成，膠膠擾擾厭餘生。',32,'全唐诗/poet.song.120000.json','["老欲投閑尚未成，膠膠擾擾厭餘生。", "方成枕上游仙夢，忽聽窗前喚起聲。"]'),
('dd5f95ec-e6b3-4cd5-a143-4925d1ee66c4','刺桐花','王十朋','宋','宋诗','song-poetry','','[]','初見枝頭萬綠濃，忽驚火傘欲燒空。',32,'全唐诗/poet.song.120000.json','["初見枝頭萬綠濃，忽驚火傘欲燒空。", "花先花後年俱熟，莫遣時人不愛紅。"]'),
('d8cf7e3d-064b-4de3-85b2-96be33a3bc09','大年游延福寺','王十朋','宋','宋诗','song-poetry','','[]','去歲曾遊九日山，匆匆不暇盡躋攀。',32,'全唐诗/poet.song.120000.json','["去歲曾遊九日山，匆匆不暇盡躋攀。", "煩君訪我不到處，好把詩篇載取還。"]'),
('f8df4c47-4f0b-445d-bf4e-6b42666bf32b','提舶贈玉友六言詩次韵以酬  其一','王十朋','宋','宋诗','song-poetry','','[]','重見異鄉佳節，又成終日清齋。',28,'全唐诗/poet.song.120000.json','["重見異鄉佳節，又成終日清齋。", "忽捧晉堂雙玉，引觴澆破愁懷。"]'),
('6b62fe77-6fcb-450c-bdb4-1a6ec9954df8','提舶贈玉友六言詩次韵以酬  其二','王十朋','宋','宋诗','song-poetry','','[]','兢渡爭飛畫舫，賜衣紛集丹墀。',28,'全唐诗/poet.song.120000.json','["兢渡爭飛畫舫，賜衣紛集丹墀。", "舉筆不忘規諫，玉堂誰進歐詩。"]'),
('1013ccdb-96dc-4e57-892d-7b76508a420c','覓百葉榴花','王十朋','宋','宋诗','song-poetry','','[]','玉友雙瓶不惡，錦囊六字尤清。',28,'全唐诗/poet.song.120000.json','["玉友雙瓶不惡，錦囊六字尤清。", "更覓榴花百葉，要令老眼增明。"]'),
('43b6b33d-ecc8-4ec2-af1b-e391fe3d042c','寄陳大諫','王十朋','宋','宋诗','song-poetry','','[]','公居言路望非輕，天下人皆側耳聽。',64,'全唐诗/poet.song.120000.json','["公居言路望非輕，天下人皆側耳聽。", "方欲携書責陽子，忽聞有疏論延齡。", "危言已落奸邪膽，正色潛消魍魎形。", "天聽未回須力爭，從茲受責亦芬馨。"]'),
('818f16b5-1451-44f2-841c-054d28359bce','天申節放生','王十朋','宋','宋诗','song-poetry','','[]','夫子釣不綱，仁心戒盡物。',264,'全唐诗/poet.song.120000.json','["夫子釣不綱，仁心戒盡物。", "君子遠庖厨，孟軻論仁術。", "生魚舍子産，獸網祝天乙。", "於牣文王沼，靈德壽周室。", "唐置放生池，天下八十一。", "至今湖州碑，輝耀魯公筆。", "我宋仁如天，神武而不殺。", "華夏及蠻貊，卵胎暨化濕。", "皆歸好生德，惟恐一物失。", "清源號佛國，此典胡獨缺。", "耽耽舉子場，馥馥荷華隰。", "誕節逢千秋，錫宴遍郡邑。", "何以壽吾君，故事修遺逸。", "魚鼈族至微，端頼尺水活。", "况茲十畝池，中含千里闊。", "郭索行草泥，玄夫巢蓮葉。", "長鬚及衆鱗，巨細各儔匹。", "圉圉復洋洋，生意俱可必。", "永逃數罟憂，咸被中孚吉。", "中有六六魚，聊茲友螾蛭。", "一朝得雲雨，龍門變凡質。", "歲旱當作霖，莫忘池中日。"]'),
('5a2cadc2-9d3d-4259-a7fb-7864ab14050a','送知宗奉祠還越  其一','王十朋','宋','宋诗','song-poetry','','[]','堂堂人物宋宗英，來主金枝玉葉盟。',64,'全唐诗/poet.song.120000.json','["堂堂人物宋宗英，來主金枝玉葉盟。", "麟趾化成公族厚，棣華詩作爭心平。", "金尊對客吟篇逸，貝葉談空世味輕。", "五月仙舟鑑湖去，芰荷香裏奏新聲。"]'),
('66646dc9-ac39-48ec-b6e9-ddc22bbce910','送知宗奉祠還越  其二','王十朋','宋','宋诗','song-poetry','','[]','綠水芙蕖汎鎮東，一觴一詠辱陪公。',64,'全唐诗/poet.song.120000.json','["綠水芙蕖汎鎮東，一觴一詠辱陪公。", "轉頭十載已陳迹，會面二山俱禿翁。", "舊隠重尋賀監宅，歸帆遥借若邪風。", "九重側席待宗老，願展惓惓劉向忠。"]'),
('bfcd724a-b8fd-4643-82c6-059f72c8466b','愛松堂納凉','王十朋','宋','宋诗','song-poetry','','[]','鈴齋苦炎熱，松竹生晚凉。',48,'全唐诗/poet.song.120000.json','["鈴齋苦炎熱，松竹生晚凉。", "颯然清我襟，兀坐興味長。", "我無桑下戀，愛此獨不忘。", "願言勿翦伐，清陰常滿堂。"]'),
('e3f3e264-3eac-4982-a0ec-a0a6b6f22fc8','郡齋夜坐聞水車聲  其一','王十朋','宋','宋诗','song-poetry','','[]','風伯吹雲不成雨，稼穡如焚誰守土。',64,'全唐诗/poet.song.120000.json','["風伯吹雲不成雨，稼穡如焚誰守土。", "鈴齋夜聞水車聲，遥想田間老農苦。", "汗流氣喘饑眼花，厭聞窟中鼉打衙。", "妻兒相勞勿愁嘆，多少高田無水車。"]'),
('3750bfd0-00e4-4971-bc71-f365b1145e45','郡齋夜坐聞水車聲  其二','王十朋','宋','宋诗','song-poetry','','[]','天二欲警老刺史，車聲夜入凝香耳。',64,'全唐诗/poet.song.120000.json','["天二欲警老刺史，車聲夜入凝香耳。", "四郊苗槁農民悲，萬壑水乾魚鼈死。", "守臣失職政事荒，誰遣連年坐黄堂。", "自慚不及段文昌，聖世豈有桑弘羊。"]'),
('5d47b74e-d5d3-44eb-b44e-13e3b8638b61','末利花','王十朋','宋','宋诗','song-poetry','','[]','日莫園人獻寶珠，化成千億小芙蕖。',32,'全唐诗/poet.song.120000.json','["日莫園人獻寶珠，化成千億小芙蕖。", "使君燕寢無沉麝，凝此清香自有餘。"]'),
('bbddd824-4c90-46ae-8b7a-58bd9e23c580','次韵傅教授景仁馬綠荔支','王十朋','宋','宋诗','song-poetry','','[]','玉座奇包未與頒，伏波家果忽堆盤。',64,'全唐诗/poet.song.120000.json','["玉座奇包未與頒，伏波家果忽堆盤。", "宜書蔡譜均稱綠，不比韓詩止詠丹。", "薦李徒誇碧實脆，嚼瓜未覺水晶寒。", "羨君衫鬢巧相似，我坐郡廳慚素餐。"]'),
('298aa516-6353-49db-b769-35d55decadfc','再次韵','王十朋','宋','宋诗','song-poetry','','[]','兩載閩南白盡頒，驚看異品上杯盤。',64,'全唐诗/poet.song.120000.json','["兩載閩南白盡頒，驚看異品上杯盤。", "發緘初訝囊非絳，擘實猶疑頰未丹。", "較美宜同法石白，攙先欲占麥秋寒。", "廣文詩句篇篇好，咀嚼令人欲廢餐。"]'),
('77ed6622-0cfe-4300-af5c-b83f2698626f','三次韵','王十朋','宋','宋诗','song-poetry','','[]','荔子新詩屢見頒，端同玉局賦金盤。',64,'全唐诗/poet.song.120000.json','["荔子新詩屢見頒，端同玉局賦金盤。", "香包盡带賜袍綠，熟顆半含仙竈丹。", "西蜀稍多應喜遠，東嘉可種似宜寒。", "微酸好入鹽梅鼎，莫作尋常諫果餐。"]'),
('c9c40e81-786d-40e4-b665-89a30a0d63e6','四次韵','王十朋','宋','宋诗','song-poetry','','[]','蔡譜黄詩久已頒，不同馬乳漫堆盤。',64,'全唐诗/poet.song.120000.json','["蔡譜黄詩久已頒，不同馬乳漫堆盤。", "色因不惡故名酒，食可成仙何用丹。", "追逐故江相上下，比方魁紫稍孤寒。", "殷勤百顆分甘意，端爲詩情合得餐。"]'),
('44c43007-6258-41b0-8fd6-1296be9fc240','五次韵','王十朋','宋','宋诗','song-poetry','','[]','涪陵妃子謾名園，豈似閩南綠一盤。',64,'全唐诗/poet.song.120000.json','["涪陵妃子謾名園，豈似閩南綠一盤。", "最喜色同青玉案，不妨功並紫金丹。", "畫看紅紫品流俗，詩嚼氷霜牙頰寒。", "吟罷閒觀右軍帖，來禽青李可同餐。"]'),
('fe11dc27-e413-4f87-aa2a-a499b312a733','六次韵','王十朋','宋','宋诗','song-poetry','','[]','年少題詩入杏園，橫空硬語勝郊盤。',64,'全唐诗/poet.song.120000.json','["年少題詩入杏園，橫空硬語勝郊盤。", "新吟陳紫并江綠，深逼蕉黄與荔丹。", "官舍聊淹廣文冷，雁行高並玉峯寒。", "黄堂病守相將去，秋菊落英誰共餐。"]'),
('5d506b0a-879f-4d7e-8d8e-c12f8586ac0c','七次韵','王十朋','宋','宋诗','song-poetry','','[]','平生雅意在丘園，行矣歸尋隠者盤。',64,'全唐诗/poet.song.120000.json','["平生雅意在丘園，行矣歸尋隠者盤。", "此日詩盟共君結，明年荔子爲誰丹。", "欲移仙種栽中土，只恐天資不耐寒。", "定向家鄉想風味，江瑶斫柱謾加餐。"]'),
('714302e7-33bf-4684-8ab5-f7f6ec362847','得雨復用聞水車韵  其一','王十朋','宋','宋诗','song-poetry','','[]','蛻骨木龍憂不雨，更喚兩牛眠下土。',64,'全唐诗/poet.song.120000.json','["蛻骨木龍憂不雨，更喚兩牛眠下土。", "水從地底飛上田，不減在天行雨苦。", "庭中忽見天雨花，白衣真人游郡衙。", "但願爲霖莫爲潦，免使泥陷羸牛車。"]'),
('3f343c76-c11b-4a17-9dcd-873ce7df99e0','得雨復用聞水車韵  其二','王十朋','宋','宋诗','song-poetry','','[]','亢旱踰時如魯史，一雨已遲淹爾耳。',64,'全唐诗/poet.song.120000.json','["亢旱踰時如魯史，一雨已遲淹爾耳。", "農猶滿望苗返魂，車亦收聲魚免死。", "我持酒戒不敢荒，急呼一盃飲松堂。", "不憂猖獗有巢昌，只恐沈猶朝飲羊。"]'),
('93dd4d06-233b-4082-ab7b-53978feecb44','吳宗教惠西施舌戲成三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','吳王無處可招魂，惟有西施舌尚存。',32,'全唐诗/poet.song.120000.json','["吳王無處可招魂，惟有西施舌尚存。", "曾共君王醉長夜，至今猶得奉芳尊。"]'),
('9463b7a7-06b2-4da1-8ec8-e968a3c731c3','吳宗教惠西施舌戲成三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','博物延陵有令孫，不因官冷作儒酸。',32,'全唐诗/poet.song.120000.json','["博物延陵有令孫，不因官冷作儒酸。", "珍庖自有西施舌，風味堪陪北海尊。"]'),
('d5545ae5-11b9-457d-9e70-a855866e34de','吳宗教惠西施舌戲成三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','長記還家屢擊鮮，南來歸興日飄然。',32,'全唐诗/poet.song.120000.json','["長記還家屢擊鮮，南來歸興日飄然。", "不緣樽俎逢西子，始泛江湖范蠡船。"]'),
('31dd6e94-49ac-4ec3-9cc4-691514837659','貢院食新荔觀雙蓮因成六言','王十朋','宋','宋诗','song-poetry','','[]','兩郡兩逢新荔，三年三結雙蓮。',28,'全唐诗/poet.song.120000.json','["兩郡兩逢新荔，三年三結雙蓮。", "酒盞莫辭在手，異時同把無緣。"]'),
('80ab8cf7-7c5c-4ffa-8fe8-b28b0f3bff0b','分韵得兩字','王十朋','宋','宋诗','song-poetry','','[]','官舍苦炎熱，貢闈快虛敞。',72,'全唐诗/poet.song.120000.json','["官舍苦炎熱，貢闈快虛敞。", "急呼玉友生，閑共同僚賞。", "堂成桂植萬，堤就池分兩。", "蓮開花並蒂，荔擘珠在掌。", "詩句聽細論，塵襟發清爽。", "行矣北歸翁，山林起遥想。"]'),
('5149f329-12f8-4ac7-a6ad-eac58bbb994b','雲榭納凉','王十朋','宋','宋诗','song-poetry','','[]','人間正炎熱，雲榭獨清凉。',24,'全唐诗/poet.song.120000.json','["人間正炎熱，雲榭獨清凉。", "如欲慰黎庶，諸君宜奉揚。"]'),
('8ca28f8a-6c7e-48ed-8445-0aa339a4a87d','分韵得宜字','王十朋','宋','宋诗','song-poetry','','[]','榭向雲間築，風從天半吹。',48,'全唐诗/poet.song.120000.json','["榭向雲間築，風從天半吹。", "談方以清飽，襟更爲凉披。", "雄入蘭臺賦，微生殿閣詩。", "倚欄觀出岫，吾去亦誠宜。"]'),
('acb8ff80-6f23-4ad2-a23f-455899d60e0b','罷官述懷','王十朋','宋','宋诗','song-poetry','','[]','去矣清源守，皤然雪滿顛。',48,'全唐诗/poet.song.120000.json','["去矣清源守，皤然雪滿顛。", "居官無善政，排悶有詩篇。", "朋盍三盃酒，公餘一覺眠。", "泉人豈思我，我意自思泉。"]'),
('ea3bc189-be3c-4e1c-a37a-5a9f26280f28','出州宅','王十朋','宋','宋诗','song-poetry','','[]','官居到處郵傳，歲月驚人電飛。',28,'全唐诗/poet.song.120000.json','["官居到處郵傳，歲月驚人電飛。", "惆悵同來德耀，故鄉不與同歸。"]'),
('df1ad934-d053-4533-98ff-e4cb2b1cb95c','寓清源驛','王十朋','宋','宋诗','song-poetry','','[]','兩年繆作清源守，不到清源洞裏游。',32,'全唐诗/poet.song.120000.json','["兩年繆作清源守，不到清源洞裏游。", "天恐孤予遠來意，驛中聊許少遲留。"]'),
('8ad9f2c2-f635-4c97-8853-ba153bfae043','諸公餞別分韵得人字','王十朋','宋','宋诗','song-poetry','','[]','清源古名郡，守土宜擇人。',204,'全唐诗/poet.song.120000.json','["清源古名郡，守土宜擇人。", "胡爲不才者，兩載乘朱輪。", "政拙歲多旱，民愁眉日顰。", "頼茲淳厚俗，容我老病身。", "乞祠竟不允，易郡俄得鄰。", "雅懷上冢願，偶有還鄉因。", "賓僚共呼酒，肴蔌嘉且新。", "展餞選士場，語離庚伏辰。", "清風屢吹衣，暑雨微灑塵。", "驪駒沸盈門，鸚鵡飛入唇。", "我亦重惜別，不辭勸酬頻。", "諸君如神魚，行奮六六鱗。", "學士倍登瀛，郡符同治秦。", "我如倦蜚鳥，野性難籠馴。", "舊巢尋故山，一枝老荆榛。", "官居類郵傳，誰能久相親。", "但願各勉力，相期作純臣。"]'),
('c65f9060-c7e6-4949-ac7b-0e7a005efea2','枕上聞雨聲','王十朋','宋','宋诗','song-poetry','','[]','枕上微聞點滴聲，皇天有意捄蒼生。',32,'全唐诗/poet.song.120000.json','["枕上微聞點滴聲，皇天有意捄蒼生。", "雖然未作商家雨，已覺炎方暑氣清。"]'),
('c9b9840a-4c6f-4cc7-b82f-f8be0fc5bd61','聞角聲','王十朋','宋','宋诗','song-poetry','','[]','角聲已作送行聲，更向蕭蕭雨後聽。',32,'全唐诗/poet.song.120000.json','["角聲已作送行聲，更向蕭蕭雨後聽。", "明日出郊聞更遠，回頭忍見二山青。"]'),
('09ee13c9-7310-444f-8a13-bedc78c0b44e','復安靜堂舊額','王十朋','宋','宋诗','song-poetry','','[]','端明之孫字子强，銀鈎鐵畫傳遺芳。',240,'全唐诗/poet.song.120000.json','["端明之孫字子强，銀鈎鐵畫傳遺芳。", "昔年作郡古平海，大筆親書安靜堂。", "自從宣和至乾道，字與輪奐爭光芒。", "一朝忽遭俗眼白，毀滅名姓深埋藏。", "我來搜訪久乃獲，老兵據爲寢處牀。", "滌除五載塵土面，字向堂上增激昂。", "祖爲第一孫是似，書有家法稱莆陽。", "體具萬安頗雄壯，榜與忠獻同翱翔。", "因知文字乃至寶，一時之厄庸何傷。", "石鼓文有鬼神護，淮西碑並日月光。", "豈容泯滅暴秦火，誰肯膾炙段文昌。", "書生作郡太迂闊，理財聽訟俱非長。", "吾君若問何以治，堂復韓蔡祠秦姜。", "今纔五日京兆耳，眷此陳迹猶未忘。", "但願茲堂日安靜，名與國壽俱無疆。"]'),
('78747318-b798-4f7e-822f-97c8aafe0c69','次蔣元肅韵','王十朋','宋','宋诗','song-poetry','','[]','酒盃三十六人銜，勸我殷勤不止三。',64,'全唐诗/poet.song.120000.json','["酒盃三十六人銜，勸我殷勤不止三。", "長記白蘋離浙右，忍看丹荔別泉南。", "自慚政似陽城拙，那得棠如召伯甘。", "見說廣文尤惜別，好詩千里送歸驂。"]'),
('7aa72bd0-d90e-4170-9c65-807cf294ed83','贈李宜之運幹','王十朋','宋','宋诗','song-poetry','','[]','謫仙苗裔自非凡，家學端能嗣大參。',64,'全唐诗/poet.song.120000.json','["謫仙苗裔自非凡，家學端能嗣大參。", "一見便知空冀北，三年長嘆滯周南。", "絕畦翰墨僕騷可，請試言詞倚馬堪。", "莫道南來橐無寶，一編傳得小雲龕。"]'),
('94349fe5-de93-4413-a5c6-883a87f1d443','記風','王十朋','宋','宋诗','song-poetry','','[]','泉南固多風，茲風大爲最。',240,'全唐诗/poet.song.120000.json','["泉南固多風，茲風大爲最。", "初驚月有暈，忽聽天鳴籟。", "蓬蓬從何來，烈烈不可奈。", "萬竅爭怒號，三光變冥昧。", "掀翻敗牆壁，摧折到松檜。", "瓦飄上天半，茅捲灑郊外。", "稻吹垂實花，果墮未熟蔕。", "山川失故容，草木遭厄會。", "飛同鷁過宋，悲異見歌沛。", "孰云楚臺雄，未覺周郊大。", "雖然不終朝，無乃已被害。", "嗟予垂素髮，濫此張皁蓋。", "方憂西疇禾，未問南海貝。", "心如韓值颶，卜效蘇命蔡。", "焚香叩穹昊，防患問耆艾。", "稍稍雲色定，徐徐雨聲霈。", "漸停箕簸揚，會見氣交泰。", "居民理破屋，老守戒征旆。", "五絃歌舜琴，一絲詠嚴瀨。", "去矣不待瓜，歸歟及鱸鱠。"]'),
('923b597a-6e6a-4e2d-8085-825d3ddd269e','蔡端明祠堂','王十朋','宋','宋诗','song-poetry','','[]','公昔自禁從，再來臨此邦。',48,'全唐诗/poet.song.120000.json','["公昔自禁從，再來臨此邦。", "河梁一何壯，筆力獨能扛。", "政績留南紀，祠堂枕大江。", "山川與人物，今古兩無雙。"]'),
('05159e95-da44-485f-b7a9-04a3282f0023','別傅教授景仁','王十朋','宋','宋诗','song-poetry','','[]','鼻祖調羹佐有商，耳孫家業踵前芳。',64,'全唐诗/poet.song.120000.json','["鼻祖調羹佐有商，耳孫家業踵前芳。", "萬言書有鹽梅味，千首詩開錦綉腸。", "絳帳詎容淹久次，制科端欲待非常。", "歸囊剩有君佳句，更獲珠璣四十章。"]'),
('9e503a51-7a8c-45aa-b07f-53337d39ed2a','贈陳教授正仲','王十朋','宋','宋诗','song-poetry','','[]','益友乎生所願親，南來深喜得斯人。',64,'全唐诗/poet.song.120000.json','["益友乎生所願親，南來深喜得斯人。", "淵源師杜真知體，人物如平豈久貧。", "絳帳可能淹教育，掖垣便合掌絲綸。", "臨行贈我五百字，楚璧隋珠未足珍。"]'),
('b3787fd3-facf-4591-9e29-ac34daa31089','挽令人','王十朋','宋','宋诗','song-poetry','','[]','糟糠情味飽相諳，我事耕耘爾力蠶。',64,'全唐诗/poet.song.120000.json','["糟糠情味飽相諳，我事耕耘爾力蠶。", "誤走迷途半天下，忽驚魂夢斷泉南。", "二年旅櫬悲無奈，千里途車涕不堪。", "預卜黄華晚秋節，佳城歸祔白巖庵。"]'),
('e417930f-9b92-48d7-867d-680175791ad6','贈陳體仁','王十朋','宋','宋诗','song-poetry','','[]','我來守清源，德星識二陳。',240,'全唐诗/poet.song.120000.json','["我來守清源，德星識二陳。", "大陳如金玉，一室清無塵。", "厭世不肯留，至今里稱仁。", "儒先賀州守，才氣超等倫。", "胸中包古今，筆下真有神。", "唾手取甲科，齒髮方青春。", "聲名滿天下，文字驚縉紳。", "勞人暫州縣，平步當要津。", "蹉跎忽至今，此志猶未伸。", "真人奉香火，蕭寺含悲辛。", "講席延諸生，黄卷訶古人。", "異端斥佛老，吾道鳴孟荀。", "聊籍束脩禮，少資囊橐貧。", "我忝二千石，二年牧斯民。", "不能助玉川，恥與韓公均。", "贈我詩與文，字字皆可珍。", "寵褒恨太過，感激難具論。", "願公少自愛，行矣當致身。", "門下有高第，廟堂手經綸。", "房魏方得君，詎肯忘河汾。"]'),
('9c9ec015-b012-4185-b9de-84db0f1c93ff','贈林尉致約','王十朋','宋','宋诗','song-poetry','','[]','紅顔白面神仙吏，好學苦吟真我徒。',32,'全唐诗/poet.song.120000.json','["紅顔白面神仙吏，好學苦吟真我徒。", "政事文章有家法，它年呼作小龍圖。"]'),
('8a4d3c72-68c7-426d-a64c-cc0e21168c9a','臨行至貢院觀桂贈致約','王十朋','宋','宋诗','song-poetry','','[]','竊祿清源愧不才，貢闈臨去尚徘徊。',32,'全唐诗/poet.song.120000.json','["竊祿清源愧不才，貢闈臨去尚徘徊。", "青青萬本新移桂，盡是梅仙手爲栽。"]'),
('6553383e-cb2b-4444-9a7f-1d813796f940','宿寂光院','王十朋','宋','宋诗','song-poetry','','[]','青山環繞如盤谷，中有清幽佛子家。',32,'全唐诗/poet.song.120000.json','["青山環繞如盤谷，中有清幽佛子家。", "人昔共來今不見，數行老淚濕烟霞。"]'),
('00716cff-f88c-4344-bb7f-1de60ad37583','陳德溥以百韵詩送別因贈一絕','王十朋','宋','宋诗','song-poetry','','[]','蓮幕游從一二年，送行越境繼前賢。',32,'全唐诗/poet.song.120000.json','["蓮幕游從一二年，送行越境繼前賢。", "筆頭皆有珠千顆，端似少陵夔府篇。"]'),
('c2f198f4-2a8c-4ba4-b2a7-0fdd76276478','越境送別者七人蔣元肅黄少度鹿伯可趙元序陳德溥葉飛卿林致約少酌驛舍','王十朋','宋','宋诗','song-poetry','','[]','同僚送我楓庭驛，共酌臨分酒一杯。',32,'全唐诗/poet.song.120000.json','["同僚送我楓庭驛，共酌臨分酒一杯。", "我念泉人仍惜別，此身雖去首頻回。"]'),
('ccc56594-25af-478b-828b-458693cc8d92','別蔣元肅','王十朋','宋','宋诗','song-poetry','','[]','符竹南來識廣文，經橫講席見淵源。',64,'全唐诗/poet.song.120000.json','["符竹南來識廣文，經橫講席見淵源。", "凌雲詞賦勝三賦，醫國忠言壓萬言。", "陳迹互將文字記，交情更向別離論。", "君方騰踏吾衰矣，名節相期百世存。"]'),
('df68a19e-4e3c-4acc-8c68-73a96d17b006','題莆田林氏雙闕','王十朋','宋','宋诗','song-poetry','','[]','唐室遥遥孝義門，屹然雙闕至今存。',32,'全唐诗/poet.song.120000.json','["唐室遥遥孝義門，屹然雙闕至今存。", "當時泣盡思親血，化作恩波遺子孫。"]'),
('936ebc5a-2fdd-46de-b93d-c796e8da29d7','過頭陀九嶺宿天王棲林二招提因成三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','凌晨飽飯渡秦溪，要上青山九級梯。',32,'全唐诗/poet.song.120000.json','["凌晨飽飯渡秦溪，要上青山九級梯。", "不使甌閩隔人世，頭陀力與五丁齊。"]'),
('f9534273-927e-4c4f-bf20-7da368d8b539','過頭陀九嶺宿天王棲林二招提因成三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','千里歸塗險更長，眼中深喜見天王。',32,'全唐诗/poet.song.120000.json','["千里歸塗險更長，眼中深喜見天王。", "從今漸入平安境，舊路艱辛未敢忘。"]'),
('e68dde16-c83e-48ac-8e40-97f918b137da','過頭陀九嶺宿天王棲林二招提因成三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','我如倦鳥欲栖林，喜見禪僧棲處深。',32,'全唐诗/poet.song.120000.json','["我如倦鳥欲栖林，喜見禪僧棲處深。", "家在梅花小溪上，一枝聊慰北歸心。"]'),
('05e4e910-6b57-4bd9-b97f-6edb965f2015','宿五峯院','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬法由來總是空，五峯名在本無峯。',32,'全唐诗/poet.song.120000.json','["萬法由來總是空，五峯名在本無峯。", "我來遥作廬山想，隠約夕陽開處逢。"]'),
('494ff1c9-5a9d-4445-967f-f315f0515e79','贈亮首坐','王十朋','宋','宋诗','song-poetry','','[]','雪頂龐眉八十餘，五峯深處結精廬。',32,'全唐诗/poet.song.120000.json','["雪頂龐眉八十餘，五峯深處結精廬。", "閲人老眼能青白，贈我嚴公一軸書。"]'),
('4c466f19-dcea-496f-b3fc-86840642a607','王成之太博寄詩病中未能和謾書二十字以酬','王十朋','宋','宋诗','song-poetry','','[]','老病欲納祿，君恩許奉祠。',24,'全唐诗/poet.song.120000.json','["老病欲納祿，君恩許奉祠。", "已爲三徑計，誤辱廣文詩。"]'),
('d1adcb3b-6d4f-4ee5-93ea-dd401673068b','司理叔文和過萬橋詩復用前韵','王十朋','宋','宋诗','song-poetry','','[]','少年一夕九起嗟，家貧親老無生涯。',128,'全唐诗/poet.song.120000.json','["少年一夕九起嗟，家貧親老無生涯。", "河東先生獨青眼，慨然許我修通家。", "三十年間同轉首，王謝依然作甥舅。", "時人咸笑孺子貧，杜老惟蒙丈人厚。", "罷官閩嶠初歸來，登堂又荷傾金罍。", "詩誦白圭感前事，情鍾我輩銜餘哀。", "定向清朝力求退，呼賓剩設嚴冬鱠。", "從公杖屨鹿巖前，明月清風趙歐會。"]'),
('13b173ae-8e02-4449-ba0f-da0dfde24510','挽令人  其一','王十朋','宋','宋诗','song-poetry','','[]','知汝莫如我，傷心不盡談。',48,'全唐诗/poet.song.120000.json','["知汝莫如我，傷心不盡談。", "忍貧猶好施，見得可曾貪。", "水陸同艱險，糟糠共苦甘。", "和鳴三十載，一夢斷閩南。"]'),
('dbc320a2-c79c-49b5-b9cc-08f10b84dad1','挽令人  其二','王十朋','宋','宋诗','song-poetry','','[]','之子有賢叔，鯫生誤受知。',48,'全唐诗/poet.song.120000.json','["之子有賢叔，鯫生誤受知。", "恩蒙夫子妻，事類白圭詩。", "黄卷悲吟夜，青燈照績時。", "竟孤偕隠願，徒切悼亡思。"]'),
('62b81228-ab4c-4f05-90f3-ab1344d6aaaa','挽令人  其三','王十朋','宋','宋诗','song-poetry','','[]','我欲誌諸墓，有言何敢私。',48,'全唐诗/poet.song.120000.json','["我欲誌諸墓，有言何敢私。", "如賓最相敬，無妬似知詩。", "孝合從姑葬，賢宜舉郡悲。", "明朝是重九，忍看菊花枝。"]'),
('aa6f43e6-2c75-42f7-835a-bc1fee31b516','梅溪草堂新闢缺少花木效少陵故事覓之以詩  其一','王十朋','宋','宋诗','song-poetry','','[]','小小園中十八香，主人游宦遂荒凉。',32,'全唐诗/poet.song.120000.json','["小小園中十八香，主人游宦遂荒凉。", "名園草木多奇品，分我餘根種草堂。"]'),
('d2eca0c8-2275-4661-861a-e29789bdfa8e','梅溪草堂新闢缺少花木效少陵故事覓之以詩  其二','王十朋','宋','宋诗','song-poetry','','[]','閑中那得買花錢，孤負桃紅李白天。',32,'全唐诗/poet.song.120000.json','["閑中那得買花錢，孤負桃紅李白天。", "拈出向來花疏目，招邀春色上詩篇。"]'),
('ac72a382-050e-4db5-88aa-74cde0ad76ea','夢齡弟生日','王十朋','宋','宋诗','song-poetry','','[]','周正猶餘八莢蓂，昴星下應一陽生。',64,'全唐诗/poet.song.120000.json','["周正猶餘八莢蓂，昴星下應一陽生。", "貌和冬嶺松俱秀，神與梅花溪共清。", "定享百齡如衛武，預開三徑學淵明。", "弟兄此去皆華髮，無惜更相薦壽觥。"]'),
('ed20cdc1-079d-482f-8f7e-2fff4a6f936f','可公禪老住泉之九日山二十年矣予臨罷官求去甚力復爲後政所留寄詩酬以一絕','王十朋','宋','宋诗','song-poetry','','[]','泉山好處稍延福，白髮禪僧去復回。',32,'全唐诗/poet.song.120000.json','["泉山好處稍延福，白髮禪僧去復回。", "且與晉松爲隠侶，莫同英石便飛來。"]'),
('d2c27467-42da-4ad3-84ab-74fa6a209db0','黄伯厚得蒲墨折而爲三以書來易戲成二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','不謂一子墨，忽成三客卿。',24,'全唐诗/poet.song.120000.json','["不謂一子墨，忽成三客卿。", "君家好兄弟，鼎立並馳名。"]'),
('e667136f-6a00-487b-b9c5-bea11e1fca29','黄伯厚得蒲墨折而爲三以書來易戲成二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','好去文房寶，堅剛宜自持。',24,'全唐诗/poet.song.120000.json','["好去文房寶，堅剛宜自持。", "吾家藏有盡，黄子翫無時。"]'),
('1d689f85-9b3d-400b-8834-c9b5770e6065','姚宰行可和詩索墨酬以元韵  其一','王十朋','宋','宋诗','song-poetry','','[]','武城民事暇，著述似虞卿。',24,'全唐诗/poet.song.120000.json','["武城民事暇，著述似虞卿。", "手握陳玄輩，磨成不朽名。"]'),
('f367b333-12b8-475f-8581-90b4cc9c15e1','姚宰行可和詩索墨酬以元韵  其二','王十朋','宋','宋诗','song-poetry','','[]','人生幾丸墨，老病厭操持。',24,'全唐诗/poet.song.120000.json','["人生幾丸墨，老病厭操持。", "好與賢明宰，研磨共救時。"]'),
('10f400a3-b450-4819-b3fa-abf47f56c586','松筆','王十朋','宋','宋诗','song-poetry','','[]','我有文房寶，莫如毛穎清。',48,'全唐诗/poet.song.120000.json','["我有文房寶，莫如毛穎清。", "來從丹桂窟，封以五夫城。", "輩行惟彤管，宗盟是墨卿。", "湘東謾三品，無此歲寒名。"]'),
('9a2124f1-18df-4503-942a-9b637a9a3238','題凈名院二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','凈名却見老維摩，道眼相看語不多。',32,'全唐诗/poet.song.120000.json','["凈名却見老維摩，道眼相看語不多。", "我待衣冠掛神武，杖藜來此老巖阿。"]'),
('c2cd533c-c6b7-40c2-8fd5-1b24dd3a68dd','題凈名院二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','谷中有月露蛾眉，水織珠簾更絕奇。',32,'全唐诗/poet.song.120000.json','["谷中有月露蛾眉，水織珠簾更絕奇。", "滿目峯巒觀未盡，有僧携紙覓題詩。"]'),
('79c588c4-7c4f-4a76-9ba9-faabe74d8c9a','千葉白桃','王十朋','宋','宋诗','song-poetry','','[]','洗盡夭夭色，泠然衆卉中。',24,'全唐诗/poet.song.120000.json','["洗盡夭夭色，泠然衆卉中。", "却將千葉雪，全勝幾枝紅。"]'),
('199491c8-3421-4977-bf6c-17023ea83ca3','菊','王十朋','宋','宋诗','song-poetry','','[]','佳節逢吹帽，黄金染菊叢。',24,'全唐诗/poet.song.120000.json','["佳節逢吹帽，黄金染菊叢。", "淵明何處飲，三徑冷香中。"]'),
('d6adb6c0-2376-4194-8652-bcf22321c399','芍藥','王十朋','宋','宋诗','song-poetry','','[]','千葉揚州種，春深霸衆芳。',24,'全唐诗/poet.song.120000.json','["千葉揚州種，春深霸衆芳。", "無言誚君子，窈窕有溫香。"]'),
('a1655b26-9d6e-495e-bd00-1fce634c4d59','蠟梅','王十朋','宋','宋诗','song-poetry','','[]','蝶采花成蠟，還將臘染花。',24,'全唐诗/poet.song.120000.json','["蝶采花成蠟，還將臘染花。", "一經坡谷眼，名字壓群葩。"]'),
('5b639155-6445-4c6e-960a-76cfd6f70dad','紅梅','王十朋','宋','宋诗','song-poetry','','[]','似桃非桃杏非杏，獨與江梅相早晚。',64,'全唐诗/poet.song.120000.json','["似桃非桃杏非杏，獨與江梅相早晚。", "天姿約略带春酲，便覺花容太柔婉。", "霞觴瀲艷玉妃醉，應誤劉郎來閬苑。", "會須參作比紅詩，莫學牆頭等閒見。"]'),
('f0fc4cf3-02f7-4bc4-8089-5f8b80358b51','梨花','王十朋','宋','宋诗','song-poetry','','[]','淡客逢寒食，村烟爛漫芳。',24,'全唐诗/poet.song.120000.json','["淡客逢寒食，村烟爛漫芳。", "謫仙天上去，白雪世間香。"]'),
('a3759afe-cb01-4954-a452-b61647720b92','酴醾','王十朋','宋','宋诗','song-poetry','','[]','風枝張羽蓋，露臉污何郎。',24,'全唐诗/poet.song.120000.json','["風枝張羽蓋，露臉污何郎。", "收拾歸醽醁，芳姿韵更香。"]'),
('b8ba69c1-c171-40e5-ae1d-3fdcc7423116','瑞香花','王十朋','宋','宋诗','song-poetry','','[]','真是花中瑞，本朝名始聞。',24,'全唐诗/poet.song.120000.json','["真是花中瑞，本朝名始聞。", "江南一夢後，天下遇清芬。"]'),
('8b864d48-758d-47af-aef1-4d88c2dfb219','丁香','王十朋','宋','宋诗','song-poetry','','[]','雨裏含愁態，枝頭綴玉英。',24,'全唐诗/poet.song.120000.json','["雨裏含愁態，枝頭綴玉英。", "爲花更雅目，變亂藥中名。"]'),
('ee68c3a6-abc0-43be-b387-10865e304edf','委羽山','王十朋','宋','宋诗','song-poetry','','[]','龜山軟翠日開屏，羽客逍遥此閉扃。',64,'全唐诗/poet.song.120000.json','["龜山軟翠日開屏，羽客逍遥此閉扃。", "早起留雲閒放鶴，夜來伴月靜看經。", "巖前方石有多好，竈裏丹砂且是靈。", "應有赤城鸞鳳過，一聲長嘯入青冥。"]'),
('5ae7829f-a94a-4fa9-8e3e-76e557da3594','玉環山','王十朋','宋','宋诗','song-poetry','','[]','清有濯纓水，白有漱齒石。',36,'全唐诗/poet.song.120000.json','["清有濯纓水，白有漱齒石。", "悠哉水石間，宦情聊自適。", "朝焉游其南，暮焉游其北。"]'),
('c002e3fa-4ac3-4750-a6e6-e9a43a7c6ab6','白鶴禪寺','王十朋','宋','宋诗','song-poetry','','[]','閒上簫臺頂，山深喜路通。',48,'全唐诗/poet.song.120000.json','["閒上簫臺頂，山深喜路通。", "人家烟色裏，古寺水聲中。", "金濺星猶在，丹成竈已空。", "神仙何處覓，千載想遺風。"]'),
('9e54966c-40e1-4890-aa2b-27e47cb4cddc','能仁禪寺','王十朋','宋','宋诗','song-poetry','','[]','不到能仁久，欣聞賜額還。',24,'全唐诗/poet.song.120000.json','["不到能仁久，欣聞賜額還。", "浮雲已過眼，依舊好青山。"]'),
('dd2d9698-ac48-4b53-afab-d4947d543a5a','石夫人','王十朋','宋','宋诗','song-poetry','','[]','亭亭獨立望天津，四畔無家石作鄰。',64,'全唐诗/poet.song.120000.json','["亭亭獨立望天津，四畔無家石作鄰。", "螺髻不梳千載曉，蛾眉空掃萬年春。", "雪爲鉛粉憑風傳，霞作胭脂仗日勻。", "莫道巖前無寶鑑，一輪明月照夫人。"]'),
('2651f388-b61e-4187-9460-f3509c57b5db','過鑑湖','王十朋','宋','宋诗','song-poetry','','[]','閣下平湖湖外山，陰晴氣象日千般。',32,'全唐诗/poet.song.120000.json','["閣下平湖湖外山，陰晴氣象日千般。", "主人便是神仙侶，莫作尋常太守看。"]'),
('a1c36d0e-35e6-4db2-b48d-05fa5438c11b','丞廳後圃雙梅一枝發和以表弟韵','王十朋','宋','宋诗','song-poetry','','[]','漫游蹤跡成浮家，一身四海驚年華。',144,'全唐诗/poet.song.120000.json','["漫游蹤跡成浮家，一身四海驚年華。", "不禁草木競時節，忽見霜幹排新花。", "曉雲生寒日未透，南枝半肥北枝瘦。", "就中一枝最先發，浪蕊浮花敢居右。", "山翁涉世如狼胡，功名日遠霜凌鬚。", "與花同是江南客，一笑爲解東陽臞。", "吟哦繞樹正百匝，未放零落空殘株。", "春風雜花儘明媚，此君風味懸知無。", "雨中看子尚不惡，可堪老葉繙蟲書。"]'),
('13048261-48bf-4e48-af74-8e1ee8515298','雲安下巖','王十朋','宋','宋诗','song-poetry','','[]','濤江翻雪卷湖灘，晚泊巖扉暫解顔。',64,'全唐诗/poet.song.120000.json','["濤江翻雪卷湖灘，晚泊巖扉暫解顔。", "夙有浄緣逢寺喜，老無生理伴僧閒。", "殘雲已斷猶飛雨，落日將沉却照山。", "半夜秋聲驚客夢，一簾珠貝冷珊珊。"]'),
('ccdf7a07-b1e9-486a-9d07-0fd0bcfc9adb','大龍湫','王十朋','宋','宋诗','song-poetry','','[]','靈源東接雁池遥，裂石崩崖下九霄。',64,'全唐诗/poet.song.120000.json','["靈源東接雁池遥，裂石崩崖下九霄。", "雲斷青天倚長劍，月明泉室挂生綃。", "江聲雨勢三秋急，雪片冰花五月饒。", "休勒移文北山去，他年來赴石梁招。"]'),
('3aabd5ee-b583-487d-8f72-afbae03150dd','卓筆峯','王十朋','宋','宋诗','song-poetry','','[]','束縛真憑造化功，巍巍直氣貫鴻濛。',64,'全唐诗/poet.song.120000.json','["束縛真憑造化功，巍巍直氣貫鴻濛。", "雨將苔色生彤管，山吐虹光遶兔鋒。", "未數如椽曾入夢，誤疑怪事尚書空。", "士人毛穎多榮辱，恩寵纔衰便不同。"]'),
('5552a644-4268-430f-a295-9456e715a6ad','兄弟鄰里日講率會因書一絕且戒其早納租稅也','王十朋','宋','宋诗','song-poetry','','[]','屏跡山林頗自安，里閭率會有餘歡。',32,'全唐诗/poet.song.120000.json','["屏跡山林頗自安，里閭率會有餘歡。", "但須及早輸租稅，不用低顔見長官。"]'),
('c527d8d6-66d0-4bad-94aa-96ed17914f67','句  其一','王十朋','宋','宋诗','song-poetry','','[]','月澹碧雲籠野水，稜稜瘦聳吟肩起。',32,'全唐诗/poet.song.120000.json','["月澹碧雲籠野水，稜稜瘦聳吟肩起。", "一天寒氣霞衣裳，人在石橋春影裏。"]'),
('4682a095-a3e2-42d9-a44c-2f5091d6669e','句  其二','王十朋','宋','宋诗','song-poetry','','[]','杜陵應恨未曾識，空向成都結草堂。',16,'全唐诗/poet.song.120000.json','["杜陵應恨未曾識，空向成都結草堂。"]'),
('392a81a3-9932-41f3-934b-d75d7c6e9862','句  其三','王十朋','宋','宋诗','song-poetry','','[]','太虛懷抱物華秋。',8,'全唐诗/poet.song.120000.json','["太虛懷抱物華秋。"]'),
('7121275b-9ad9-425b-a368-3a490b21341c','句','王百朋','宋','宋诗','song-poetry','','[]','詩書滿腸腹，應笑带經人。',12,'全唐诗/poet.song.120000.json','["詩書滿腸腹，應笑带經人。"]'),
('3d911d44-d459-4199-b395-6ffffb52fccf','懷王龜齡','姜大呂','宋','宋诗','song-poetry','','[]','左原消息杳無聞，令我愁懷似亂雲。',64,'全唐诗/poet.song.120000.json','["左原消息杳無聞，令我愁懷似亂雲。", "多病廢詩兼廢酒，青春孤我亦孤君。", "要同學問文章樂，無奈東西南北分。", "况是一簷殘雨後，落花飛絮兩紛紛。"]'),
('595fe673-a428-433f-825b-870878ffbc5d','句','萬椿','宋','宋诗','song-poetry','','[]','剩栽桑柘教妻蠶。',8,'全唐诗/poet.song.120000.json','["剩栽桑柘教妻蠶。"]'),
('8075a351-0e52-4ab2-a89b-e2cf2c67398c','句','李元翁','宋','宋诗','song-poetry','','[]','玉華野人多病惱，獨守寒爐煨芋魁。',16,'全唐诗/poet.song.120000.json','["玉華野人多病惱，獨守寒爐煨芋魁。"]'),
('da4ee343-f67e-47fc-a2b0-60e4eda86fe6','句','越州幕僚','宋','宋诗','song-poetry','','[]','蓮幕風清不受梅。',8,'全唐诗/poet.song.120000.json','["蓮幕風清不受梅。"]'),
('b0fbf556-be69-4fc9-88bb-fe8ff0db2ff5','句','陳商霖','宋','宋诗','song-poetry','','[]','生死交情誰念舊，炎凉世態競迎新。',16,'全唐诗/poet.song.120000.json','["生死交情誰念舊，炎凉世態競迎新。"]'),
('55ac32e6-f411-44f3-846e-78bc9d5eb951','示張直溫','林之奇','宋','宋诗','song-poetry','','[]','築山必使高，鑿井必使深。',84,'全唐诗/poet.song.120000.json','["築山必使高，鑿井必使深。", "百正戒淺近，盛德羞浮沉。", "焉有尺寸枝，能棲垂天禽。", "焉有升斗泉，能容橫江鱘。", "借茲論物理，足以開君心。", "嗌在容不足，弱在力不任。", "大道如路然，固無古與今。"]'),
('869fd7d5-be9c-4a37-85eb-9ca8e966131a','朝乘','林之奇','宋','宋诗','song-poetry','','[]','朝乘日車出，暮載星影還。',48,'全唐诗/poet.song.120000.json','["朝乘日車出，暮載星影還。", "顛冥朝暮中，出入咫尺間。", "已覺素志非，更知人理艱。", "小利專欲速，大德不踰閑。"]'),
('d4513fd9-54df-4161-926c-33252808e28a','田漏','林之奇','宋','宋诗','song-poetry','','[]','古星昏曉中，寒暑已不疑。',48,'全唐诗/poet.song.120000.json','["古星昏曉中，寒暑已不疑。", "田家更置漏，寸晷亦欲知。", "汗與水俱滴，身隨陰屢移。", "誰當哀此勞，往往奪其時。"]'),
('c3122a93-2537-477b-bc2d-6968c19ccfd8','雜詠','林之奇','宋','宋诗','song-poetry','','[]','懷王自墮馬，賈傅至死悲。',48,'全唐诗/poet.song.120000.json','["懷王自墮馬，賈傅至死悲。", "古人事一職，豈敢苟然爲。", "哭死非爲生，吾心良不欺。", "滔滔聲利間，絳灌亦何知。"]'),
('ea2613d9-a31e-4d54-ae67-5634fcdab8fd','看白雲愛而成詩','林之奇','宋','宋诗','song-poetry','','[]','秋風吹白雲，觸處自何谷。',84,'全唐诗/poet.song.120000.json','["秋風吹白雲，觸處自何谷。", "初猶半洞門，欻出遍巖腹。", "零落依水湄，片段掛枯木。", "餘影透微白，滅跡混空綠。", "煙蘿自翳島，溆荇徒縈曲。", "安知蒼梧野，下覆猿鳥哭。", "誰能久徘徊，返顧視黄鵠。"]'),
('cbeff1de-c96e-4679-86d5-1ca81bed11b8','舉舉媚學子','林之奇','宋','宋诗','song-poetry','','[]','舉舉媚學子，居曰不吾知。',48,'全唐诗/poet.song.120000.json','["舉舉媚學子，居曰不吾知。", "知而有不能，無乃失於欺。", "不知未爲患，不欺浩難期。", "咄哉天下懷，何以天下爲。"]'),
('85dad60a-f174-4ecf-ab17-96d9c355753f','呼雞','林之奇','宋','宋诗','song-poetry','','[]','雞呼雞來前，犬嗾犬至止。',48,'全唐诗/poet.song.120000.json','["雞呼雞來前，犬嗾犬至止。", "夫豈必可召，役以食乃爾。", "今吾曷爲悲，人而雞犬爲。", "自計無自存，西山謝夷齊。"]'),
('be9882c1-678d-472d-9f5e-3c3f38a48ed3','秋懷','林之奇','宋','宋诗','song-poetry','','[]','槭槭庭樹葉，朝零非昔稠。',144,'全唐诗/poet.song.120000.json','["槭槭庭樹葉，朝零非昔稠。", "呦呦草蟲鳴，暮急曉未休。", "爾蟲無不平，豈亦有哀憂。", "胡爲勞呻吟，與士感傷投。", "壯士亦何者，哀哦與蟲酬。", "所抱不列陳，調苦難謠謳。", "極目有遠見，直懷羞曲求。", "蒿藜襲久安，功名忘前收。", "日月忽未幾，天地今復秋。", "少壯負所懷，老大安能謀。", "生無及人功，死骨埋泉羞。", "胡爲不奮飛，徒與寒餓讎。"]'),
('c94d5fb6-b443-4032-a352-2685693c5727','四事','林之奇','宋','宋诗','song-poetry','','[]','會有四不赴，時有四不出。',48,'全唐诗/poet.song.120000.json','["會有四不赴，時有四不出。", "無貴亦無賤，無固亦無必。", "里閈閒過從，身安心自逸。", "如此三十年，幸逢太平日。"]'),
('4f15236f-d35a-49b3-b18f-9a436565004e','高竹','林之奇','宋','宋诗','song-poetry','','[]','高竹碧相倚，自能發餘清。',48,'全唐诗/poet.song.120000.json','["高竹碧相倚，自能發餘清。", "時時微風來，萬葉同一聲。", "道污得夷理，物虛含遠情。", "階前閒步人，意思何清平。"]'),
('a24d8b39-ce77-4bbb-b7b3-b4804479ae80','村居','林之奇','宋','宋诗','song-poetry','','[]','日影滿松窗，雲開雨初止。',48,'全唐诗/poet.song.120000.json','["日影滿松窗，雲開雨初止。", "晴林梨栗熟，曉巷兒童喜。", "牛羊深澗下，鳧雁寒塘裏。", "田父酒新成，瓶甕饋鄰里。"]'),
('6420903a-7fb4-40d1-9a30-abb204dc1e09','新晴山月','林之奇','宋','宋诗','song-poetry','','[]','高松漏疎月，落影如畫地。',48,'全唐诗/poet.song.120000.json','["高松漏疎月，落影如畫地。", "徘徊愛其平，夜久不能寐。", "怯風池荷卷，病雨山果墜。", "誰伴予苦吟，滿林啼絡緯。"]'),
('28dffc20-4912-4f1c-9aa6-fd0dab76ed1b','屬疾梧軒','林之奇','宋','宋诗','song-poetry','','[]','高梧覆新葉，滿院發華滋。',48,'全唐诗/poet.song.120000.json','["高梧覆新葉，滿院發華滋。", "白日一何永，清陰閒自移。", "暖蟲垂到地，晴鳥語多時。", "病肘倚枯几，泊然忘所思。"]'),
('3d0cfff5-ddba-41b6-ac47-3b5d99ad745f','謝公定和二范秋懷','林之奇','宋','宋诗','song-poetry','','[]','西風一葉脫，迹已不可掃。',48,'全唐诗/poet.song.120000.json','["西風一葉脫，迹已不可掃。", "巷有白馬生，朝回焚諫草。", "誰云事君難，是亦父子間。", "所要功補衮，不言能犯顔。"]'),
('d13f3cf8-d1bc-40b1-8dd0-0c465d4ec156','宿舊彭澤懷陶令','林之奇','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','潜魚願深渺，淵明無由逃。',132,'全唐诗/poet.song.120000.json','["潜魚願深渺，淵明無由逃。", "彭澤當此時，沉冥一世豪。", "司馬寒如灰，禮樂卯金刀。", "□□□□□，□□□元亮。", "凄其望諸葛，骯髒猶漢相。", "時無益州牧，指撝用諸將。", "平生本朝心，歲月閱江浪。", "空餘詩語工，落筆九天上。", "向來非無人，此友獨可尚。", "屬余剛制酒，無用酌杯盎。", "欲招千載魂，斯文或宜當。"]'),
('391b92f0-2f34-47ff-a122-a7529002e07f','題宛陵張待舉曲肱亭','林之奇','宋','宋诗','song-poetry','','[]','仲蔚蓬蒿宅，宜城詩句中。',60,'全唐诗/poet.song.120000.json','["仲蔚蓬蒿宅，宜城詩句中。", "人賢忘巷陋，境勝失途窮。", "寒葅書萬卷，零亂剛直胸。", "偃蹇勳業外，嘯歌山水重。", "晨雞催不起，擁被聽松風。"]'),
('0aef6124-b2c1-4517-b7d5-1536e7dcd75c','春日雜書','林之奇','宋','宋诗','song-poetry','','[]','昨日爲雨備，今晨天乃風。',84,'全唐诗/poet.song.120000.json','["昨日爲雨備，今晨天乃風。", "障風謹自保，通夕雪迷空。", "備一常失計，盡備力不供。", "因之置不爲，拱手受禍兇。", "當爲不可讓，任彼萬變攻。", "筑室如金石，何勞計春冬。", "此道簡且安，古來家國同。"]'),
('c0d91c2b-8410-40cb-8abd-0994a4afa203','賀雨拜表','林之奇','宋','宋诗','song-poetry','','[]','羣雲雨事畢，振旅不復陣。',72,'全唐诗/poet.song.120000.json','["羣雲雨事畢，振旅不復陣。", "掃天無一塵，千里還綠潤。", "晨朝大明賀，沙路萬蹄印。", "朝元泛翠瓦，佳氣去人近。", "頗聞避斧扆，侑膳徹龍筍。", "願君愛物心，從此至堯舜。"]'),
('4aba4cad-c5b8-4930-905f-7ff10c781e4e','雨後出城馬上作','林之奇','宋','宋诗','song-poetry','','[]','既雨天氣佳，微雲淡如掃。',72,'全唐诗/poet.song.120000.json','["既雨天氣佳，微雲淡如掃。", "欲尋煙際鐘，騎馬河邊草。", "紫椹飽黄鸝，人家夏蠶老。", "田婦踏繅車，隔籬語音好。", "嗟我一何愚，讀書浪枯槁。", "不及此中人，終年客長道。"]'),
('e956f683-7089-4b54-a06b-024f33d5bd31','江月圖','林之奇','宋','宋诗','song-poetry','','[]','冥冥一月輕，不知水與天。',84,'全唐诗/poet.song.120000.json','["冥冥一月輕，不知水與天。", "獨於顥氣中，仰見素璧圓。", "超然狂道士，起視清夜闌。", "自拈白玉笛，吹此江月寒。", "想當萬籟息，逸響流空煙。", "我從江海來，形留意先還。", "何當買漁篷，追此水墨仙。"]'),
('187c1512-393b-4e4b-9074-fbffad8c6199','送葛都官南歸','林之奇','宋','宋诗','song-poetry','','[]','不羨新爲赤縣尹，惟羨暫向江南歸。',64,'全唐诗/poet.song.120000.json','["不羨新爲赤縣尹，惟羨暫向江南歸。", "江南羃羃梅雨時，風帆差差并鳥飛。", "罾竿夾岸長若桅，水籠畜魚鮮且肥。", "家在千山古溪上，先應喜鵲噪門扉。"]'),
('be27a5f2-392c-4f61-aea3-9d799347d104','滄洲亭懷古','林之奇','宋','宋诗','song-poetry','','[]','瀟水悠悠天際來，夾江古木抱山回。',64,'全唐诗/poet.song.120000.json','["瀟水悠悠天際來，夾江古木抱山回。", "柵中人物不滿把，日晏市散多蒼苔。", "九疑巉天古雲埋，遥想帝子龍車迴。", "心衰目極何可望，九歌寂寂令人哀。"]'),
('fe0a1cfc-4782-4c2f-9baf-5ca9bb51fb7c','縱步湘西','林之奇','宋','宋诗','song-poetry','','[]','今朝不易得天晴，閒過江西取意行。',64,'全唐诗/poet.song.120000.json','["今朝不易得天晴，閒過江西取意行。", "忽然林外見山色，又向橋邊聞水聲。", "綠竹長松間桃李，天然翠幙圍羅綺。", "日暮歸舟醉不知，晚風吹過湘江水。"]'),
('5b0dd9ad-2b14-43b2-aab5-85d528f8f169','謁客','林之奇','宋','宋诗','song-poetry','','[]','入門投謁吏翩翩，我非欲見禮則然。',64,'全唐诗/poet.song.120000.json','["入門投謁吏翩翩，我非欲見禮則然。", "異哉賓主兩無語，客起疾如走避燃。", "我已不恭愧昔賢，忍使泥塗朝衣冠。", "人生暫聚鴻集川，春風吹飛何後先。"]'),
('cdb09933-6e27-4fb8-9476-f8b929248871','墨染絲','林之奇','宋','宋诗','song-poetry','','[]','繰絲自喜如霜白，輸入官家吏嫌黑。',64,'全唐诗/poet.song.120000.json','["繰絲自喜如霜白，輸入官家吏嫌黑。", "手持退印競傳呼，倏見長條染深墨。", "墨絲歸織家人衣，別買輸官吏嗔遲。", "寄言敵國與三軍，汝得豐衣民苦辛。"]'),
('5cdf5cfe-dc2e-44c2-89ed-73eabc52e95c','豫章別李元中宣德','林之奇','宋','宋诗','song-poetry','','[]','舊聞諸李隱龍眠，伯時已老元中少。',144,'全唐诗/poet.song.120000.json','["舊聞諸李隱龍眠，伯時已老元中少。", "一行作吏各天涯，故人落落疎星曉。", "西山影裏識君面，碧照草江眸子瞭。", "向來問道渺多岐，只今領略歸玄妙。", "老鳳垂頭噤不語，古木查牙噪春鳥。", "身在幕府心江湖，左胥右律但坐嘯。", "第愁一葉釣漁舟，不容七尺堂堂表。", "我今歸卧翠谷雲，君應紫禁鶯花繞。", "相思有夢到茅齋，細雨青燈坐林杪。"]'),
('813e790e-8d6e-43f7-b099-55bfbc91fa8e','聞徐師川自京師還豫章','林之奇','宋','宋诗','song-poetry','','[]','九衢塵裏無停舟，君居陋巷不出遊。',64,'全唐诗/poet.song.120000.json','["九衢塵裏無停舟，君居陋巷不出遊。", "滿城惡少弋鳧雁，對面故人風馬牛。", "別後天寒燈火夜，歸來眠冷江湖秋。", "馮驩老大食不飽，起視八荒徒蒯緱。"]'),
('c84c4829-c40d-4130-8c1b-9e63044e53bb','早春偶題','林之奇','宋','宋诗','song-poetry','','[]','寒風淅瀝鳴枯葦，小鴨睡殘猶未起。',64,'全唐诗/poet.song.120000.json','["寒風淅瀝鳴枯葦，小鴨睡殘猶未起。", "更教細雨結輕寒，坐聽蕭蕭打窗紙。", "石盆養蒲已抽翠，雕斛栽花先生紫。", "擁爐閉閤賦幽香，未怕春冰生硯水。"]'),
('c0ca4221-3a80-415f-b49a-1f10cef9777b','夢訪友生','林之奇','宋','宋诗','song-poetry','','[]','少年結客長安城，妄喜縱酒一章程。',96,'全唐诗/poet.song.120000.json','["少年結客長安城，妄喜縱酒一章程。", "支離老去一茅屋，枕書卧聞長短更。", "友生相望止百里，寒夜寥間無微聲。", "夢中乘興輒見戴，剡溪聊爾扁舟行。", "覺來蘧蘧一榻上，不用僮僕爭籬迎。", "吹燈弄筆欲書寄，窗前白月方亭亭。"]'),
('ca6fc961-b44f-4efd-a1bd-fbfc5ad7c936','承天潜師畫贊','林之奇','宋','宋诗','song-poetry','','[]','金剛圈裏翻身過，栗棘蓬萊滿口吞。',32,'全唐诗/poet.song.120000.json','["金剛圈裏翻身過，栗棘蓬萊滿口吞。", "領得楊歧端的句，却嫌蒸餅大餫飩。"]'),
('7f1795f7-7311-4acb-b5df-38d7d9a432bf','西禪此庵凈老真贊','林之奇','宋','宋诗','song-poetry','','[]','眼碧眉厖，足趺肩嚲。',52,'全唐诗/poet.song.120000.json','["眼碧眉厖，足趺肩嚲。", "此庵樣子，元來恁麽。", "當年唱箇無生曲，火冷雲深從寡和。", "如今口作掛壁閑，獨說宗乘鬧浩浩。"]'),
('72d3fd3e-70dc-4f29-97a8-064f298d4495','延福可老真贊','林之奇','宋','宋诗','song-poetry','','[]','渾沌鑿開無限事，逍遥游後更何疑。',32,'全唐诗/poet.song.120000.json','["渾沌鑿開無限事，逍遥游後更何疑。", "饒伊齊得鵬并鷃，不似當年作蝶時。"]'),
('a08dafe2-d686-4299-b5f3-1ea2e6fccb0a','觀音畫贊','林之奇','宋','宋诗','song-poetry','','[]','稽首補陀聞思修，千手千眼普供應。',176,'全唐诗/poet.song.120000.json','["稽首補陀聞思修，千手千眼普供應。", "世人兩手及兩眼，眼見手捉各隨心。", "多一手眼無用處，即與駢拇枝指等。", "菩薩照用一時行，應以千心爲主宰。", "相彼方寸湛然地，不容二念那復千。", "我謂菩薩如水月，一水一月同照曜。", "方員大小雖不同，舉手見月等無二。", "我今續此妙色相，以爲正念皈依處。", "於一身心起多想，而作千手千眼見。", "普願大員鏡智中，知我此念無間斷。", "所求皆應如谷聲，請無不從亦如是。"]'),
('97b07f1e-b58f-42fa-8933-80adbab99ae6','泗州畫贊','林之奇','宋','宋诗','song-poetry','','[]','稽首泗州普照王，曩以寶塔接群品。',176,'全唐诗/poet.song.120000.json','["稽首泗州普照王，曩以寶塔接群品。", "塔今敗壞成微塵，隨意分身無不在。", "我觀世間有爲法，無常遷變同一空。", "假饒建塔如恒沙，未有不歸幻滅者。", "豈惟淮塔有興廢，阿育王造亦非堅。", "菩薩應感常現世，不隨寶塔俱存亡。", "耕雨穫晴長淮風，普爲眾生作饒益。", "我今繪此應感象，常以正念爲皈依。", "於此員光一尋中，而興七級浮屠想。", "正念皈依無間斷，普願菩薩常感通。", "洪鍾小大隨叩鳴，所求所請皆如意。"]'),
('f6e4e986-1962-44d4-9f37-b5bb314630f4','題雪峰如藏主水月圖','林之奇','宋','宋诗','song-poetry','','[]','千江有月一一同，一月普現千江影。',208,'全唐诗/poet.song.120000.json','["千江有月一一同，一月普現千江影。", "謂一爲月影非實，影既非實月何有。", "是一即千千即一，水月究竟無實相。", "隨見有月月在水，亦無究竟非實者。", "譬如觀音妙色身，對物而見千臂眼。", "於是千臂千眼中，何者爲正何獨非。", "菩薩一體作一用，千體同是無剩法。", "此水此月亦復然，照用齊行一無欠。", "俯不見月仰亦無，千月闕一固不可。", "上人此庵憩瓶錫，終日宴坐常湛然。", "散一爲千彌六虛，攝千歸一不盈寸。", "我知上人環堵中，能廣能狹能方圓。", "空諸所有何必然，作是見者名邪見。"]'),
('e205018b-44bb-4c57-83db-e0d2d16d4d52','和洪教菊','林之奇','宋','宋诗','song-poetry','','[]','陶令遺世情，尚餘愛菊念。',192,'全唐诗/poet.song.120000.json','["陶令遺世情，尚餘愛菊念。", "菊亦有可愛，愛之苦不厭。", "我觀傲霜枝，真金赴烈焰。", "道韻輕園綺，孤標敵鍼奄。", "配以靖節名，萬古不爲忝。", "况茲中央色，獨許此君占。", "凝然端正姿，不受紅紫艷。", "草木吾味同，世情那得染。", "璀璨歸來辭，斯言了無玷。", "偶亦愛此花，秋來朝暮饜。", "富貴兩浮雲，天地一旅店。", "是中論饑飽，本自無贏欠。", "便擬學淵明，奈此才不贍。", "菊資三徑荒，酒須十分灧。", "待讀悠然句，乃無雍徹僭。", "但論廣文詩，瘧愈不須砭。"]'),
('6d91929a-8f4b-4601-83ef-89ae26b281cc','和王龜齡不欺堂  其一','林之奇','宋','宋诗','song-poetry','','[]','心外何曾別有天，吾心和處即昭然。',32,'全唐诗/poet.song.120000.json','["心外何曾別有天，吾心和處即昭然。", "昭然莫向穹蒼覓，帝所清都在目前。"]'),
('274c4367-3c4d-473e-9aeb-0966511e36e7','和王龜齡不欺堂  其二','林之奇','宋','宋诗','song-poetry','','[]','地上空虛總是天，此中那復計中邊。',32,'全唐诗/poet.song.120000.json','["地上空虛總是天，此中那復計中邊。", "好將天體爲心體，體得純全自浩然。"]'),
('6fee5169-63e9-4ce6-a6a3-867c2476f852','燈  其一','林之奇','宋','宋诗','song-poetry','','[]','自從失道人多岐，擿植冥行信所之。',32,'全唐诗/poet.song.120000.json','["自從失道人多岐，擿植冥行信所之。", "昨夜忽然尋得路，孤燈一點是吾師。"]'),
('fde56c61-ca9c-4a78-9ac3-929924555c30','燈  其二','林之奇','宋','宋诗','song-poetry','','[]','月明方始覺星稀，燭照還知燈力微。',32,'全唐诗/poet.song.120000.json','["月明方始覺星稀，燭照還知燈力微。", "若使世間無聖哲，草根螢爝總光輝。"]'),
('c1ca1f24-cddf-4bfe-8cdf-5b46da6c476e','癸未冬至','林之奇','宋','宋诗','song-poetry','','[]','塵勞終日謾區區，竟是乾坤一腐儒。',64,'全唐诗/poet.song.120000.json','["塵勞終日謾區區，竟是乾坤一腐儒。", "半世飽知榮與辱，新冬頓覺我爲吾。", "關防向後存心誤，檢點從前制行粗。", "理欲從今罷研究，無工夫處是工夫。"]'),
('d015eff7-a03c-4d68-bae9-a4fee50adb21','句','林之奇','宋','宋诗','song-poetry','','[]','耿耿一寸心，不能去庭闈。',12,'全唐诗/poet.song.120000.json','["耿耿一寸心，不能去庭闈。"]'),
('615a4ac3-56f4-44f6-9822-d230c5606e75','過杜工部祠','鄒定','宋','宋诗','song-poetry','','[]','疇昔哦詩憶耒陽，茲因捧檄過祠堂。',64,'全唐诗/poet.song.120000.json','["疇昔哦詩憶耒陽，茲因捧檄過祠堂。", "一生忠義孤吟裏，千載凄凉古道旁。", "自是風霜侵病骨，非干牛酒涴詩腸。", "明朝解纜秋江上，問訊先生一瓣香。"]'),
('3dc53a9e-3570-4f17-be82-da87a1cfdf84','滴翠樓  其一','蕭之敏','宋','宋诗','song-poetry','','[]','一溪流水漾殘春，上有高樓碧瓦新。',32,'全唐诗/poet.song.120000.json','["一溪流水漾殘春，上有高樓碧瓦新。", "溪路晝陰元不雨，却愁空翠染衣巾。"]'),
('52339442-5cfc-4cfd-9e43-64ea21c223f3','滴翠樓  其二','蕭之敏','宋','宋诗','song-poetry','','[]','我愛東坡句法遒，治平雙澗昔經游。',32,'全唐诗/poet.song.120000.json','["我愛東坡句法遒，治平雙澗昔經游。", "曾吟滴翠衣裘濕，請借佳名榜畫樓。"]'),
('8b895dae-4f37-462f-83d2-16760e4675d2','天池聖燈  其一','蕭之敏','宋','宋诗','song-poetry','','[]','俯仰區區類桔槔，訪幽尋勝自忘勞。',64,'全唐诗/poet.song.120000.json','["俯仰區區類桔槔，訪幽尋勝自忘勞。", "雲峰一握天還近，雪徑千盤地最高。", "支杖緩行真野逸，擁爐端坐或禪逃。", "幽人未厭看遊客，爛煮園蔬飯老饕。"]'),
('9822a40a-2f3b-4ac3-955d-0e7f5833da2b','天池聖燈  其二','蕭之敏','宋','宋诗','song-poetry','','[]','細如珠顆大如盃，照夜浮空去復來。',32,'全唐诗/poet.song.120000.json','["細如珠顆大如盃，照夜浮空去復來。", "神物戲人安可料，密移星斗下巖隈。"]'),
('1380750c-59b1-48bf-a002-e739436d0f66','挽于湖','施士衡','宋','宋诗','song-poetry','','[]','湧泉詞筆坐中驚，天付斯文以道鳴。',64,'全唐诗/poet.song.120000.json','["湧泉詞筆坐中驚，天付斯文以道鳴。", "獨步蟾宮丹桂選，濡毫綸閣紫微清。", "絕絃慟哭人琴喪，埋玉凄凉柱石傾。", "一見那知成永別，重來天路問騎鯨。"]'),
('e5e12f22-2a30-4eba-9bbe-f4eb7567c18c','復挽','施士衡','宋','宋诗','song-poetry','','[]','十年帥鉞倦馳驅，適意方謀一壑居。',64,'全唐诗/poet.song.120000.json','["十年帥鉞倦馳驅，適意方謀一壑居。", "賈誼有才終太傅，薛收無壽處中書。", "傷心風月江心古，過眼光陰夢幻虛。", "紅紫飄零春色盡，後凋松柏獨蕭疎。"]'),
('a708bbb0-f1cc-42f7-a65d-366a4c00e23d','頂山栗','王伯廣','宋','宋诗','song-poetry','','[]','黄籬抱中實，紫苞發外彩。',144,'全唐诗/poet.song.120000.json','["黄籬抱中實，紫苞發外彩。", "寄蹤蜂窠垂，藏頭蝟皮隘。", "詎堪鼯鼠竊，更復猿猱采。", "心憐使民畏，時須徇兒愛。", "荆山破金璞，驪珠掩微纇。", "縝密文自保，滋味身乃碎。", "筠籠貢厥珍，不在柤梨外。", "羅籩加其儀，顧與菱芡對。", "易飽屏膏肉，餘功益肝肺。", "懸風當令堅，致濕忍使敗。", "晉地棗非偶，宣城蜜佳配。", "誰知麝香囊，可居天下最。"]'),
('2f257662-32fa-4cd1-aa32-41f29f6fceab','寶嚴寺','王伯廣','宋','宋诗','song-poetry','','[]','平湖鏡浄中，背貼青峰巒。',120,'全唐诗/poet.song.120000.json','["平湖鏡浄中，背貼青峰巒。", "去郭二十里，金碧輝波瀾。", "是曰寶華境，萬象鬰以盤。", "壯哉窣堵坡，一瞰天地寬。", "誰懷墮塵鞅，幾欲招飛鸞。", "我生眇何能，山水情所安。", "扁舟幾來斯，不爲開愁端。", "意到自行樂，樽酒那追歡。", "何時結青蓮，超適心外觀。", "塵迹身兩忘，浩然天地間。"]'),
('2b76fcc8-d6b0-4947-bed2-44433c5e5734','謁顯應觀崔真君','魏元若','宋','宋诗','song-poetry','','[]','磁州惠政澤流長，翊運於今有耿光。',64,'全唐诗/poet.song.120000.json','["磁州惠政澤流長，翊運於今有耿光。", "金甲護遷馳白馬，絳衣誕聖擁紅羊。", "久勞宵旰籌中土，爲祝英靈監下方。", "唾手幽燕應默相，彎弧萬里射天狼。"]'),
('2684497a-234c-4845-bebe-16621344e560','唐孝子張常洧義臺','苗昌言','宋','宋诗','song-poetry','','[]','義臺屹立尚千秋，褒詔曾宣李鄴侯。',64,'全唐诗/poet.song.120000.json','["義臺屹立尚千秋，褒詔曾宣李鄴侯。", "古碣不教蒼蘚蝕，高原惟見夕陽流。", "耕夫鋤自將芝護，野客衣還伴鶴游。", "一樣荒墳偏起敬，孝思耿耿至今留。"]'),
('4ed5ebc8-953b-43e0-b192-2042f77744e2','瑞雲潭','薛珩','宋','宋诗','song-poetry','','[]','一派寒潭闞碧虛，閒雲自有卷還舒。',32,'全唐诗/poet.song.120000.json','["一派寒潭闞碧虛，閒雲自有卷還舒。", "夜來數仞祥光起，早去溪頭聽詔書。"]'),
('20b9797c-f60f-47d8-b2bb-e845ca7f08aa','燕堂詩','蔡茲','宋','宋诗','song-poetry','','[]','世情日淺道情深，悔不林泉早脫簪。',64,'全唐诗/poet.song.120000.json','["世情日淺道情深，悔不林泉早脫簪。", "一世簡編貽後葉，百年香火奉先心。", "詩緣好句須親錄，酒到濃時輒倩斟。", "於此更無關意事，時携諸幼步花陰。"]'),
('f9147519-66e9-4ba2-b31b-a223098485a0','高宗皇帝挽詞  其一','林栗','宋','宋诗','song-poetry','','[]','倉猝扶宗社，艱危啟聖神。',48,'全唐诗/poet.song.120000.json','["倉猝扶宗社，艱危啟聖神。", "英雄歸駕御，狂狡願和親。", "泛掃妖氛凈，恢張治化新。", "倦勤三紀外，頭白盡遺民。"]'),
('3ad52abb-138f-45cb-8d7d-7ddff0ef7d6a','高宗皇帝挽詞  其二','林栗','宋','宋诗','song-poetry','','[]','周漢中興勝，唐虞內禪高。',48,'全唐诗/poet.song.120000.json','["周漢中興勝，唐虞內禪高。", "髀消從馬腹，屣脫等鴻毛。", "弓劍悲長在，羹牆慕轉勞。", "龍髯攀莫及，四海共呼咷。"]'),
('9cb53cc2-624b-4721-862c-6055bd0202e8','高宗皇帝挽詞  其三','林栗','宋','宋诗','song-poetry','','[]','兼愛無南北，全能冠古今。',48,'全唐诗/poet.song.120000.json','["兼愛無南北，全能冠古今。", "典墳供夜覽，烽火自宵沉。", "睿藻成章煥，宸鈞寓意深。", "萬年垂琬琰，誰識至仁心。"]'),
('14f9d998-9b06-46c8-8f47-a72dfeb325a8','石井詩一首','林栗','宋','宋诗','song-poetry','','[]','石井靈蹤信不凡，一泓巖下碧深潭。',64,'全唐诗/poet.song.120000.json','["石井靈蹤信不凡，一泓巖下碧深潭。", "誰磨皎潔青銅鏡，更琢玲瓏碧玉龕。", "濯去衣巾無限垢，潄來齒頰有餘甘。", "懸知坎谷非佳井，寄語詩人莫恨談。"]'),
('0d29527c-5cb7-4ec2-b1eb-e548c544d8fb','句  其一','林栗','宋','宋诗','song-poetry','','[]','定王遺筑覽長沙，城郭山川四面佳。',16,'全唐诗/poet.song.120000.json','["定王遺筑覽長沙，城郭山川四面佳。"]'),
('b94c8d1b-1543-4396-9877-b9b02f408335','句  其二','林栗','宋','宋诗','song-poetry','','[]','千年依舊長安土，萬里思歸帝子家。',16,'全唐诗/poet.song.120000.json','["千年依舊長安土，萬里思歸帝子家。"]'),
('2cfb1dfe-4f3f-4636-a157-4275e6f22c92','挽王信伯先生  其一','楊邦弼','宋','宋诗','song-poetry','','[]','伊洛親聞道，淵微賴發揚。',48,'全唐诗/poet.song.120000.json','["伊洛親聞道，淵微賴發揚。", "東吳賢望重，西觀舊書藏。", "吾黨將安放，斯文豈遂亡。", "堂堂寧復見，門士慟新岡。"]'),
('cc38ba37-157e-4f89-a486-8a641382e904','挽王信伯先生  其二','楊邦弼','宋','宋诗','song-poetry','','[]','梁木俄摧壞，嗟吁喪大賢。',48,'全唐诗/poet.song.120000.json','["梁木俄摧壞，嗟吁喪大賢。", "典刑看肖子，道學付誰傳。", "一代風流盡，千年物論先。", "師言猶在耳，身敢墜周旋。"]'),
('429afb36-2c18-4f88-b106-ce7d81dc754f','五言戲贈呂神童行','嚴煥','宋','宋诗','song-poetry','','[]','自我諏人物，天涯實眇然。',48,'全唐诗/poet.song.120000.json','["自我諏人物，天涯實眇然。", "晚觀童子意，早拍病夫肩。", "凜凜神鋒異，琅琅腹笥傳。", "晴溫武林道，光怪呂家船。"]'),
('c5058885-3f42-493c-a316-c8987bd45a13','鄉人呂正之教三子連中童子科盛哉前此無有也推原所以啟其意者繇今大漕顯謨公乃不遠數百里來致感激余與之釃酒道舊歡甚匆匆欲歸賦詩以留之','嚴煥','宋','宋诗','song-poetry','','[]','千秋萬歲聖賢話，盡挂諸郎齒頰閒。',64,'全唐诗/poet.song.120000.json','["千秋萬歲聖賢話，盡挂諸郎齒頰閒。", "發縱指南知有自，昂霄聳壑定非艱。", "靈椿挺挺元未老，珠樹樅樅孰可攀。", "過我朝陽語中曲，且停煙櫂置家山。"]'),
('99f2853c-d6cf-414d-8b91-18d514d52ee3','和潘良貴三江亭','陳晉錫','宋','宋诗','song-poetry','','[]','神襟百慮不容侵，勝概乘閒偶訪尋。',64,'全唐诗/poet.song.120000.json','["神襟百慮不容侵，勝概乘閒偶訪尋。", "趺坐豈無觀水術，臨流應有濟川心。", "斂將蓬島溶溶氣，散作陽春字字金。", "郢曲調高人寡和，微生何敢綴雄吟。"]'),
('ab1e58d0-315c-41eb-9ef3-b01eeec34a17','醒心亭','陳賓','宋','宋诗','song-poetry','','[]','亭以醒心名，心與亭何與。',180,'全唐诗/poet.song.120000.json','["亭以醒心名，心與亭何與。", "物各有感通，此理貴深喻。", "峴山峙豐碑，見者皆墮淚。", "推類盡其餘，庶表名亭義。", "我昨發莆陽，春光正明媚。", "肩輿撼頓間，思慮雜勞勩。", "行行復行行，至此若沾醉。", "振衣躡斯亭，四顧足清致。", "芳樹布繁陰，晴山薦空翠。", "時有幽禽來，且無俗駕至。", "物我方兩忘，情景亦相會。", "天君始泰然，萬境絕纖翳。", "後樂與先憂，虛靈良不昧。", "揭扁端在茲，夫豈無所試。", "尚期知我者，他時來作記。"]'),
('5c0b0444-07d0-4787-81c6-e27ef5011f5c','龍多山','劉望之','宋','宋诗','song-poetry','','[]','金船載山知有無，大千浮空佛所書。',256,'全唐诗/poet.song.120000.json','["金船載山知有無，大千浮空佛所書。", "何人夜斷海山臂，一手挈置西南隅。", "白虹發晴涪水現，翠鳳下曉巴山趨。", "亮哉何邦實有此，但恐□舞皆凡姝。", "已從上頭收浩蕩，更著幽處藏縈紆。", "馮僊觀中柏摩月，靜老巖下泉跳珠。", "霜荷千樹小雨暗，野竹萬箇秋風□。", "石囷□不了歲事，丹竈肯爲凡人鑪。", "惜無數桃出山崦，來藉芳草開春壺。", "從來山僧野道士，畏客誓不荒榛蕪。", "問誰結屋據雄會，邑中令君秦大夫。", "此郎平生眼如鶻，視此亦足知遠圖。", "挽衣留客來置酒，要看碧浪摧天吳。", "我亦爲渠脚力輕，拄杖插到青雲孤。", "酒酣撫檻叫落日，共閔此世真區區。", "真須舉臂游汗漫，莫向人間墮履鳧。"]'),
('1b728ab3-0579-416a-9ddc-fc533556d1cf','沱江','劉望之','宋','宋诗','song-poetry','','[]','尚勝三年謫，終慚萬里馴。',48,'全唐诗/poet.song.120000.json','["尚勝三年謫，終慚萬里馴。", "極知行路澀，可忍在家貧。", "歲晚沱江綠，雲深錦樹新。", "相思肯如月，夜夜只隨人。"]'),
('2dd1e44f-6dbe-47f5-aaa2-5d64df44d7fe','草堂','劉望之','宋','宋诗','song-poetry','','[]','風月藏詩骨，流離賦病骸。',48,'全唐诗/poet.song.120000.json','["風月藏詩骨，流離賦病骸。", "不禁一飽死，空遺百生懷。", "樹秀天通隴，山嬌客語淮。", "壁間無半偈，無乃望君崖。"]'),
('fed94140-f78e-428e-8462-dc5c1f1e86a9','子雲故居','劉望之','宋','宋诗','song-poetry','','[]','殺却王章愛孔光，舉朝誰復說興亡。',64,'全唐诗/poet.song.120000.json','["殺却王章愛孔光，舉朝誰復說興亡。", "未能免俗歌新美，豈不懷歸念楚狂。", "斗酒只今猶寂寞，小池無舊已荒凉。", "秋風細雨催人去，似恐徘徊費感傷。"]'),
('1fef0785-c29e-4534-b651-b6fb28a0438e','新都驛遠平軒','劉望之','宋','宋诗','song-poetry','','[]','霜晴木落送歸鞍，袖手微吟此慰顔。',64,'全唐诗/poet.song.120000.json','["霜晴木落送歸鞍，袖手微吟此慰顔。", "勝欲憑欄招白鳥，更煩翦樹出青山。", "晚悲薄祿非三釜，賴許清詩見一斑。", "看到遠平纔得恨，我寧歸卧尺椽間。"]'),
('00721e15-6e6e-4b2f-9e2c-407f0cb6c972','古柏','劉望之','宋','宋诗','song-poetry','','[]','草木長生亦偶然，不須聞此便談仙。',64,'全唐诗/poet.song.120000.json','["草木長生亦偶然，不須聞此便談仙。", "燒枝競說丹飛日，舉世寧知手種年。", "雙鶴不歸秋自冷，萬牛回首句空傳。", "相逢一飲清陰下，與子前生定有緣。"]'),
('f0f9acdd-9b61-4f48-bb92-fde5f0efb449','出游','劉望之','宋','宋诗','song-poetry','','[]','漫有游隨意，何曾語展眉。',48,'全唐诗/poet.song.120000.json','["漫有游隨意，何曾語展眉。", "琴臺悲犬子，江路憶熊兒。", "修竹蕭蕭寺，平蕪淺淺陂。", "年來底事業，訪古但饒詩。"]'),
('9aa858b3-e439-4156-8b7e-79726de6b0ec','發成都  其一','劉望之','宋','宋诗','song-poetry','','[]','落拓平生載酒行，如今憔悴鬢絲生。',32,'全唐诗/poet.song.120000.json','["落拓平生載酒行，如今憔悴鬢絲生。", "無金得買青樓笑，空負閑愁出錦城。"]'),
('be16ad35-9ebc-4b87-9810-0841446c7b87','發成都  其二','劉望之','宋','宋诗','song-poetry','','[]','欲洗羈愁只自醒，郫筒酒好信虛名。',32,'全唐诗/poet.song.120000.json','["欲洗羈愁只自醒，郫筒酒好信虛名。", "江陽春色論千戶，價比西州却未輕。"]'),
('947902f9-3a4d-4370-bec3-f9054d201616','發成都  其三','劉望之','宋','宋诗','song-poetry','','[]','一夜孤舟浪打頭，不容客夢到滄洲。',32,'全唐诗/poet.song.120000.json','["一夜孤舟浪打頭，不容客夢到滄洲。", "誰言江上煙波急，未抵歸心一半流。"]'),
('93bc0dde-7b0c-4788-a55a-fa93f0d8bb86','久留少城','劉望之','宋','宋诗','song-poetry','','[]','好去相羊烏角巾，却來躪踏軟紅塵。',64,'全唐诗/poet.song.120000.json','["好去相羊烏角巾，却來躪踏軟紅塵。", "酒因覓睡方成醉，金爲收書更覺貧。", "屢入草堂難下語，少留藥市恐逢人。", "可憐弔古凄凉意，只向揚家往返頻。"]'),
('2c5b8974-a176-4ac4-a2e7-eb1977c3c3dd','荔枝','劉望之','宋','宋诗','song-poetry','','[]','瀘戎瘴癘窟，閩粵山水鄉。',24,'全唐诗/poet.song.120000.json','["瀘戎瘴癘窟，閩粵山水鄉。", "如何產此物，爛然照炎荒。"]'),
('e3a1622d-1aa8-498d-9569-c40324debcd0','海棠','劉望之','宋','宋诗','song-poetry','','[]','平山堂下花無數，看到海棠春好處。',32,'全唐诗/poet.song.120000.json','["平山堂下花無數，看到海棠春好處。", "東君用意惱風光，遲日放開陰勒住。"]'),
('4e97fdc4-5ac1-49b5-af33-ba7ee79f2230','詩二首  其一','劉望之','宋','宋诗','song-poetry','','[]','歸計墮何許，出溪仍泝流。',24,'全唐诗/poet.song.120000.json','["歸計墮何許，出溪仍泝流。", "夢回牛溉路，行到馬湖秋。"]'),
('17ea9e13-671c-429d-bf63-aaabc501075d','詩二首  其二','劉望之','宋','宋诗','song-poetry','','[]','孤舟未晚泊，煙火傍人家。',24,'全唐诗/poet.song.120000.json','["孤舟未晚泊，煙火傍人家。", "小市常憂虎，空城不見花。"]'),
('7800e686-d9e0-4e38-ba0b-cdb9fd085f2f','題三學山','劉望之','宋','宋诗','song-poetry','','[]','棲賢古招提，十里巨松陰。',60,'全唐诗/poet.song.120000.json','["棲賢古招提，十里巨松陰。", "棟宇自隋氏，悠悠歲月深。", "唐人范生畫，風雨欲剝侵。", "相傳金仙趾，玉質存至今。", "星黑夜正午，異物爲華燈。"]'),
('81d5d545-3cd4-4525-86ba-06ccb19aac50','讀和議成赦文作','劉望之','宋','宋诗','song-poetry','','[]','一紙盟書換戰塵，萬方呼舞却霑巾。',64,'全唐诗/poet.song.120000.json','["一紙盟書換戰塵，萬方呼舞却霑巾。", "崇陵訪沈空遺恨，郢國憐懷若有人。", "收拾金繒煩廟算，安排鐘鼎頌宗臣。", "小儒何敢知機事，終望君王赦奉春。"]'),
('4514f274-e41d-4aaf-af62-a8580f740822','句  其一','劉望之','宋','宋诗','song-poetry','','[]','鳳林秋晚見日落，鹿門事遠無人傳。',16,'全唐诗/poet.song.120000.json','["鳳林秋晚見日落，鹿門事遠無人傳。"]'),
('daa08ac3-2b8e-4713-ad8f-66842dcd7140','句  其二','劉望之','宋','宋诗','song-poetry','','[]','地連巴楚峰嵐見，節近清明柳色知。',16,'全唐诗/poet.song.120000.json','["地連巴楚峰嵐見，節近清明柳色知。"]'),
('a1d56eaa-dfdc-4f8e-b942-50909ceb7353','句  其三','劉望之','宋','宋诗','song-poetry','','[]','山盤四十八面險，雲暗三百六旬秋。',16,'全唐诗/poet.song.120000.json','["山盤四十八面險，雲暗三百六旬秋。"]'),
('e82ca17f-d6c0-4fbf-bbe5-169ce119d6d2','句  其四','劉望之','宋','宋诗','song-poetry','','[]','剩破朱紅供短髮，南荒來校世間書。',16,'全唐诗/poet.song.120000.json','["剩破朱紅供短髮，南荒來校世間書。"]'),
('32bcddea-75b8-4b07-bae5-5656a578adbf','句  其五','劉望之','宋','宋诗','song-poetry','','[]','海山無瘴八蠻清。',8,'全唐诗/poet.song.120000.json','["海山無瘴八蠻清。"]'),
('2f910144-14d1-4d3f-8494-fb05283c1962','句  其六','劉望之','宋','宋诗','song-poetry','','[]','莫道南州居井底，請來此處望川原。',16,'全唐诗/poet.song.120000.json','["莫道南州居井底，請來此處望川原。"]'),
('f749a2f5-f9a1-438e-b8d4-213a22bb1ec8','句  其七','劉望之','宋','宋诗','song-poetry','','[]','南縣燒畬早，西溪落漲初。',12,'全唐诗/poet.song.120000.json','["南縣燒畬早，西溪落漲初。"]'),
('f20e2cdb-bcd2-4745-8a79-4321cbbbc1da','句  其八','劉望之','宋','宋诗','song-poetry','','[]','聞說南州異，寒來正月並。',12,'全唐诗/poet.song.120000.json','["聞說南州異，寒來正月並。"]'),
('b6f7451d-3dc0-4f14-928a-a2c21f47c2e9','句  其九','劉望之','宋','宋诗','song-poetry','','[]','山遶郡樓秋過雨，月臨池樹晚生煙。',16,'全唐诗/poet.song.120000.json','["山遶郡樓秋過雨，月臨池樹晚生煙。"]'),
('b54fed9b-00ff-4e66-8963-e48d64294c4b','句  其一○','劉望之','宋','宋诗','song-poetry','','[]','便作稽山看，犀湖五月凉。',12,'全唐诗/poet.song.120000.json','["便作稽山看，犀湖五月凉。"]'),
('4caac6c1-ad7b-454d-9248-cf5dd62e9050','題山石','陳知柔','宋','宋诗','song-poetry','','[]','山花有空相，江月多清暉。',24,'全唐诗/poet.song.120000.json','["山花有空相，江月多清暉。", "野意寫不盡，微吟浩忘歸。"]'),
('0e553423-ce85-4a47-975f-ab4de09e99ca','題石橋','陳知柔','宋','宋诗','song-poetry','','[]','巨石橫空豈偶然，萬雷奔壑有飛泉。',64,'全唐诗/poet.song.120000.json','["巨石橫空豈偶然，萬雷奔壑有飛泉。", "好山雄壓三千界，幽處常栖五百仙。", "雲際樓臺深夜見，雨中鐘鼓隔溪傳。", "我來不作聲聞想，聊試茶甌一味禪。"]'),
('6e4ae72f-9313-448b-84bf-66b4ed796a4f','登巾山','陳知柔','宋','宋诗','song-poetry','','[]','司馬胸中著雲夢，杜陵眼底蓋乾坤。',32,'全唐诗/poet.song.120000.json','["司馬胸中著雲夢，杜陵眼底蓋乾坤。", "吾衰不復論茲事，飽看孤帆落遠村。"]'),
('ece88b8b-6da8-4342-9f06-b50715fdeb22','天台遊山','陳知柔','宋','宋诗','song-poetry','','[]','煙蘿穿幾重，柴車倦驅駕。',180,'全唐诗/poet.song.120000.json','["煙蘿穿幾重，柴車倦驅駕。", "忽尋鐘磬音，山腰得僧舍。", "主僧聞我來，曳杖出相迓。", "揖我坐虛閣，登臨欠臺榭。", "老屋數椽餘，風物自閑暇。", "古木出雲杪，遥岑來竹罅。", "下臨一泓水，涵光冷相射。", "但能了此生，未遽慚大厦。", "我本山中人，偶失學圃稼。", "爲米聊復留，兩同僧過夏。", "得舟家可浮，遇竹宅便借。", "是處皆南山，何必東籬下。", "悠悠去忘歸，寧畏長官罵。", "松月苦留客，徘徊度清夜。", "明朝過桃溪，溪女莫相詫。"]'),
('f84bdbd5-8dd3-4081-81f4-39690d60b801','次海上長亭村','陳知柔','宋','宋诗','song-poetry','','[]','行到山窮處，微茫島嶼青。',48,'全唐诗/poet.song.120000.json','["行到山窮處，微茫島嶼青。", "百年多逆旅，萬事一長亭。", "風雨晚潮急，魚蝦曉市腥。", "平生誦佳句，今見海冥冥。"]'),
('906fbb42-3b1b-4fdd-bdca-326f8c5bfcfd','宿天台萬年寺','陳知柔','宋','宋诗','song-poetry','','[]','古寺來投宿，雲巖第幾層。',48,'全唐诗/poet.song.120000.json','["古寺來投宿，雲巖第幾層。", "有詩堪供佛，無事且依僧。", "小閣泉喧枕，修廊雨暗燈。", "好峰看未足，夢繞碧崚嶒。"]'),
('ae0ad263-706d-4932-9c91-ccad8f3addc6','題洪景伯通判清閟堂','陳知柔','宋','宋诗','song-poetry','','[]','別乘清名滿世間，却來堂下植檀欒。',64,'全唐诗/poet.song.120000.json','["別乘清名滿世間，却來堂下植檀欒。", "已無俗物敗人意，且與此君同歲寒。", "夜月半庭金影碎，秋風一枕玉聲殘。", "雁行吏退鈴齋靜，想見巍冠獨倚闌。"]'),
('af002946-e5fa-4bb7-8c64-ca7f5f0781c1','謁韓祠','陳知柔','宋','宋诗','song-poetry','','[]','斯文何罪竄南荒，來謁孤祠淚數行。',64,'全唐诗/poet.song.120000.json','["斯文何罪竄南荒，來謁孤祠淚數行。", "恐有遺書藏壞壁，豈無哀賦吊沅湘。", "精神不受氛煙蔽，道義長涵日月光。", "四壁蕭蕭香火冷，何人能與作堂皇。"]'),
('d7a97977-cccb-40c5-bb15-b393f3728ab7','韓木  其一','陳知柔','宋','宋诗','song-poetry','','[]','層江波靜鰐如掃，一畝寒陰禽自呼。',32,'全唐诗/poet.song.120000.json','["層江波靜鰐如掃，一畝寒陰禽自呼。", "莫把甘棠比韓木，令人灑涕共長吁。"]'),
('7aff90ab-c615-4366-a45e-7f4ec03d0a81','韓木  其二','陳知柔','宋','宋诗','song-poetry','','[]','康成迹寄書带草，玄德祥標羽葆桑。',32,'全唐诗/poet.song.120000.json','["康成迹寄書带草，玄德祥標羽葆桑。", "名與此山俱不朽，何如煙杪鬰蒼蒼。"]'),
('b43e63e4-6929-49b6-bcda-2259d7f7d6f6','讀潮本韓集','陳知柔','宋','宋诗','song-poetry','','[]','大雅寥寥不復還，如公幾得古人全。',64,'全唐诗/poet.song.120000.json','["大雅寥寥不復還，如公幾得古人全。", "格高枯淡復志賦，意到渾淪原道篇。", "趙子遺編今復亂，歐公校本孰能傳。", "古音祕矣尤難識，聊與磨鉛一究研。"]'),
('2e1a11d9-ac1d-4abf-a46e-888c2f25d106','蓮花峰','陳知柔','宋','宋诗','song-poetry','','[]','多病登臺今古情，菊花摇蕩午凉生。',64,'全唐诗/poet.song.120000.json','["多病登臺今古情，菊花摇蕩午凉生。", "山前木落石巖出，海上潮來秋渚平。", "野興已隨芳草還，歸鞭更傍落霞明。", "愧無十丈開花句，獨卧禪房心自清。"]'),
('58dc025a-4948-4111-9a60-cda24ddde060','題秦隱君祠次鄧經略韻','陳知柔','宋','宋诗','song-poetry','','[]','人境初無車馬喧，卜居原得近姜村。',64,'全唐诗/poet.song.120000.json','["人境初無車馬喧，卜居原得近姜村。", "山圍古寺苔生砌，花落前汀潮打門。", "已許揭身如日月，不妨爲客任乾坤。", "清詩海內流傳久，亭下空餘石硯存。"]'),
('059191e2-4a1a-437a-b112-97518aaa274d','謁姜相墳次鄧經略韻','陳知柔','宋','宋诗','song-poetry','','[]','欲將興廢問洪鈞，來謁孤墳獨愴神。',64,'全唐诗/poet.song.120000.json','["欲將興廢問洪鈞，來謁孤墳獨愴神。", "千載高風餘凜凜，一池秋水自粼粼。", "門前帆影來天際，林杪鐘聲落海濱。", "此道寥寥今復振，不應漁水是東鄰。"]'),
('acc35d21-3349-4e88-bf4a-fa4d0252ba3f','環翠亭','陳知柔','宋','宋诗','song-poetry','','[]','當年把臂入龍山，猶記相逢醉夢間。',64,'全唐诗/poet.song.120000.json','["當年把臂入龍山，猶記相逢醉夢間。", "君似孤雲了無礙，我如倦翼早知還。", "茅簷負日真成算，竹榻論詩整破顔。", "欲問太平真氣象，夜來風月到松關。"]'),
('9caf1772-e016-4250-a7e6-d325c70721a9','涵清閣','陳知柔','宋','宋诗','song-poetry','','[]','追憶唯菴真可人，詩成咳唾筆如神。',32,'全唐诗/poet.song.120000.json','["追憶唯菴真可人，詩成咳唾筆如神。", "使登是閣一快掃，當有銀鈎鐵畫新。"]'),
('6412bde5-9e13-4a90-9b79-434d7fd51628','句','陳知柔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','木落洞庭秋。',6,'全唐诗/poet.song.120000.json','["木落洞庭秋。"]'),
('d35e0cc2-b690-44cf-96ea-8d92bcfa480e','詩一首','黄端','宋','宋诗','song-poetry','','[]','虎脊初終梟獍飛，龍髯半落鬼神疑。',32,'全唐诗/poet.song.120000.json','["虎脊初終梟獍飛，龍髯半落鬼神疑。", "行人二月登廬嶺，點點驪珠欲灑碑。"]'),
('1377a7cf-5be2-4d33-a98e-726feda6ebb9','題涪翁亭','黄然','宋','宋诗','song-poetry','','[]','清音妙絕東坡老，方響名高太史公。',32,'全唐诗/poet.song.120000.json','["清音妙絕東坡老，方響名高太史公。", "水遶烏尤談笑外，江連洪雅畫圖中。"]'),
('fd9e9f34-e9b5-4da4-aa27-434ff493572e','題靈隱寺','王予可','宋','宋诗','song-poetry','','[]','遊山無處浣塵埃，出郭尋幽入翠苔。',64,'全唐诗/poet.song.120000.json','["遊山無處浣塵埃，出郭尋幽入翠苔。", "眾水盡從雙澗去，一峰元自五天來。", "行春人散題名在，坐夏僧閒聽講回。", "清磬一聲猿鳥寂，石楠花落滿經臺。"]'),
('a8c76947-e9f7-41de-ad11-8a815f5003e6','宮詞','王予可','宋','宋诗','song-poetry','','[]','水曲朱門漪漾漫，一簾花雨月波寒。',32,'全唐诗/poet.song.120000.json','["水曲朱門漪漾漫，一簾花雨月波寒。", "金閨背襯鴛鴦冷，春困秋千立畫干。"]'),
('946eff52-db45-465c-9908-5ade78788dba','南園湖石','王予可','宋','宋诗','song-poetry','','[]','翠雀銜雲墮翠蕪，砥峰倒影卧平湖。',32,'全唐诗/poet.song.120000.json','["翠雀銜雲墮翠蕪，砥峰倒影卧平湖。", "飛花不到穿簾月，高倚晴天一劍孤。"]'),
('0c09c1ff-d213-4779-a4cc-2ca7e4eaec13','馴鶴圖','王予可','宋','宋诗','song-poetry','','[]','寢處粧鉛未捲釵，孤雲花带月邊來。',32,'全唐诗/poet.song.120000.json','["寢處粧鉛未捲釵，孤雲花带月邊來。", "六宮簾幕金鸞冷，露濕晨烟啄翠苔。"]'),
('b754a484-2c81-4539-9680-e8c35f889cd7','雜詩二首  其一','王予可','宋','宋诗','song-poetry','','[]','白露沙灘浸綠湄，小舟艤岸尚依稀。',32,'全唐诗/poet.song.120000.json','["白露沙灘浸綠湄，小舟艤岸尚依稀。", "山回屏曲江連樹，春鎖人家深處歸。"]'),
('1b9aada4-814e-4127-a152-4ec6760546a0','雜詩二首  其二','王予可','宋','宋诗','song-poetry','','[]','暗悲秋色素團團，一雨飄零飚霽寒。',32,'全唐诗/poet.song.120000.json','["暗悲秋色素團團，一雨飄零飚霽寒。", "天浄長空烟斂處，彩虹金挂樹頭山。"]'),
('b969605c-4585-42de-945f-b0810f9c0fd2','宮體  其一','王予可','宋','宋诗','song-poetry','','[]','紅葉鋪霜撼御階，繡蓮塵蹴襯羅鞋。',32,'全唐诗/poet.song.120000.json','["紅葉鋪霜撼御階，繡蓮塵蹴襯羅鞋。", "袖沾鶯翅調簧語，墮却銜翹入鬢釵。"]'),
('cece6311-fdac-410b-aa0f-01cb0b35c5bc','宮體  其二','王予可','宋','宋诗','song-poetry','','[]','驕馬金籠藉草歸，翠鸞屏曲染紅霏。',32,'全唐诗/poet.song.120000.json','["驕馬金籠藉草歸，翠鸞屏曲染紅霏。", "凭欄山色春風裏，喚得鶯兒燕子飛。"]'),
('81a9ad98-1bb0-44a5-b03d-4344d18ecf08','句  其一','王予可','宋','宋诗','song-poetry','','[]','石裂雯華漬月秋。',8,'全唐诗/poet.song.120000.json','["石裂雯華漬月秋。"]'),
('0f051fd6-b458-4c75-97da-0d13e6ce8cde','句  其二','王予可','宋','宋诗','song-poetry','','[]','壺樹苔波月漬皴。',8,'全唐诗/poet.song.120000.json','["壺樹苔波月漬皴。"]'),
('49745e65-b977-4ad2-9414-4343f32b403e','句  其三','王予可','宋','宋诗','song-poetry','','[]','一壺天地醒眠小。',8,'全唐诗/poet.song.120000.json','["一壺天地醒眠小。"]'),
('e9f0df8e-52e0-4994-9620-cfff899d84f5','句  其四','王予可','宋','宋诗','song-poetry','','[]','萬疊雲山飛小雁。',8,'全唐诗/poet.song.120000.json','["萬疊雲山飛小雁。"]'),
('645c8d4c-a057-47a2-88df-4a846dad961f','句  其五','王予可','宋','宋诗','song-poetry','','[]','風色偃貂裘。',6,'全唐诗/poet.song.120000.json','["風色偃貂裘。"]'),
('34537dcc-1c0f-412a-97c5-befeaab2e521','句  其六','王予可','宋','宋诗','song-poetry','','[]','唾尖絨舌淡紅甜。',8,'全唐诗/poet.song.120000.json','["唾尖絨舌淡紅甜。"]'),
('847b7036-802a-4855-843c-7ea9edfdb408','句  其七','王予可','宋','宋诗','song-poetry','','[]','金盆水不暖，翠雀啄晴苔。',12,'全唐诗/poet.song.120000.json','["金盆水不暖，翠雀啄晴苔。"]'),
('4ae979d2-d0d1-42e4-8eb7-caae2de6dfa3','句  其八','王予可','宋','宋诗','song-poetry','','[]','鳳蹴瑶華散，龍啣桂子香。',12,'全唐诗/poet.song.120000.json','["鳳蹴瑶華散，龍啣桂子香。"]'),
('e265bf09-5aae-4ea5-ab92-30897aee8e6e','句  其九','王予可','宋','宋诗','song-poetry','','[]','一片冷截潭底月，六彎斜卷隴頭雲。',16,'全唐诗/poet.song.120000.json','["一片冷截潭底月，六彎斜卷隴頭雲。"]'),
('dd2c7f98-cd55-42b8-bc87-3974669025e0','句  其一○','王予可','宋','宋诗','song-poetry','','[]','簾捲綠陰花外月，玉山冰雪醉扶翁。',16,'全唐诗/poet.song.120000.json','["簾捲綠陰花外月，玉山冰雪醉扶翁。"]'),
('9fb16519-1a6f-4ae9-a9a7-262882ffb7b7','句  其一一','王予可','宋','宋诗','song-poetry','','[]','啼鳥倒啣金羽舞，驚蛇斜傍玉簾飛。',16,'全唐诗/poet.song.120000.json','["啼鳥倒啣金羽舞，驚蛇斜傍玉簾飛。"]'),
('e431e7dc-9c11-4a6f-b1f4-9302c391e024','句  其一二','王予可','宋','宋诗','song-poetry','','[]','鳳環捧席带香屏，鯨杯倚伎和雲捲。',16,'全唐诗/poet.song.120000.json','["鳳環捧席带香屏，鯨杯倚伎和雲捲。"]'),
('82081573-d240-4519-8d2b-264ad133a10f','句','李子遷','宋','宋诗','song-poetry','','[]','石鼎夜聯詩筆健，布囊春醉酒錢粗。',16,'全唐诗/poet.song.120000.json','["石鼎夜聯詩筆健，布囊春醉酒錢粗。"]'),
('b08c593b-28cd-4470-98bb-4cbac19460b0','題王龜齡詹事祠堂','王秬','宋','宋诗','song-poetry','','[]','當時孤論偶相同，終始知心每愧公。',64,'全唐诗/poet.song.120000.json','["當時孤論偶相同，終始知心每愧公。", "纔見安車延綺季，遽嗟石室祀文翁。", "百年公議分明在，一餉紛華究竟空。", "白髮舊交衰甚矣，尚能留面對高風。"]'),
('0f36b0c7-7c58-4560-b805-fee122d6415a','題不欺室張魏公爲王龜齡書也何子應賦詩','王秬','宋','宋诗','song-poetry','','[]','君不見開元名相張九齡，歲寒松柏森蒼鱗。',99,'全唐诗/poet.song.120000.json','["君不見開元名相張九齡，歲寒松柏森蒼鱗。", "胡塵澒洞言始驗，世間回首思忠臣。", "堂堂魏公忠貫日，志欲平戎獎王室。", "歸來無地展經綸，餘事文章揮健筆。", "玉節朱轓兩君子，不以交情變生死。", "共將新句紀遺編，留與山林續詩史。"]'),
('7e582e95-48dd-4f79-ace1-df825aa3f389','登歷下古城員外新亭二首  其一','王秬','宋','宋诗','song-poetry','','[]','新亭結構罷，隱見清湖陰。',72,'全唐诗/poet.song.120000.json','["新亭結構罷，隱見清湖陰。", "跡籍臺觀舊，氣溟海岳深。", "圓荷想自昔，遺堞感至今。", "芳宴此時具，哀絲千古心。", "主稱壽尊客，筵秩宴北林。", "不阻蓬蓽興，得兼梁甫吟。"]'),
('21d686dd-1cae-4b73-b147-461ee7b3c660','登歷下古城員外新亭二首  其二','王秬','宋','宋诗','song-poetry','','[]','吾宗固神秀，體物寫謀長。',72,'全唐诗/poet.song.120000.json','["吾宗固神秀，體物寫謀長。", "形制開古跡，曾冰延樂方。", "太山雄地理，巨壑眇雲莊。", "高興泊煩促，永懷清典常。", "含弘知四大，出入見三光。", "負郭喜粳稻，安時歌吉祥。"]'),
('ba2e240b-9fed-4c64-9e3f-22be4c0c269e','登綺霞亭','王秬','宋','宋诗','song-poetry','','[]','危亭臨霽景，金碧迥紛紛。',48,'全唐诗/poet.song.120000.json','["危亭臨霽景，金碧迥紛紛。", "天映中原氣，山橫萬古雲。", "夕陽寒未斂，孤鶩遠猶聞。", "俯仰懷前哲，清樽爲苾芬。"]'),
('f413fa5e-98d2-46c9-859a-2a9ffec64975','句  其一','王秬','宋','宋诗','song-poetry','','[]','何時五畝成歸計，來作鄰翁伴藝林。',16,'全唐诗/poet.song.120000.json','["何時五畝成歸計，來作鄰翁伴藝林。"]'),
('aab94da6-58d3-46a2-924f-f83395be0282','句  其二','王秬','宋','宋诗','song-poetry','','[]','柳色知春淺，鐘聲覺寺深。',12,'全唐诗/poet.song.120000.json','["柳色知春淺，鐘聲覺寺深。"]'),
('60ab1903-9b20-4143-94b0-858dd27750b7','句  其三','王秬','宋','宋诗','song-poetry','','[]','避虎連村靜，分魚一市腥。',12,'全唐诗/poet.song.120000.json','["避虎連村靜，分魚一市腥。"]'),
('c2570ee6-1217-47c1-aaed-46eb8459c352','句  其四','王秬','宋','宋诗','song-poetry','','[]','羊角洞開風浩蕩。',8,'全唐诗/poet.song.120000.json','["羊角洞開風浩蕩。"]'),
('f9b0a880-abe3-4ae5-b470-68df332840a5','臨終偈','釋子深','宋','宋诗','song-poetry','','[]','衲僧日日是好日，要行便行無固必。',32,'全唐诗/poet.song.120000.json','["衲僧日日是好日，要行便行無固必。", "虛空天子夜行船，摩訶般若波羅蜜。"]'),
('306d824e-712f-41ba-a939-cbae2935e16e','韓木','黄補','宋','宋诗','song-poetry','','[]','先生來潮南，先生一時屋。',184,'全唐诗/poet.song.120000.json','["先生來潮南，先生一時屋。", "潮南得先生，潮南千載足。", "嗚呼潮南俗亦淳，先生遺樹今猶存。", "春山二月春鳥響，遊人樹底羅酒尊。", "尊殘倚樹初不語，暗覺山翁淚如雨。", "山翁之淚良可憐，我生不及元和前。", "元和萬事已塵土，惟有喦邊留此樹。", "樹本於人果何識，爲是先生手親植。", "先生一去今幾秋，喦頭滿樹春風浮。", "風從昨夜何懰慓，儼似當年祛鰐色。", "鰐魚東遁不回頭，一带寒江遶郡流。", "郡人向晚爭歸舟，樹與江波相對愁。"]'),
('dd51d9e5-4db6-435e-a1d2-ace16bef03be','擬古六首  其一','曾協','宋','宋诗','song-poetry','','[]','濯濯春月柳，低映金張宅。',48,'全唐诗/poet.song.120000.json','["濯濯春月柳，低映金張宅。", "風光到飛絮，枝頭少顔色。", "榮華豈不好，歲晚負賞識。", "堅貞自中心，君看松與柏。"]'),
('565b3deb-720a-4ada-941e-3ce60dd8b676','擬古六首  其二','曾協','宋','宋诗','song-poetry','','[]','幽窗射明月，寂寞閑素琴。',48,'全唐诗/poet.song.120000.json','["幽窗射明月，寂寞閑素琴。", "朱絃不改調，撫弄無好音。", "文衣襲綠綺，明徽鈿黄金。", "君恩一朝異，對此千恨深。"]'),
('142023c4-b3c8-4e22-ad3f-d503507a267a','擬古六首  其三','曾協','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','憶昨初離別，羞容不成歌。',84,'全唐诗/poet.song.120000.json','["憶昨初離別，羞容不成歌。", "長袖未曾舞，塵埃生綺羅。", "君恩一言足，歲月豈在多。", "澤國多悲風，江湖易濤波。", "遊子久行役，歲晏今若何。", "迢迢朱樓夜，數起瞻明河。", "不如長江月，素影常相過。"]'),
('705c77cb-a04b-40dc-a480-6e6a12aceab6','擬古六首  其四','曾協','宋','宋诗','song-poetry','','[]','迢迢千尺松，下有綠髮龜。',48,'全唐诗/poet.song.120000.json','["迢迢千尺松，下有綠髮龜。", "流膏穿厚地，配此凌雲姿。", "隱見雖若殊，雪霜俱不移。", "置身苟得地，共保千歲期。"]'),
('004826ca-25bc-4d8b-8e4d-e6325e77a14c','擬古六首  其五','曾協','宋','宋诗','song-poetry','','[]','孤峰鬰嵯峨，千古常峻峙。',48,'全唐诗/poet.song.120000.json','["孤峰鬰嵯峨，千古常峻峙。", "下有迴環水，流浪無定止。", "如何深遠意，盡寄七絃裏。", "妾意極高山，君心甚流水。"]'),
('99d9bace-2fbe-455c-ac74-e0da04bc460a','擬古六首  其六','曾協','宋','宋诗','song-poetry','','[]','日月無時停，飄忽成隆冬。',72,'全唐诗/poet.song.120000.json','["日月無時停，飄忽成隆冬。", "烟雲慘不舒，暮雪陵飚風。", "永懷皸瘃憂，藉此衣褐重。", "蟄蟲逐微煖，地底度歲窮。", "飲啄却外物，一氣常自充。", "人貌肖天地，不能保微躬。"]'),
('19775651-7820-4615-a008-1cccd01c9490','擬結客少年場','曾協','宋','宋诗','song-poetry','','[]','結客少年場，定交杯酒間。',96,'全唐诗/poet.song.120000.json','["結客少年場，定交杯酒間。", "相傾在意氣，握手出肺肝。", "倉皇夜扣門，然諾曾不難。", "所至足賓客，後乘車班班。", "鄠杜走馬歸，百萬供一餐。", "路人側目視，仇家骨常寒。", "紅塵一箭飛，大索喧長安。", "可笑愚儒生，相逢話辛酸。"]'),
('b402a16d-abf5-4fce-bdd4-47295703a6fb','和唐使君秬古風二首  其一','曾協','宋','宋诗','song-poetry','','[]','宦遊非所安，舉足常徊徨。',120,'全唐诗/poet.song.120000.json','["宦遊非所安，舉足常徊徨。", "官事似馬曹，自謂真漫郎。", "猶慚上官前，簪裳久低昂。", "歸輒痛掃溉，草木有幽香。", "但令眼中青，不問眉間黄。", "何期逢故侯，一見心清凉。", "揚袂指鄉國，矯翼西南翔。", "危言氣崢嶸，高懷涕淋浪。", "更憐凡草木，欲置桃李場。", "作詩借光輝，此意寧可忘。"]'),
('c4ab2e97-7ff5-44f4-8041-78ec0bb20441','和唐使君秬古風二首  其二','曾協','宋','宋诗','song-poetry','','[]','志士身許國，夫豈慕高爵。',120,'全唐诗/poet.song.120000.json','["志士身許國，夫豈慕高爵。", "感慨九重恩，領受千里託。", "安邊志獲就，解印良亦樂。", "厚祿棄千鍾，壯氣橫六幕。", "造朝吐奇論，投合期契鑰。", "終焉謾喋喋，遠意誰領略。", "琳館返高卧，鈴齋休畫諾。", "擬尋一畝宮，未辦千金橐。", "松楸已在眼，阡陌想交錯。", "迴頭長安日，傾心比葵藿。"]'),
('a975beba-4d95-450b-83b1-05c9c1cb75e9','送汪汝馮沿檄造朝','曾協','宋','宋诗','song-poetry','','[]','春風扇微和，散入桃李場。',120,'全唐诗/poet.song.120000.json','["春風扇微和，散入桃李場。", "枯枿受披拂，處處生輝光。", "有客事行役，起柁凌官塘。", "浮家入烟浪，琴書粲成行。", "旁有玉頰人，妙指出宮商。", "主人志超俗，心胸瑩琳琅。", "但使秋月明，豈慮浮雲翔。", "富貴恐不免，賦予元有常。", "善保萬金璧，毋遺輕毀傷。", "豈無山徑蹊，徐步遵康莊。"]'),
('a4598227-2388-4566-a5db-0b437ebb07f4','陳晞顔獲玉兔甚奇邀予賦詩','曾協','宋','宋诗','song-poetry','','[]','一氣散萬有，飛潜異形姿。',204,'全唐诗/poet.song.120000.json','["一氣散萬有，飛潜異形姿。", "烏鵠自昔然，羽翼不可移。", "穎也衣褐徒，斕斑廼其宜。", "今茲獨何事，皓皓涅不淄。", "毳毛玉雪如，整整機上絲。", "無乃真得僊，傳載非詭辭。", "騎蟾入廣寒，成此一段奇。", "長生侶素娥，不受塵土羈。", "祇應得得來，隱見必其時。", "往牒紀創見，奕奕登瑞旗。", "退之號崛强，雄誇見文詞。", "君侯過人行，精神動皇祇。", "屢供平反笑，長詠南陔詩。", "異物自來馴，不起山林思。", "霜月照庭戶，晴雲點階墀。", "致此非好玩，於焉卜期頤。", "上堂問起居，秀色增兩眉。"]'),
('51242937-3632-4cab-a49f-0d786586aeff','鄧器先北窗','曾協','宋','宋诗','song-poetry','','[]','今人競圖南，朗朗百間屋。',120,'全唐诗/poet.song.120000.json','["今人競圖南，朗朗百間屋。", "夫子胡不然，嚮晦一窗足。", "北窗吾亦愛，嘗謂所樂獨。", "豈知交游中，昌歜或同欲。", "光澄窮永晝，風遠宜三伏。", "誦書音和平，高卧夢清熟。", "吟詩與作賦，未覺環堵蹙。", "心安爾許寬，六合寄一粟。", "閑聽飛雨灑，靜看游蜂觸。", "一笑知莫逆，排闥不待速。"]'),
('88e21c0f-7d2a-4655-a049-04ed53aeba43','次韻李粹伯登鎮江倅廳富覽亭','曾協','宋','宋诗','song-poetry','','[]','酒餘共逍遥，散步升高岡。',48,'全唐诗/poet.song.120000.json','["酒餘共逍遥，散步升高岡。", "萬物困霜雪，歲晏俱老蒼。", "江山一臨眺，志欲凌八荒。", "青霞儻見分，誰能束冠裳。"]'),
('b3a6131d-0423-4306-99a1-f0bbba541316','題李粹伯晦菴','曾協','宋','宋诗','song-poetry','','[]','天道有消息，物理兼屈伸。',144,'全唐诗/poet.song.120000.json','["天道有消息，物理兼屈伸。", "鳥匿定將擊，龍蟄以存身。", "卷舒雖不同，爲用常相因。", "老聃晞髮時，恝然似非人。", "肢體尚可墮，外物真埃塵。", "信知猶龍姿，涵養知幾春。", "寂寥千載下，裔孫豈其倫。", "磊落感意氣，崢嶸富精神。", "廼以晦自居，悠然返天真。", "漁樵欲爭席，鷗鳥行相親。", "形諜不可掩，眉端已津津。", "風雲一朝便，垂天起潜鱗。"]'),
('cd4ca93d-0cf1-4fda-9eb5-9646905a3dd4','王炎弼安吉丞廳真清軒和沈文伯韻','曾協','宋','宋诗','song-poetry','','[]','青山如君子，臭味我族類。',144,'全唐诗/poet.song.120000.json','["青山如君子，臭味我族類。", "向來傲官府，正自惡俗吏。", "主人清且賢，菽水無虛僞。", "胸次塵滓盡，端可肖人意。", "軒窗自羅列，獻此重疊翠。", "公餘一隱几，舉目窮幽事。", "昔爲幕中賓，妙語了同異。", "孰堪畏棲遲，勝境配高義。", "要從孺子濯，不逐眾人醉。", "呤哦坐書叢，袖手太阿利。", "沈侯負能名，二絕一言蔽。", "聊同座右銘，此語君莫墜。"]'),
('540f65aa-1d5c-4013-8bbd-f59ebbe8612e','江梅','曾協','宋','宋诗','song-poetry','','[]','北風號喬林，萬象無容姿。',72,'全唐诗/poet.song.120000.json','["北風號喬林，萬象無容姿。", "高標自有時，正與冰雪宜。", "老幹儼枯木，疎花粲橫枝。", "刻玉費天巧，不爲俗眼窺。", "託質在空谷，清高終見知。", "論功鼎鼐間，枝頭子離離。"]'),
('423fb257-8cee-4612-ba4a-e74622426f73','蠟梅','曾協','宋','宋诗','song-poetry','','[]','小樹列仙質，翛然道家裝。',84,'全唐诗/poet.song.120000.json','["小樹列仙質，翛然道家裝。", "雪帔掛淺絳，銖衣曳微黄。", "清風一披拂，芝蘭讓幽香。", "老子專鼻觀，此花正相當。", "就令困霜雪，肯受泥塗傷。", "題評得名字，詩人惜輝光。", "雖無調鼎實，不作時世粧。"]'),
('4aa17ea6-0a16-48f3-a870-d45fdb6bd447','章季子携所作樂府來以詩謝之','曾協','宋','宋诗','song-poetry','','[]','平生尚幽僻，塵務百不省。',120,'全唐诗/poet.song.120000.json','["平生尚幽僻，塵務百不省。", "屢從松竹遊，身閑愛官冷。", "何知事大繆，窮日厭鞭打。", "抽身對佳客，屣倒冠不整。", "吏徒環顧人，爲我忍俄頃。", "匆匆上馬揖，語略意已領。", "新詩滿懷袖，璀璨吐光景。", "歸來坐明月，萬象入清境。", "風林起驚鵲，閑窗散花影。", "吟哦不成寐，盡此良夜永。"]'),
('c3824c49-c3c9-4413-8cd5-5b0d7419e087','題大兒新安官舍三樂齋','曾協','宋','宋诗','song-poetry','','[]','吾先聖人徒，游夏同淵源。',288,'全唐诗/poet.song.120000.json','["吾先聖人徒，游夏同淵源。", "孝友與忠信，入道先本根。", "下視晉楚富，商歌滿乾坤。", "一唯了萬事，伋軻繼師尊。", "至今百世後，家法要不煩。", "近數高曾來，潔身等璵璠。", "當時天下士，白首稱曾門。", "世掇太常第，自致冕與軒。", "養祿到北堂，孝哉無間言。", "猶悲鯉庭空，遺恨終自吞。", "至我壯無成，浪使歲月奔。", "文科始不嗣，媿此朱兩轓。", "賴汝念祖烈，先登倡諸孫。", "寂寥四十載，重拜雨露恩。", "吾年獨天假，將雛見飛翻。", "靦顔幸一洗，積德慚九原。", "三年作尉歸，橫經處侯藩。", "孤城山水稠，草木霜不蕃。", "官閒身無事，舊書可重繙。", "故職在六經，緒業勤討論。", "避堂舍翁媼，齒在髮未髠。", "不憂俸酸寒，羅列奉晨飧。", "公黌沸絃誦，私室合箎塤。", "氣完萬物輕，始驗中所存。"]'),
('ab553b1e-719c-4dfd-89e5-cbaccd41c3c3','飲沈氏園得僻字','曾協','宋','宋诗','song-poetry','','[]','會心足勝侶，暇日訪春色。',181,'全唐诗/poet.song.120000.json','["會心足勝侶，暇日訪春色。", "慵尋剡溪榜，厭曳永嘉屐。", "名園可徘徊，勝概在咫尺。", "峰巒起平地，村落墮城壁。", "梅橫前嶺峻，柳列長堤直。", "最愛臨水亭，欲背依山石。", "沉沉想潜鱗，錚錚聽仙弈。", "初無杖屨勞，具享山林適。", "一尊供笑語，四座列豪逸。", "規摹西洛舊，髣髴香山昔。", "愛酒太白狂，耽詩少陵僻。", "始靜姑縱談，中喧或爭席席。", "殘鐘咽林際，新月掛簷隙。", "飲散興未厭，人歸境愈寂。", "何必記昔游，虛空了無迹。"]'),
('f5de6f6c-0281-4323-8f60-47e6f0f83b86','送鄧器先赴羅田尉五首  其一','曾協','宋','宋诗','song-poetry','','[]','我始來相居，談公口瀾翻。',48,'全唐诗/poet.song.120000.json','["我始來相居，談公口瀾翻。", "平生驚人句，筆力正始間。", "古人不可作，因君見班班。", "矍然起懦庸，褰裳撼詩關。"]'),
('d8d41fb6-8dda-4504-92a2-b1a970107f23','送鄧器先赴羅田尉五首  其二','曾協','宋','宋诗','song-poetry','','[]','吾鄉旴江西，流轉半天下。',48,'全唐诗/poet.song.120000.json','["吾鄉旴江西，流轉半天下。", "夢爲故國遊，流涕指丘社。", "漂萍偶同止，風力巧相借。", "感君聲氣似，剪燭對清夜。"]'),
('67ec9531-7c62-4526-8755-9fe87faf7e51','送鄧器先赴羅田尉五首  其三','曾協','宋','宋诗','song-poetry','','[]','之子抱奇器，彈冠始茲年。',48,'全唐诗/poet.song.120000.json','["之子抱奇器，彈冠始茲年。", "邑人望風度，夫豈南昌仙。", "樂土風俗淳，吠犬申旦眠。", "弓刀無可試，斑衣日蹁躚。"]'),
('953da322-65f5-415d-92a4-be9b1dbfcaca','送鄧器先赴羅田尉五首  其四','曾協','宋','宋诗','song-poetry','','[]','古郡有奇觀，祖祖燈相傳。',48,'全唐诗/poet.song.120000.json','["古郡有奇觀，祖祖燈相傳。", "子來後往哲，青山古依然。", "紛紛簿領中，深觀常安然。", "但使內外盡，饑餐困須眠。"]'),
('d39fa461-4676-4fbf-94ad-938420d1e753','送鄧器先赴羅田尉五首  其五','曾協','宋','宋诗','song-poetry','','[]','君齒餘四十，見推十年兄。',48,'全唐诗/poet.song.120000.json','["君齒餘四十，見推十年兄。", "驚呼昔安在，相逢太晚生。", "坐語未及盡，風帆忽遐征。", "願君懷此都，吾廬始經營。"]'),
('d055d0da-e48f-446d-bab1-ff4947db8d53','送趙德莊右司赴江東漕八首  其一','曾協','宋','宋诗','song-poetry','','[]','往年際風雲，濯濯春月柳。',48,'全唐诗/poet.song.120000.json','["往年際風雲，濯濯春月柳。", "俊氣橫九天，下筆蛟龍走。", "歲晚收其實，落落堅且久。", "澹然松檜質，不爲霜雪朽。"]'),
('256fba1d-21c3-4315-812b-a7e77d836173','送趙德莊右司赴江東漕八首  其二','曾協','宋','宋诗','song-poetry','','[]','軒蓋事朝謁，閶闔方晨趨。',48,'全唐诗/poet.song.120000.json','["軒蓋事朝謁，閶闔方晨趨。", "霜露懷松楸，慨然賦歸歟。", "確志感清衷，載以使者車。", "往宣問事條，勿但安田廬。"]'),
('9b8a77b8-043e-4aa2-bacb-f609bdbab288','送趙德莊右司赴江東漕八首  其三','曾協','宋','宋诗','song-poetry','','[]','正色立公府，嘉謀贊巖廊。',48,'全唐诗/poet.song.120000.json','["正色立公府，嘉謀贊巖廊。", "材華動人主，咫尺鴛鷺行。", "掉頭不肯住，清宵夢滄浪。", "丈夫貴勇决，養此百鍊剛。"]'),
('7a409571-0584-42d7-b2b3-bec3b2b0e752','送趙德莊右司赴江東漕八首  其四','曾協','宋','宋诗','song-poetry','','[]','行邁未爲遠，兩州東西都。',48,'全唐诗/poet.song.120000.json','["行邁未爲遠，兩州東西都。", "中天敞華闕，魚鑰黄金鋪。", "山川儼形勢，貔貅凜戈殳。", "正須埋輪手，先聲震江吳。"]'),
('d04cf363-0619-42fa-b422-bae4827f78d2','送趙德莊右司赴江東漕八首  其五','曾協','宋','宋诗','song-poetry','','[]','建業一都會，由來帝王畿。',48,'全唐诗/poet.song.120000.json','["建業一都會，由來帝王畿。", "曠哉懷古心，陳迹猶依依。", "當年王謝家，青紫滿烏衣。", "萬事一丘土，簡策徒是非。"]'),
('e3aa2537-43ef-487f-9e80-7246404cc89d','送趙德莊右司赴江東漕八首  其六','曾協','宋','宋诗','song-poetry','','[]','飽學兼內外，超然悟空無。',48,'全唐诗/poet.song.120000.json','["飽學兼內外，超然悟空無。", "是身任東西，乾坤一蘧廬。", "目前謾紛紜，一致總萬殊。", "良欲行世間，不效山澤癯。"]'),
('56ba0ccf-de5d-4726-a85f-1ff748c8fa0d','送趙德莊右司赴江東漕八首  其七','曾協','宋','宋诗','song-poetry','','[]','鄉來遠門牆，引睇想光輝。',48,'全唐诗/poet.song.120000.json','["鄉來遠門牆，引睇想光輝。", "宦游偶相值，間關得因依。", "都門送星軺，依然寸心違。", "勿爲賈胡留，速書季子歸。"]'),
('b3c36500-6aca-417d-8878-5fea569bc031','送趙德莊右司赴江東漕八首  其八','曾協','宋','宋诗','song-poetry','','[]','我公廊廟姿，當爲濟時霖。',48,'全唐诗/poet.song.120000.json','["我公廊廟姿，當爲濟時霖。", "生材必有用，應物初無心。", "異時百僚上，金貂耀華簪。", "富貴恐不免，易退其自今。"]'),
('3793c19e-df07-477a-8b41-fd578f01eca8','賦趙有翼仇池石次沈正卿用蘇翰林韻','曾協','宋','宋诗','song-poetry','','[]','貪夫居奇貨，什襲藏結綠。',168,'全唐诗/poet.song.120000.json','["貪夫居奇貨，什襲藏結綠。", "寧知十五城，不救卞和足。", "豈如嗜石人，丘壑在胸腹。", "不知連城價，但賞數峰蹙。", "長公仙去後，兵馬遂南牧。", "尤物落何許，心知委溝瀆。", "何期超世賢，愛石不愛玉。", "夜半負之走，包裹隨竄伏。", "一朝返窗几，時清端可卜。", "李虎初平羊，案上紛相逐。", "崢嶸幸無恙，不問牛馬谷。", "趙侯天機異，閱世輕嗜欲。", "好奇與嗜利，達觀均一曲。", "正恐便棄置，就賞君宜速。"]'),
('0cf1c6fa-e731-4238-b592-1f11b77f3c60','送趙有翼通守吳興','曾協','宋','宋诗','song-poetry','','[]','江南雨無時，桃李迹已陳。',204,'全唐诗/poet.song.120000.json','["江南雨無時，桃李迹已陳。", "有客念江湖，別乘陪朱輪。", "明德先九族，恩殊在廷臣。", "惟公真龍種，眉宇猶津津。", "不受膏粱昏，辭章動楓宸。", "合著玉笋班，冠冕朝大昕。", "去丞股肱郡，要此骨肉親。", "蕭蕭霅水鄉，溪山繞城闉。", "空光纈紋亂，倒影圖畫新。", "金石富文墨，烟波多隱淪。", "坐想賢使君，迎笑均憑茵。", "席間荀陳俱，會此主與賓。", "陳榻對清夜，潘輿行莫春。", "拄頰愛爽氣，揮毫詠風蘋。", "遠近入題品，蒼翠生精神。", "我忘鷗鳥盟，低徊踐香塵。", "因子動歸興，詰旦車當巾。"]'),
('eee87a05-fd8d-43f2-9a43-8fd2f6ee4c8f','寄題蘭陵郡齋梅露堂','曾協','宋','宋诗','song-poetry','','[]','蘭陵爲郡更齊梁，地望卓犖聞四方。',240,'全唐诗/poet.song.120000.json','["蘭陵爲郡更齊梁，地望卓犖聞四方。", "清班詵詵儲材良，相踵往佩太守章。", "憲公遺愛初未忘，當時瑞露今名堂。", "於茲遼遼幾星霜，此邦復得尚書郎。", "政似古人天降祥，揭榜華屋遥相望。", "使君燕寢東西廂，嶺梅林林分兩傍。", "春事已退墮渺茫，調羹有實升廟廊。", "葉間奇葩忽芬芳，縹白異狀中有香。", "襞績千葉成花房，天公好善善必彰。", "故出瑞物非其常，此花顔色見未嘗。", "浴以沆瀣宵瀼瀼，炯如珠璣綴琳琅。", "蜂房割蜜蔗流漿，邦人歡呼走且僵。", "我公中心念丁黄，撫摩凋瘵還耕桑。", "天錫嘉瑞不肯當，盡掇鉅美歸聖皇。", "公豈我留返鵷行，但有盛事存甘棠。"]'),
('28b803cc-fc8d-4e43-96e8-c6e7edb3894a','送趙有翼監丞造朝供職','曾協','宋','宋诗','song-poetry','','[]','君侯昂然百夫雄，近之和氣如春風。',240,'全唐诗/poet.song.120000.json','["君侯昂然百夫雄，近之和氣如春風。", "揚眉高論多折衷，眾人斂衽稱名通。", "發爲詩章燦璧琮，氣豪筆健敏且工。", "口占欲使十手供，春雲容與朝霞烘。", "肯如空階號秋蟲，槁項巖穴甘老窮。", "是將織文裨衮龍，潤色造化分天功。", "奏之清廟流笙鏞，宜使正笏趨槐楓。", "發舒平生學古胸，時吐奇論驚羣公。", "久矣高門映衰宗，金蘭投分自諸翁。", "我嘗聯曹愧凡庸，竭蹶道上昔所同。", "朔雪撲面花蒙茸，六龍先路如雲從。", "重來苕溪奉從容，好若膠漆始且終。", "先後唱和如歌鐘，君還清班朝九重。", "我將轂下居治中，他時涉筆朱墨叢。", "已見矯翼凌長空，一笑道舊雙頰紅。"]'),
('4444ba22-0e41-48d6-a453-13837d40397d','次翁士秀喜雪長詠','曾協','宋','宋诗','song-poetry','','[]','陰陽持權或贏縮，運氣循環更剝復。',320,'全唐诗/poet.song.120000.json','["陰陽持權或贏縮，運氣循環更剝復。", "忽驚寒凜襲重裘，元是祥霙散平陸。", "登山不覺屐齒折，索酒仍催葛巾漉。", "蕭條貧居馬爲二，瑟縮凍坐龜藏六。", "揮毫謾詫句中眼，對案常逢食無肉。", "未謀南畝五百弓，浪說朱輪三十輻。", "且欣膏潤入郊原，爲拯黔黎出溝瀆。", "敢將固陋測帝心，概想生靈皆子育。", "將春欲放草木葉，成歲先須天地肅。", "伊余平生貪靜勝，有此一廛從穆卜。", "應憐此地久憔悴，端向吾廬增煜煜。", "巧隨高下綴琪樹，任逐橫斜落雲屋。", "塵緣頓覺一羽輕，詩句但驚翻水速。", "坐令歡意盪愁思，仍遣時寒破常燠。", "嵇康醉狀聳危石，衛玠羸姿立修竹。", "排來一一盡連璧，環立詵詵皆冠玉。", "晚風徐韻仍佩環，枯木無心亦冠服。", "曉連青女增粲粲，夜映金波兼穆穆。", "遮藏春色失斕斑，漏泄梅花有芬馥。", "掀髯一笑萬事空，細讀君詩倒醽醁。"]'),
('9dfe73bd-1a3a-479f-93c0-41f69baa0cd1','次韻翁士秀雪再作','曾協','宋','宋诗','song-poetry','','[]','尚記東郊千頃白，夜不聞聲曉盈尺。',176,'全唐诗/poet.song.120000.json','["尚記東郊千頃白，夜不聞聲曉盈尺。", "飄灑速若赴敵兵，密陣橫空誰督責。", "且從膏澤落田疇，不厭寒威凌枕席。", "朅來重見凍雲凝，似欲飛花襲遺跡。", "起尋藜杖行東皋，麥隴芊芊凈摇碧。", "平生殷雷轉空腸，此日准擬千倉積。", "老農甚喜天破慳，尊酒相携慰疲劇。", "土膏滲漉入鋤犂，丁寧孫子耕須力。", "勸農使君軟語多，莫待官儂費鞭策。", "人言回天古所難，坐變樂歲須臾間。", "丈夫行志自其所，會作一朝黄鵠舉。"]'),
('7ad2ec59-6132-4859-b967-62624e60ae56','和裘父姪季貍竹夫人歌','曾協','宋','宋诗','song-poetry','','[]','我家門戶瀟灑侯，渭川千畝封君儔。',96,'全唐诗/poet.song.120000.json','["我家門戶瀟灑侯，渭川千畝封君儔。", "自應秀氣到兒女，骨格凜凜含清秋。", "向來玉立蹄輪道，已解使人除熱惱。", "事君爲取冰雪清，豈是與君相媚好。", "人生用捨元有時，秋堂掛壁何足悲。", "不是短檠長棄置，會與夏簟還相宜。"]'),
('ace706e8-f17c-4598-976c-5362bec83175','周知和以蘇陳倡和韻賦水仙江梅蠟梅三種花謹次韻','曾協','宋','宋诗','song-poetry','','[]','天工著意初放花，三英凜凜真一家。',128,'全唐诗/poet.song.120000.json','["天工著意初放花，三英凜凜真一家。", "鏤冰點酥更團蠟，始信功深解生物。", "臨風却嗅心自知，粲兮粲兮哦古詩。", "幾年刻玉但成葉，一笑真同長康絕。", "得非仙種來神山，爲伴老子終朝眠。", "歲寒得友不忍去，且對眾香勤覓句。", "鼎分風月俱可人，如陳竇劉人所君。", "詩場戰罷戢干越，盡掃色塵歌一鉢。"]'),
('18656e7f-c564-4403-ba5e-93dc8d788764','周知和李粹伯一再和鉢字韻詩益工勉繼元韻','曾協','宋','宋诗','song-poetry','','[]','道人鍾情獨此花，封植絕類富貴家。',128,'全唐诗/poet.song.120000.json','["道人鍾情獨此花，封植絕類富貴家。", "毋令攀折强封蠟，精神頓減非生物。", "五陵少年那得知，氣使造化須新詩。", "春工未遍裁雲葉，但賦貢金品皆絕。", "公家甥舅如玉山，清夜秉燭愁花眠。", "一朝奉節公馳去，又疊陽關斷腸句。", "誰專此花蔣徑人，公自無愧面覲君。", "來詩聲調轉清越，謬對霜鐘扣銅鉢。"]'),
('4339d770-4776-4c94-81c4-5b8ff3a3452f','次韻翁士秀病起','曾協','宋','宋诗','song-poetry','','[]','一間何闊昔未有，擬遣蒼頭問安否。',192,'全唐诗/poet.song.120000.json','["一間何闊昔未有，擬遣蒼頭問安否。", "果然示疾毗耶城，靜看醫方出吾肘。", "平生豪氣干青雲，客疾來侵豈能久。", "已知筋力却几杖，復見精神照窗牖。", "花時倏忽風雨過，無語酬春愧顔厚。", "管城端復束高閣，公不自倡誰爲首。", "俄驚肆筆出大篇，聊示作家三昧手。", "我今方覺疾病嬰，豈是同生值陽九。", "鏡中華髮略相似，材具超人定非偶。", "公今闊步躡中朝，顧我一麾方出守。", "如何江湖大國楚，笑謂曹鄶言地醜。", "似矜斷木欲青黄，寧有長松生培塿。"]'),
('619226a1-19ce-4d0b-a2a5-6204b75dbc47','暮春雜詠八首  其一','曾協','宋','宋诗','song-poetry','','[]','曲徑穿深樾，支流旁小亭。',48,'全唐诗/poet.song.120000.json','["曲徑穿深樾，支流旁小亭。", "鳥將雲共遠，天與樹俱青。", "水色清堪掇，風聲靜可聽。", "壁間餘地在，落筆記曾經。"]'),
('693ed87d-862c-4b95-9214-eab6d8d7e599','暮春雜詠八首  其二','曾協','宋','宋诗','song-poetry','','[]','蓮沼瓊瑶墮，萱庭錦繡張。',48,'全唐诗/poet.song.120000.json','["蓮沼瓊瑶墮，萱庭錦繡張。", "靜聞人語好，閑愛水風凉。", "藜杖休行樂，蒲團且坐忘。", "沙禽相識慣，趯趯近胡床。"]'),
('164b03bf-8598-4573-9159-76947c9db475','暮春雜詠八首  其三','曾協','宋','宋诗','song-poetry','','[]','晝永常支枕，賓來旋整冠。',48,'全唐诗/poet.song.120000.json','["晝永常支枕，賓來旋整冠。", "日篩槐影細，風撼竹聲乾。", "壤沃耘耕少，人閒賦斂寬。", "近知田舍樂，不記昔爲官。"]'),
('60052c29-4660-4600-b3ff-c3d7512e04eb','暮春雜詠八首  其四','曾協','宋','宋诗','song-poetry','','[]','客路清溪好，人家綠樹間。',48,'全唐诗/poet.song.120000.json','["客路清溪好，人家綠樹間。", "凄凉何縣雨，想像別州山。", "馴雀飛還下，遊魚去自還。", "兒曹了官事，天地一身閑。"]'),
('fd460690-8490-4285-9f58-2f58db666faf','暮春雜詠八首  其五','曾協','宋','宋诗','song-poetry','','[]','目斷江頭樹，襟披海上風。',48,'全唐诗/poet.song.120000.json','["目斷江頭樹，襟披海上風。", "荷鋤偕婦子，擲釣共兒童。", "晚筀關心碧，秋蓮滿意紅。", "歌聲何處起，舞手爲年豐。"]'),
('4bf35598-5e05-4c10-9c0e-670026ec7354','暮春雜詠八首  其六','曾協','宋','宋诗','song-poetry','','[]','信使頻驅傳，元戎罷枕戈。',48,'全唐诗/poet.song.120000.json','["信使頻驅傳，元戎罷枕戈。", "茅茨隨處有，禾稼望中多。", "寓客時吳語，豐年半楚歌。", "泰然真樂土，誰爲挽天河。"]'),
('ba1b5ed9-019b-40c7-9312-164fc72fccd5','暮春雜詠八首  其七','曾協','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','楚甸三千里，旌麾列大邦。',48,'全唐诗/poet.song.120000.json','["楚甸三千里，旌麾列大邦。", "渺瀰連沃野，隱轔抱長江。", "此際藩王室，何人擁將幢。", "向來稱下邑，國士有無雙。"]'),
('e82f05a7-6d1f-4da7-9258-dfdab3a4538b','暮春雜詠八首  其八','曾協','宋','宋诗','song-poetry','','[]','隔岸連平野，鄰家背短城。',48,'全唐诗/poet.song.120000.json','["隔岸連平野，鄰家背短城。", "海風無日息，楚水照人清。", "有子能干祿，全家可代耕。", "飯餘無一事，更覺勝平生。"]'),
('8cc85671-2fcf-4dc8-ad9c-4022bf4831c8','蓬戶','曾協','宋','宋诗','song-poetry','','[]','野客何爲戶，編非茅即蓬。',48,'全唐诗/poet.song.120000.json','["野客何爲戶，編非茅即蓬。", "松堅難闔闢，竹瘦謾牢籠。", "疎密殊無準，粗纖任不同。", "我常知善閉，寧向此矜功。"]'),
('008a6c4b-36aa-4ab5-a605-0da9ac877090','王叔武示忠州張使君德遠近詩次韻三首  其一','曾協','宋','宋诗','song-poetry','','[]','垂紳立朝著，智略勝吾丘。',48,'全唐诗/poet.song.120000.json','["垂紳立朝著，智略勝吾丘。", "列戟分名郡，兒童說細侯。", "卷舒誰罣礙，中外且嬉遊。", "聞說淮南守，天邊又拜州。"]'),
('0bc6e783-3172-45ff-9c22-cd5226e55469','王叔武示忠州張使君德遠近詩次韻三首  其二','曾協','宋','宋诗','song-poetry','','[]','妙理居言外，高懷見酒邊。',48,'全唐诗/poet.song.120000.json','["妙理居言外，高懷見酒邊。", "無心千里奉，有意一燈傳。", "柏樹誰能指，虛空莫問年。", "爐香聊閉閤，何處覓心田。"]'),
('e15d2430-f446-4817-a196-3da2dd29855a','王叔武示忠州張使君德遠近詩次韻三首  其三','曾協','宋','宋诗','song-poetry','','[]','安心今得法，問道舊名庵。',48,'全唐诗/poet.song.120000.json','["安心今得法，問道舊名庵。", "雅致追龐老，高風數泐潭。", "遠公容入社，彌勒本同龕。", "寄語邦人道，叢林始罷參。"]'),
('33b8456a-efec-463e-86a6-6b9821a18b16','倪文舉寺簿挽詩三首  其一','曾協','宋','宋诗','song-poetry','','[]','盛德逾人遠，高談造理深。',48,'全唐诗/poet.song.120000.json','["盛德逾人遠，高談造理深。", "保身元有道，應世了無心。", "別日更寒暑，交情隔古今。", "紙窗風雪夜，猶記掉頭吟。"]'),
('ab26c46f-bf0b-49cb-94c1-1976d8e7323a','倪文舉寺簿挽詩三首  其二','曾協','宋','宋诗','song-poetry','','[]','學植春同富，詞源海樣寬。',48,'全唐诗/poet.song.120000.json','["學植春同富，詞源海樣寬。", "細聽朝士說，宜著侍臣冠。", "泉壤歸何遽，容臺席未安。", "蒼旻如可問，不遣淚河乾。"]'),
('a939c921-3f8a-4f5e-8e87-418e586ec500','倪文舉寺簿挽詩三首  其三','曾協','宋','宋诗','song-poetry','','[]','水國相從日，文場並進時。',48,'全唐诗/poet.song.120000.json','["水國相從日，文場並進時。", "駑材元有限，逸駕自難追。", "方指青雲路，俄聞薤露詩。", "鵬程千萬里，却付稱家兒。"]'),
('bd7078a6-489e-491d-81b3-d858bd9a4678','和韓子文','曾協','宋','宋诗','song-poetry','','[]','寄迹驚殊縣，論詩得勝流。',48,'全唐诗/poet.song.120000.json','["寄迹驚殊縣，論詩得勝流。", "更容參往返，不恨此淹留。", "絕唱終三疊，長謠擬四愁。", "同遊有陶謝，莫賦仲宣樓。"]'),
('266769fe-b6de-4b99-8ec4-09ff741f1a3c','送李秀叔吏部拜命赴闕二首  其一','曾協','宋','宋诗','song-poetry','','[]','此地詳聞月旦評，精神英發氣和平。',64,'全唐诗/poet.song.120000.json','["此地詳聞月旦評，精神英發氣和平。", "胸蟠七澤波瀾闊，骨鬭九秋風露清。", "窮巷蕭條從我老，半生懷抱向君傾。", "忽聞來促朝天騎，應記當年曳履聲。"]'),
('0d0d47ea-2913-4abc-9976-ef9ff5f42c6b','送李秀叔吏部拜命赴闕二首  其二','曾協','宋','宋诗','song-poetry','','[]','君王念舊數星霜，驛騎風馳詔濕黄。',64,'全唐诗/poet.song.120000.json','["君王念舊數星霜，驛騎風馳詔濕黄。", "闊步入趨天北極，舊班聯踐漢中郎。", "好行素志應須力，穩上青雲不用忙。", "異日相從話功業，知無愧色沮剛腸。"]'),
('80f1a938-111d-43ae-aeca-15902c153ce0','李懋之壺中齋請賦詩','曾協','宋','宋诗','song-poetry','','[]','山川吞盡一壺中，未見先生芥蒂胸。',64,'全唐诗/poet.song.120000.json','["山川吞盡一壺中，未見先生芥蒂胸。", "要識廣輸藏粟粒，且將談笑舉針鋒。", "橘中載酒初無礙，花裏行車足有容。", "可但大千歸眼界，網塵從此現重重。"]'),
('db1050a2-ed0e-4778-abf7-1825ba3e01f2','次韻翁士秀見贈二首  其一','曾協','宋','宋诗','song-poetry','','[]','川原積歲阻交情，佳客常思置驛迎。',64,'全唐诗/poet.song.120000.json','["川原積歲阻交情，佳客常思置驛迎。", "花縣論心尊俎樂，竹宮識面歲時驚。", "久知書作征南癖，更覺詩同東野清。", "却斂櫜鞬真退舍，君才屹立五言城。"]'),
('c933e5c7-e291-4e8b-bf0a-edf31b3cf9f9','次韻翁士秀見贈二首  其二','曾協','宋','宋诗','song-poetry','','[]','興來躡履便追隨，共約乘風汗漫期。',64,'全唐诗/poet.song.120000.json','["興來躡履便追隨，共約乘風汗漫期。", "述作正須陶令手，利名不上紫芝眉。", "名高似斗誰能挹，量大如淵不可窺。", "老去故交今絕少，高情傾蓋樂新知。"]'),
('7fe9c499-4504-4698-a466-5be31db1d71d','再次前韻二首呈士秀  其一','曾協','宋','宋诗','song-poetry','','[]','相逢此日勝平生，不厭搘筇數送迎。',64,'全唐诗/poet.song.120000.json','["相逢此日勝平生，不厭搘筇數送迎。", "樂地共欣三徑就，詩壇仍見一軍驚。", "風飄柳線曾經染，雪著梅梢分外清。", "光景喚人無計奈，剩煩佳句破愁城。"]'),
('1b1a1faa-0d24-4bbe-a279-ac4b6cbca74c','再次前韻二首呈士秀  其二','曾協','宋','宋诗','song-poetry','','[]','錦囊惠我句增奇，賞會應須得子期。',64,'全唐诗/poet.song.120000.json','["錦囊惠我句增奇，賞會應須得子期。", "萬頃淵深連渤澥，千尋巉刻對峨眉。", "心游舊簡幾忘食，家有名園不暇窺。", "誰報詩人春到了，屋山應有候禽知。"]'),
('34081d18-c79b-49a5-88ba-64b94ec0d68c','次韻汪汝馮見贈','曾協','宋','宋诗','song-poetry','','[]','身閑官冷巧相如，草舍柴扉况並居。',64,'全唐诗/poet.song.120000.json','["身閑官冷巧相如，草舍柴扉况並居。", "刮目尚爲三日別，論心真勝十年書。", "屢煩折簡催羸馬，知有新粧出綺疏。", "興發會須携短策，要看風味慰逃虛。"]'),
('fc3a6d26-2d13-432d-86a4-ab073affadae','次趙有翼簡徐聖可元韻','曾協','宋','宋诗','song-poetry','','[]','已向幽居賦晚晴，欲經絕壁訪神清。',64,'全唐诗/poet.song.120000.json','["已向幽居賦晚晴，欲經絕壁訪神清。", "不憂五柳荒松菊，敢嘆三閭带杜蘅。", "=無風月三千首，賴有絲桐一再行。", "誰似孔庭能父子，繼揮高韻思如傾。"]'),
('d0425c07-0459-42d7-9866-393ede4088aa','喜晴','曾協','宋','宋诗','song-poetry','','[]','詩翁高興動新晴，未踏湖山句已清。',64,'全唐诗/poet.song.120000.json','["詩翁高興動新晴，未踏湖山句已清。", "領略風光初入眼，指麾泉石欲盱衡。", "屢傳黼扆方圖舊，應有鋒車便趣行。", "莫向苕溪戀行樂，葵心元向太陽傾。"]'),
('cbbd25ff-53fb-4493-9b67-98b9a2160e55','李粹伯對月見懷次韻','曾協','宋','宋诗','song-poetry','','[]','初收雨脚萬絲懸，妙手誰人補漏天。',64,'全唐诗/poet.song.120000.json','["初收雨脚萬絲懸，妙手誰人補漏天。", "佳月素華迷夜旦，好詩餘味滿中邊。", "裴徊無奈謝希逸，齁䶎總輸邊孝先。", "見說百篇酬一斗，高門重見酒中仙。"]'),
('13e9f98a-a5a2-4313-b5a3-48b688940357','王叔武示和人雪詩次韻二首  其一','曾協','宋','宋诗','song-poetry','','[]','天上瓊花次第垂，且教微霰向塵飛。',64,'全唐诗/poet.song.120000.json','["天上瓊花次第垂，且教微霰向塵飛。", "玉糅重見嬌飛燕，鶴舞初疑老令威。", "農事預知三徑樂，釣舟遥憶五湖歸。", "夢迴陡覺衾裯薄，應是迷空一尺圍。"]'),
('ad8ef693-3637-4959-b391-4e10c0e893fe','王叔武示和人雪詩次韻二首  其二','曾協','宋','宋诗','song-poetry','','[]','迴瞻一色暮雲垂，癡雀相看凍不飛。',64,'全唐诗/poet.song.120000.json','["迴瞻一色暮雲垂，癡雀相看凍不飛。", "地闢爛銀窺佛界，班連萬玉想天威。", "輕明照日千山靜，寒碧浮江一棹歸。", "見說孤吟清到骨，知君不羨妓成圍。"]'),
('c71ab1ad-8d02-43a6-a056-7eb9c177a933','送薛士昭','曾協','宋','宋诗','song-poetry','','[]','邂逅江干得勝流，襟懷冰玉氣橫秋。',64,'全唐诗/poet.song.120000.json','["邂逅江干得勝流，襟懷冰玉氣橫秋。", "相逢便及平生事，欲去知難苦死留。", "殘漏寒燈催別酒，淡雲微雨送行舟。", "虎頭自是封侯骨，穩上青雲莫倦游。"]'),
('53454636-5415-48ff-877f-75be30f2c92d','沈正卿示探梅詩次韻','曾協','宋','宋诗','song-poetry','','[]','數點微明已露奇，解顔相見却先知。',64,'全唐诗/poet.song.120000.json','["數點微明已露奇，解顔相見却先知。", "携壺擬醉無窮樹，走馬來看第一枝。", "照水意閑真我輩，釀寒雲重正花時。", "自從親識春風面，不信良工畫有詩。"]'),
('c6056cb0-1969-4b59-b663-0784aa26dca9','再次沈韻','曾協','宋','宋诗','song-poetry','','[]','獨將春信報天涯，豈是無情定有知。',64,'全唐诗/poet.song.120000.json','["獨將春信報天涯，豈是無情定有知。", "巧占歲寒憐韻勝，冥搜詩句愧辭枝。", "松篁有約成三友，桃李爭功彼一時。", "珍重休文三昧手，盡回佳處入清詩。"]'),
('98c04ae7-43f8-4e77-9bb1-972a8a9ce511','正卿借韻招同社候雨霽訪梅次韻','曾協','宋','宋诗','song-poetry','','[]','看梅常擬到參橫，最愛微霜墮太清。',64,'全唐诗/poet.song.120000.json','["看梅常擬到參橫，最愛微霜墮太清。", "輕棹幽探煩結約，繁花亂點要晴明。", "直須香裏同扶杖，莫問尊前幾舉觥。", "誰向詩盟最先歃，定知一座自公傾。"]'),
('b4d12cfe-5ca4-40d6-ad1e-29390e8b4cb0','總司官餞董少卿','曾協','宋','宋诗','song-poetry','','[]','蚤聞天詔下江津，元是君王自賞音。',64,'全唐诗/poet.song.120000.json','["蚤聞天詔下江津，元是君王自賞音。", "闊步穩登霄漢路，借留難副士民心。", "緩歌共有留連意，別酒休辭瀲灧斟。", "三節踵來公去後，空餘離恨一江深。"]'),
('2b318b5e-4648-44b9-9fb7-821d681b43c6','謝翁子履子進惠詩二首  其一','曾協','宋','宋诗','song-poetry','','[]','聯翩連璧扣柴荆，剝啄初聞屣履迎。',64,'全唐诗/poet.song.120000.json','["聯翩連璧扣柴荆，剝啄初聞屣履迎。", "華衮借褒知不稱，纍珠入手見須驚。", "長篇勢欲傾三峽，古調聲堪被四清。", "聊遣世人知句法，君家元有謝宣城。"]'),
('055b4bb3-5c32-4f60-a754-c2685f139b6c','謝翁子履子進惠詩二首  其二','曾協','宋','宋诗','song-poetry','','[]','偶結茅茨一水湄，便從佳士得心期。',64,'全唐诗/poet.song.120000.json','["偶結茅茨一水湄，便從佳士得心期。", "可堪大老留青眼，更向諸郎識白眉。", "驥足方求千里附，豹文先許一斑窺。", "鶴鳴子和君家事，此樂外人那得知。"]'),
('f48d442f-5e5e-47cb-8dbe-77d1de03ae49','次韻謝鄭仲南惠詩二首  其一','曾協','宋','宋诗','song-poetry','','[]','毫端萬態鬭森嚴，山比崇高粟比纖。',64,'全唐诗/poet.song.120000.json','["毫端萬態鬭森嚴，山比崇高粟比纖。", "學博自應前輩似，才多真可萬人兼。", "心傳家法書仍在，腹有成章筆未拈。", "雄辯縱橫皆正論，却羞季子尚飛箝。"]'),
('bb7bbb67-30c8-4bcd-b90c-8a010b93b02b','次韻謝鄭仲南惠詩二首  其二','曾協','宋','宋诗','song-poetry','','[]','腰組歸來且打乖，闔廬纔可著吾儕。',64,'全唐诗/poet.song.120000.json','["腰組歸來且打乖，闔廬纔可著吾儕。", "可堪佳客尋衰迹，更著新詩起壯懷。", "枉對青山記排闥，好當紅藥詠翻階。", "一從悟得驚人句，自悔枚臯賦似俳。"]'),
('da9a8ae0-cdde-4001-a66f-61f53a54d5fa','謝翁子亨惠詩','曾協','宋','宋诗','song-poetry','','[]','爲愛高門足鳳麟，恂恂濟濟燕雙親。',64,'全唐诗/poet.song.120000.json','["爲愛高門足鳳麟，恂恂濟濟燕雙親。", "和聲自得壎箎樂，巧思爭裁錦繡新。", "句裏直須希鮑謝，客來今復見荀陳。", "要知家法傳無盡，更到垂髫總過人。"]'),
('19f7b23e-d5cf-49d1-bf6f-616d28067eb3','謝蜀人侯君惠詩','曾協','宋','宋诗','song-poetry','','[]','我曾魂夢到西南，翠碧相圍遠近山。',64,'全唐诗/poet.song.120000.json','["我曾魂夢到西南，翠碧相圍遠近山。", "睡覺不知身許遠，神遊却悔便求還。", "國家舊數兩川最，人物尤勝二漢間。", "笑讀君詩生羽翼，便如舉目對孱顔。"]'),
('94db05a1-7b66-40e3-a79a-06510688adda','送向兄荆父帥維揚二首  其一','曾協','宋','宋诗','song-poetry','','[]','寵數頻煩色愈溫，耐官丞相克家孫。',64,'全唐诗/poet.song.120000.json','["寵數頻煩色愈溫，耐官丞相克家孫。", "川原迤邐提封闊，旌纛森嚴上將尊。", "心識古人風節似，望知前輩典刑存。", "春風草綠長淮凈，眼看頻流雨露恩。"]'),
('efc69140-a057-4f92-936c-34bd37ae593f','送向兄荆父帥維揚二首  其二','曾協','宋','宋诗','song-poetry','','[]','大父曾開刺史天，固應陳迹尚依然。',64,'全唐诗/poet.song.120000.json','["大父曾開刺史天，固應陳迹尚依然。", "邦人却怪家風在，故老今推宅相賢。", "仗鉞秉旄仍置使，輕裘緩带更安邊。", "須知此日分憂重，更覺光榮掩後前。"]'),
('6a156bdf-7532-45f7-b95f-bd97aa584cc3','和陳晞顔春盡思歸二首  其一','曾協','宋','宋诗','song-poetry','','[]','坐閱榮枯鳥過空，青冥誰解指行蹤。',64,'全唐诗/poet.song.120000.json','["坐閱榮枯鳥過空，青冥誰解指行蹤。", "柳邊初見鶯調舌，樹底俄驚鹿養茸。", "稱副閑身清晝永，裝添靜境綠陰濃。", "宮桃正倚東風醉，也逐迴溝出九重。"]'),
('a4e344a9-4016-43f2-aba0-455a5391ae38','和陳晞顔春盡思歸二首  其二','曾協','宋','宋诗','song-poetry','','[]','小白長紅幾番飛，清詩端爲解愁圍。',64,'全唐诗/poet.song.120000.json','["小白長紅幾番飛，清詩端爲解愁圍。", "莫貪藉草尋幽事，須念留花苦待歸。", "杜酒政須常在手，沈腰元自不勝衣。", "織成春恨無窮盡，誰遣天孫不下機。"]'),
('8e6fffd9-a6c8-4a04-b557-9bf99fc45ab5','夜飲枕流次日以詩記陳迹','曾協','宋','宋诗','song-poetry','','[]','水軒幽會六人同，夜色蒼茫蠟炬紅。',64,'全唐诗/poet.song.120000.json','["水軒幽會六人同，夜色蒼茫蠟炬紅。", "淅淅好風天似水，紛紛高論氣如虹。", "罰籌蝟起觴無算，醉骨山頹榼屢空。", "却坐胡床看月上，對人樓殿有無中。"]'),
('0f389013-0b94-4d14-ade3-66a31ff3326e','再飲枕流和王景文韻','曾協','宋','宋诗','song-poetry','','[]','乞得微官本爲閒，生憎簿領積如山。',64,'全唐诗/poet.song.120000.json','["乞得微官本爲閒，生憎簿領積如山。", "鼎來佳客無陶謝，向後微言到孔顔。", "安得朱絃起秋思，預愁清淚落陽關。", "壯懷醉裏依然在，不信蕭蕭兩鬢斑。"]'),
('3dece67a-6a17-47be-b19c-17e12dc10405','昔先君子與司直兄相知文字間諸孤懸隔各未相聞一旦裘父姪惠然見訪共道家庭舊好撫今念昔慨然傷懷因成小詩呈裘父','曾協','宋','宋诗','song-poetry','','[]','傳業懸知臭味同，許時蹤跡馬牛風。',64,'全唐诗/poet.song.120000.json','["傳業懸知臭味同，許時蹤跡馬牛風。", "莫誇今夕爲何夕，不見吾翁對若翁。", "道舊幾驚心欲折，問年俱恨鬢成蓬。", "只應飽學非同調，滿篋新詩字字工。"]'),
('501d5aba-2ce1-4c85-ac9d-d40ddb2ecca2','裘父見和復次韻','曾協','宋','宋诗','song-poetry','','[]','郢質由來迥不同，曾當巧匠運斤風。',64,'全唐诗/poet.song.120000.json','["郢質由來迥不同，曾當巧匠運斤風。", "肯過異縣尋癡叔，聊遣高談慰病翁。", "骯髒吾甘老苕霅，飛騰君合上崑蓬。", "祇今已恨成名晚，好把文章問化工。"]'),
('f152e6d7-b3f1-443f-8d4d-a44f1907299a','和裘父見贈二首  其一','曾協','宋','宋诗','song-poetry','','[]','平生傳業志詩書，常恥朱門衒綺襦。',64,'全唐诗/poet.song.120000.json','["平生傳業志詩書，常恥朱門衒綺襦。", "作意文場旋閣筆，强顔宦路亦分符。", "駸駸春意回平野，戛戛籃輿入畫圖。", "但恐相思勞小阮，想從煙際望重湖。"]'),
('637437dd-6ac1-4814-93d3-46d9c82718e0','和裘父見贈二首  其二','曾協','宋','宋诗','song-poetry','','[]','鄉關重見慰餘年，踉蹡迎門喜欲顛。',64,'全唐诗/poet.song.120000.json','["鄉關重見慰餘年，踉蹡迎門喜欲顛。", "先遣好詩陳曲折，更搜餘論盡中邊。", "尚勤葯石論臣佐，莫向杯觴近聖賢。", "杜口不言窮達事，知君客疾不難痊。"]'),
('6aebeb05-c9cd-4947-8e71-f640783a1eb5','俞義仲輓詩','曾協','宋','宋诗','song-poetry','','[]','適意平生水竹居，雌黄在手爲藏書。',64,'全唐诗/poet.song.120000.json','["適意平生水竹居，雌黄在手爲藏書。", "久看英子聲名早，常恐良朋過往疎。", "方喜安輿迎綵袖，忽驚平陌走喪車。", "青松翠柏新阡路，常使行人淚滿裾。"]'),
('cb4d6c5b-c375-4962-a18b-1257da703887','邵衮臣挽詩二首  其一','曾協','宋','宋诗','song-poetry','','[]','軒冕初期咳唾收，一官白首歎淹留。',64,'全唐诗/poet.song.120000.json','["軒冕初期咳唾收，一官白首歎淹留。", "已嗟遊宦騫騰晚，遽遣功名取次休。", "中壽不令周甲子，遺編曾擬傳春秋。", "未應埋沒隨黄壤，定作騎鯨汗漫遊。"]'),
('5849a6a3-77a2-40ac-916d-05f8fb9c4198','邵衮臣挽詩二首  其二','曾協','宋','宋诗','song-poetry','','[]','幼年耆舊識東牀，壯歲名喧翰墨場。',64,'全唐诗/poet.song.120000.json','["幼年耆舊識東牀，壯歲名喧翰墨場。", "老去里閭推聞望，向來士子誦文章。", "芊綿宿草悲春盡，牢落佳城怨夜長。", "賴有集賢多故舊，筆端三絕刻琳瑯。"]'),
('35daba2b-b389-4b43-be48-86c3f0588208','寒食雨霽','曾協','宋','宋诗','song-poetry','','[]','亂雲將雨趁狂風，掃溉氛埃瞬息中。',64,'全唐诗/poet.song.120000.json','["亂雲將雨趁狂風，掃溉氛埃瞬息中。", "指點山川開凈綠，按行花草失欹紅。", "槐榆改火年年事，簫鼓迎神處處同。", "自是平生觀物化，不因春去始知空。"]'),
('7b8bd8a3-9cd4-430d-a8ab-d20b4434eb13','湖山堂','曾協','宋','宋诗','song-poetry','','[]','自從幽處得官居，不向良工覓畫圖。',64,'全唐诗/poet.song.120000.json','["自從幽處得官居，不向良工覓畫圖。", "青繞簾帷山極望，冷侵庭戶水平鋪。", "漁歌歷歷來天外，帆影飛飛入坐隅。", "俸粟有餘公事少，卧聽風雨落江湖。"]'),
('5a326f7c-b3fa-449c-ae4d-02ccb5cda07c','衛公堂二首  其一','曾協','宋','宋诗','song-poetry','','[]','衛公精爽故依然，陳迹凄凉不記年。',64,'全唐诗/poet.song.120000.json','["衛公精爽故依然，陳迹凄凉不記年。", "亭遠謾傳曾起草，樓高無復見籌邊。", "新銘初勒風煙上，舊觀都忘歲月遷。", "從此南徐矜勝概，美談留與後生傳。"]'),
('6f76eb8b-01b0-49e3-b91f-8fbdc005cc59','衛公堂二首  其二','曾協','宋','宋诗','song-poetry','','[]','寥寥相望兩邦君，冰雪襟懷錦繡文。',64,'全唐诗/poet.song.120000.json','["寥寥相望兩邦君，冰雪襟懷錦繡文。", "身見共誇新令尹，名高猶榜故將軍。", "神交頓覺千年近，心遠初無一間分。", "只有玄談探佛海，坐傾端復掩前聞。"]'),
('b37a85c3-fcf3-4c32-8345-05cdf1c9f1dc','送張忠州使君八兄二首  其一','曾協','宋','宋诗','song-poetry','','[]','邂逅江干不自期，坐傾談屑看霏霏。',64,'全唐诗/poet.song.120000.json','["邂逅江干不自期，坐傾談屑看霏霏。", "豈無清禁摛華地，只得名城衣錦歸。", "惜別定知雙鬢換，問詩常恨寸心違。", "目窮千里蒼茫際，惟有檣烏向北飛。"]'),
('6cee3843-3578-4f68-b738-322fa246c5fa','送張忠州使君八兄二首  其二','曾協','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','東閣如公不挽留，又飄征袖入西州。',64,'全唐诗/poet.song.120000.json','["東閣如公不挽留，又飄征袖入西州。", "四方謾說多奇士，千騎纔教占上頭。", "那得長繩縈去棹，不堪淋雨助離愁。", "長江自古常東注，莫遣仙舟得泝流。"]'),
('a7e43b63-c50f-46a7-9bbe-4e280c1fb630','題陳倅升卿芝草圖二首  其一','曾協','宋','宋诗','song-poetry','','[]','別駕陰功草木知，一朝變化出神奇。',64,'全唐诗/poet.song.120000.json','["別駕陰功草木知，一朝變化出神奇。", "乍驚蓂莢還同長，更羨卿雲向下垂。", "文筆分明傳異狀，畫圖次第記當時。", "嘉祥創見輕千古，信宿曾看十樣芝。"]'),
('107fde0f-d7e1-4e6d-a201-f134b08351ca','題陳倅升卿芝草圖二首  其二','曾協','宋','宋诗','song-poetry','','[]','高義從來蓋里閭，枌榆社底得新居。',64,'全唐诗/poet.song.120000.json','["高義從來蓋里閭，枌榆社底得新居。", "萱堂秀骨松難老，蘭砌清才玉不如。", "天產寶芝彰瑞應，地靈妙相紀生初。", "定知繼展調元手，不負平生萬卷書。"]'),
('fd6cecdb-3ee9-4c36-88bc-6eabe32f3bed','沈正卿重梅次韻','曾協','宋','宋诗','song-poetry','','[]','恰占春工一倍奇，休言造化總無私。',64,'全唐诗/poet.song.120000.json','["恰占春工一倍奇，休言造化總無私。", "香羅翦透因稠疊，瑴玉裁成却附離。", "愛玩枝頭無限思，題評筆下若爲辭。", "開時縱晚春猶早，底事遊蜂聖得知。"]'),
('dd47ca79-4b57-47d4-9be1-16a22c327575','和俞幾先喜雨二首  其一','曾協','宋','宋诗','song-poetry','','[]','萬人望歲正艱難，坐對盤餐泚在顔。',64,'全唐诗/poet.song.120000.json','["萬人望歲正艱難，坐對盤餐泚在顔。", "沿泝謾談舟楫利，圃畦未放桔槹閑。", "歡呼甘雨今朝足，准擬豐年舊觀還。", "眼裏塵氛掃除盡，撲人空翠繞西山。"]'),
('bc778a67-7ce5-4bb5-9627-6e5eeb7d4f9b','和俞幾先喜雨二首  其二','曾協','宋','宋诗','song-poetry','','[]','自嗤宦況局寒蟬，已覺歸心决大川。',64,'全唐诗/poet.song.120000.json','["自嗤宦況局寒蟬，已覺歸心决大川。", "勿使山靈長謝客，幸餘溪友舊忘年。", "無心欲羨千鍾祿，有意初謀二頃田。", "雨足年豐無一事，春蠶將老只思眠。"]'),
('20e440cb-cd45-4120-b5cf-4985463d972a','和蔣子尚','曾協','宋','宋诗','song-poetry','','[]','偶隨舶趠上淮州，忽見霜凝尚此留。',64,'全唐诗/poet.song.120000.json','["偶隨舶趠上淮州，忽見霜凝尚此留。", "屢指雲天談故國，幾從煙水理歸舟。", "自知客子驚殘歲，賴有斯人破旅愁。", "他日西窗剪銀燭，巴山却話夢中遊。"]'),
('cf90f53b-b79b-4cb5-bc40-19b3256262c6','和王雅州見贈','曾協','宋','宋诗','song-poetry','','[]','懷人俄復幾春秋，三舍相望見末由。',64,'全唐诗/poet.song.120000.json','["懷人俄復幾春秋，三舍相望見末由。", "千騎前驅催首路，九重側席納嘉謀。", "茅茨至陋何堪顧，蘋藻雖微尚可羞。", "准擬掃除迎上客，玉蕤陰底列觥籌。"]'),
('ac6f1f74-d0c2-4dcd-842e-4d38579d1143','陳晞顔董漕湖南過零陵用簡齋韻見贈次韻謝之又賦一篇述懷  其一','曾協','宋','宋诗','song-poetry','','[]','筆到鍾王意有餘，詩章高古過黄初。',64,'全唐诗/poet.song.120000.json','["筆到鍾王意有餘，詩章高古過黄初。", "班行未上論思地，遠使聊宣寬大書。", "乞與豐年均飽煖，更申嚴令絕侵漁。", "肯迂使節存支郡，咫尺猶嫌會面疎。"]'),
('afb0928c-f432-4057-abae-0de29c1eb587','陳晞顔董漕湖南過零陵用簡齋韻見贈次韻謝之又賦一篇述懷  其二','曾協','宋','宋诗','song-poetry','','[]','平生志不在贏餘，久擬揮毫賦遂初。',64,'全唐诗/poet.song.120000.json','["平生志不在贏餘，久擬揮毫賦遂初。", "莫問倚牆空甔石，但令盈几足琴書。", "幸存茅屋幽堪隱，况有清溪近可漁。", "賸欲抽簪訪松菊，要憑突兀看扶疎。"]'),
('6164a62f-f353-477a-bc28-3dad16b0b09d','都漕適至作詩相慶次韻','曾協','宋','宋诗','song-poetry','','[]','邂逅江干倍囅然，喜公彊健過前年。',64,'全唐诗/poet.song.120000.json','["邂逅江干倍囅然，喜公彊健過前年。", "筆端電掃三千字，言下冰消十二緣。", "傳業有人吾免矣，擊鮮溷汝古同然。", "自今擬棄人間事，總把傳家付阿圓。"]'),
('10fe9323-20a8-4b5a-b5ef-35e3c6419667','和李粹伯','曾協','宋','宋诗','song-poetry','','[]','萬事知公一髮輕，尚憐花草喚愁生。',64,'全唐诗/poet.song.120000.json','["萬事知公一髮輕，尚憐花草喚愁生。", "酒邊意氣來酣戰，筆下文章要主盟。", "絕唱共驚神有助，擅場將見敵無爭。", "總輸老子工藏拙，飽食安眠百不營。"]'),
('4f97d616-b606-4e33-b02b-d980d2895fc1','寄題陳晞顔敦復齋','曾協','宋','宋诗','song-poetry','','[]','一入虛齋百慮沉，箇中何待覓知音。',64,'全唐诗/poet.song.120000.json','["一入虛齋百慮沉，箇中何待覓知音。", "雪收未起龍蛇蟄，境靜初窺天地心。", "五里霧中藏豹穩，九重淵底得珠深。", "自從占斷寬閒野，寂寞虛空無古今。"]'),
('fafd73c7-25a2-4616-b15d-9ec108c3084d','趙有翼招同社出遊次韻','曾協','宋','宋诗','song-poetry','','[]','總道無情却有情，撩人幽事不勝清。',64,'全唐诗/poet.song.120000.json','["總道無情却有情，撩人幽事不勝清。", "擬同騷僕從長吉，不遣橘奴覓李衡。", "四山濃淡要題品，百卉後先宜按行。", "登覽不憂風雨迫，揮戈須駐日西傾。"]'),
('525e5b46-4d2e-4d82-ae6e-afaeb1b7bc82','諸公出遊有翼有詩和者盈軸次日飲正卿家出以示余走筆繼韻','曾協','宋','宋诗','song-poetry','','[]','可堪俗事苦相留，不許聯翩李郭舟。',64,'全唐诗/poet.song.120000.json','["可堪俗事苦相留，不許聯翩李郭舟。", "酒興定知鯨浪吸，詞源聊看峽江流。", "名如北斗誰能挹，價重連城未易酬。", "恰似西都數人物，校書中秘讓諸劉。"]'),
('d9812eda-df2c-4101-9148-64e52bf2b6e4','有翼有詩督真率第二會次韻','曾協','宋','宋诗','song-poetry','','[]','滿眼春光處處山，妨人行樂幾多端。',64,'全唐诗/poet.song.120000.json','["滿眼春光處處山，妨人行樂幾多端。", "絕憐玄圃一步地，便勝香山八節灘。", "莫放賞心閑裏過，擬將物化靜中觀。", "未開桃李留春事，可是芳苞不耐寒。"]'),
('0ec0ec7d-f5f9-4b1a-9fad-daabade0f4a1','送裘父姪還鄉二首  其一','曾協','宋','宋诗','song-poetry','','[]','氣吐長虹一世豪，尚憐花草助風騷。',64,'全唐诗/poet.song.120000.json','["氣吐長虹一世豪，尚憐花草助風騷。", "正須重碧澆胸次，不遣輕霜上鬢毛。", "浪說清時敞東閣，誰捐好語到西曹。", "江神却解歸歟興，賸放潮頭百尺高。"]'),
('f0670456-8631-4faa-a4df-f438eb50e913','送裘父姪還鄉二首  其二','曾協','宋','宋诗','song-poetry','','[]','塵外情懷得自由，便携琴鶴上歸舟。',64,'全唐诗/poet.song.120000.json','["塵外情懷得自由，便携琴鶴上歸舟。", "露寒月白關心夜，山瘦江清滿意秋。", "却背京城無眷戀，去尋古迹有遲留。", "奚奴莫厭詩囊滿，重紀山川爛漫遊。"]'),
('ea713b7d-02ca-4337-9f9e-8fafc0260d23','代常州請平江鄭侍郎','曾協','宋','宋诗','song-poetry','','[]','接壤西東似犬牙，一時迎送使君車。',64,'全唐诗/poet.song.120000.json','["接壤西東似犬牙，一時迎送使君車。", "應憐壯歲棠陰在，未覺神京驛路賒。", "飛觀慣看凉月挂，層樓將見瑞雲遮。", "當筵莫訴盃行速，兩地春光作一家。"]'),
('0ee18077-d897-4483-891c-db8f1305d8e9','代人上平江徐侍郎五首  其一','曾協','宋','宋诗','song-poetry','','[]','秋到人間斂麴塵，于門初見矞星辰。',64,'全唐诗/poet.song.120000.json','["秋到人間斂麴塵，于門初見矞星辰。", "須知宇內風雲合，况是天邊雨露新。", "盛德可容窺底藴，殊功端自見經綸。", "不應久袖安邦手，運指從教轉大鈞。"]'),
('9a93fc01-1497-49c6-8304-ddff971d2558','代人上平江徐侍郎五首  其二','曾協','宋','宋诗','song-poetry','','[]','漢朝法從讓嚴徐，却數羣公總不如。',64,'全唐诗/poet.song.120000.json','["漢朝法從讓嚴徐，却數羣公總不如。", "千載流芳傳竹簡，一言偃革見囊書。", "由來東海傳高閣，復見甘泉載後車。", "富貴功名兩相似，崑丘元自產璠璵。"]'),
('f6d1af4d-92ea-48f4-abc7-9793a049abaf','代人上平江徐侍郎五首  其三','曾協','宋','宋诗','song-poetry','','[]','雙旌來自日華邊，帝遣銜恩下九天。',64,'全唐诗/poet.song.120000.json','["雙旌來自日華邊，帝遣銜恩下九天。", "膏澤已周家十萬，道途不歎驛三千。", "封疆舊占江湖闊，驩頌新從里巷傳。", "可是聖朝私此地，教將和氣作豐年。"]'),
('f89aeeed-bf58-4b4b-8ec3-0af5957de9fd','代人上平江徐侍郎五首  其四','曾協','宋','宋诗','song-poetry','','[]','巍峨冠冕聳精神，好傍軒墀對紫宸。',64,'全唐诗/poet.song.120000.json','["巍峨冠冕聳精神，好傍軒墀對紫宸。", "一德擬推黄帝筴，紀年還數絳人旬。", "懸知紫詔馳三節，肯使朱轓駐兩輪。", "聞說邦人稱壽處，香雲低覆玉嶙峋。"]'),
('0a5668e8-1215-4b73-ac87-9d8a58bf4040','代人上平江徐侍郎五首  其五','曾協','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','哦詩獻壽信知難，門館材多不可攀。',64,'全唐诗/poet.song.120000.json','["哦詩獻壽信知難，門館材多不可攀。", "敢曳長裾居客右，祇容濫吹列行間。", "爲陵便恐輕深谷，若礪還應誓泰山。", "千載通明宮殿裏，常看冠珮壓清班。"]'),
('08c02f7b-b4fd-4017-a1cb-0f01fb99c59f','紫巖雜詠 飛瀑','曾協','宋','宋诗','song-poetry','','[]','欲作銀河落，支筇仰面看。',24,'全唐诗/poet.song.120000.json','["欲作銀河落，支筇仰面看。", "會須雷電散，已覺逼人寒。"]'),
('1889f340-c5d3-42a3-b7f3-8bbd623efd56','紫巖雜詠 坳池','曾協','宋','宋诗','song-poetry','','[]','峭絕崩雲處，泓澄忽此逢。',24,'全唐诗/poet.song.120000.json','["峭絕崩雲處，泓澄忽此逢。", "寧知一勺水，清潤入千峰。"]'),
('ac4c8ef2-bfe1-4435-a1ca-e821ab1ea170','紫巖雜詠 留煙','曾協','宋','宋诗','song-poetry','','[]','暝色蒼然至，浮煙漫不分。',24,'全唐诗/poet.song.120000.json','["暝色蒼然至，浮煙漫不分。", "小留巖竇底，爲伴宿簷雲。"]'),
('d92917d0-83b3-461d-9f45-03d28dca8160','紫巖雜詠 濺石','曾協','宋','宋诗','song-poetry','','[]','淅瀝排炎暑，潺湲弄晚晴。',24,'全唐诗/poet.song.120000.json','["淅瀝排炎暑，潺湲弄晚晴。", "不知來遠近，常作對床聲。"]'),
('c4cc9d89-a9cf-462b-a43c-1d884afacd80','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其一','曾協','宋','宋诗','song-poetry','','[]','盛世須材傑，高名動聖明。',24,'全唐诗/poet.song.120000.json','["盛世須材傑，高名動聖明。", "一麾淮海去，青旆擁千兵。"]'),
('fdca1c9d-b9b7-4898-adea-d53f713fe660','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其二','曾協','宋','宋诗','song-poetry','','[]','別兄今幾時，邦人指難弟。',24,'全唐诗/poet.song.120000.json','["別兄今幾時，邦人指難弟。", "莫誦海沂康，兩馮如魯衛。"]'),
('10a6aacf-3a5a-4842-a938-e8ac220373ff','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其三','曾協','宋','宋诗','song-poetry','','[]','公材如武庫，劍槊方森森。',24,'全唐诗/poet.song.120000.json','["公材如武庫，劍槊方森森。", "亦復擅風流，坐繼正始音。"]'),
('f6536213-5c89-4aac-8d98-ef88fd9c1a91','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其四','曾協','宋','宋诗','song-poetry','','[]','詩成嘯諾餘，謀出壺觴暇。',24,'全唐诗/poet.song.120000.json','["詩成嘯諾餘，謀出壺觴暇。", "却整進賢冠，麒麟要圖畫。"]'),
('12034b1d-0791-4904-90f3-e9f79b8982f2','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其五','曾協','宋','宋诗','song-poetry','','[]','公家西州烈，武事冠方冊。',24,'全唐诗/poet.song.120000.json','["公家西州烈，武事冠方冊。", "祖孫世有人，要足門三戟。"]'),
('6a79caca-2f29-4655-bc86-cfe6e50eea0d','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其六','曾協','宋','宋诗','song-poetry','','[]','平生功名心，不肯事酣宴。',24,'全唐诗/poet.song.120000.json','["平生功名心，不肯事酣宴。", "向來話淮南，山川眼中見。"]'),
('b427e7bf-907e-4026-83d2-e70dbd720553','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其七','曾協','宋','宋诗','song-poetry','','[]','楚國尚勇力，秉羽而甘寢。',24,'全唐诗/poet.song.120000.json','["楚國尚勇力，秉羽而甘寢。", "雖無倒載名，勝飲懷安鴆。"]'),
('1bcec47c-9252-4322-b61d-a1eb1443e751','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其八','曾協','宋','宋诗','song-poetry','','[]','疆事須長算，朝家得實能。',24,'全唐诗/poet.song.120000.json','["疆事須長算，朝家得實能。", "坐來酬萬務，心地自虛凝。"]'),
('74b6773a-b63a-4608-b825-5a7aaa6ce42b','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其九','曾協','宋','宋诗','song-poetry','','[]','復旦風雲合，丹心日月明。',24,'全唐诗/poet.song.120000.json','["復旦風雲合，丹心日月明。", "江神迴朗照，霽色向來清。"]'),
('8428f0a7-c622-4123-b54f-f29dabe6551c','送王炎弼赴山陽守以兵衛森畫戟宴寢凝清香爲韻十首  其一○','曾協','宋','宋诗','song-poetry','','[]','壺矢新油幕，春蕪舊戰場。',24,'全唐诗/poet.song.120000.json','["壺矢新油幕，春蕪舊戰場。", "候亭閒夜柝，歸袖著天香。"]'),
('653f22b7-dde3-426d-b007-ba8dd1ed097a','山雲','曾協','宋','宋诗','song-poetry','','[]','自聳干霄勢，應憐望歲心。',24,'全唐诗/poet.song.120000.json','["自聳干霄勢，應憐望歲心。", "試將膚寸澤，來作濟時霖。"]'),
('bc43af08-4356-4792-a261-94910559dc14','小山叢桂','曾協','宋','宋诗','song-poetry','','[]','暗綠團團樹，浮蒼淺淺山。',24,'全唐诗/poet.song.120000.json','["暗綠團團樹，浮蒼淺淺山。", "不須吟些些，幽韻已班班。"]'),
('419ba58b-7dcb-4673-bff1-1d4de25cbffd','題留煙亭','曾協','宋','宋诗','song-poetry','','[]','漠漠縈空漫不收，只應此地占清幽。',32,'全唐诗/poet.song.120000.json','["漠漠縈空漫不收，只應此地占清幽。", "雲煙本是無心物，亦爲山人重挽留。"]'),
('00c28477-0c8f-4da9-b87c-12f52787a67b','題零陵郡治環翠亭','曾協','宋','宋诗','song-poetry','','[]','鈴索無聲訟牒稀，雨餘四野競扶犂。',32,'全唐诗/poet.song.120000.json','["鈴索無聲訟牒稀，雨餘四野競扶犂。", "小亭獨坐心無事，滿地綠陰山鳥啼。"]'),
('15105322-4cbb-4bf2-8da7-64453a94f8f0','醒心亭','曾協','宋','宋诗','song-poetry','','[]','主人誰與解春酲，百斛香醪一小亭。',32,'全唐诗/poet.song.120000.json','["主人誰與解春酲，百斛香醪一小亭。", "兀兀泠泠俱可樂，醒來還醉醉還醒。"]'),
('1f424046-10f4-4c73-8c7a-6e770b3a0569','荻華渚','曾協','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','摇摇小渚荻初成，遠意渾疑接洞庭。',32,'全唐诗/poet.song.120000.json','["摇摇小渚荻初成，遠意渾疑接洞庭。", "准擬秋來看積雪，更和風雨醉時聽。"]'),
('e4c4d6a6-b1e6-4b49-abb4-4186bba97534','睡足軒','曾協','宋','宋诗','song-poetry','','[]','落盡庭花日未西，枝間栩栩定爲誰。',32,'全唐诗/poet.song.120000.json','["落盡庭花日未西，枝間栩栩定爲誰。", "遥知城市紛紛際，正是幽人睡足時。"]'),
('7c46f7ff-3d28-4321-83ff-67978ab4df7a','潔泉','曾協','宋','宋诗','song-poetry','','[]','絕愛泓然一鑑渟，肯教塵土犯清泠。',32,'全唐诗/poet.song.120000.json','["絕愛泓然一鑑渟，肯教塵土犯清泠。", "祇緣較德先生似，不爲爭名陸羽經。"]'),
('0197c5a1-b535-447e-b546-edcc16e9c1c8','清富庵','曾協','宋','宋诗','song-poetry','','[]','一衲纏身便有餘，亂山深處卜幽居。',32,'全唐诗/poet.song.120000.json','["一衲纏身便有餘，亂山深處卜幽居。", "舉頭物物皆呈露，試問金多得似無。"]'),
('12a79125-6618-4803-8291-b23ff2edbaf0','薝蔔林','曾協','宋','宋诗','song-poetry','','[]','可人濃翠護微黄，寶樹森森自著行。',32,'全唐诗/poet.song.120000.json','["可人濃翠護微黄，寶樹森森自著行。", "居士飯餘無一事，坐來還印寂然香。"]'),
('ce33addf-0b41-418d-af05-97532f35a886','凝香逕','曾協','宋','宋诗','song-poetry','','[]','白葛烏紗一逕長，心清草木自成香。',32,'全唐诗/poet.song.120000.json','["白葛烏紗一逕長，心清草木自成香。", "何須爐裏煙成縷，不用衣間紫作囊。"]'),
('758bf0ec-4c9b-4876-b40e-e8fdf66ff5c9','野菊澗','曾協','宋','宋诗','song-poetry','','[]','泠泠清漲濯秋芳，採擷堪供九日觴。',32,'全唐诗/poet.song.120000.json','["泠泠清漲濯秋芳，採擷堪供九日觴。", "爲乞曉瓶真沆瀣，不應眉壽獨南陽。"]'),
('d4ad1452-3c84-493b-a027-caa55f264aa3','遊罨畫溪  其一','曾協','宋','宋诗','song-poetry','','[]','春去無蹤綠滿堤，空移征棹過漣漪。',32,'全唐诗/poet.song.120000.json','["春去無蹤綠滿堤，空移征棹過漣漪。", "自驚朱墨抽身晚，不及青紅倒影時。"]'),
('044ede28-f5ea-411b-bece-fa517d0a618e','遊罨畫溪  其二','曾協','宋','宋诗','song-poetry','','[]','罨畫溪頭事已空，桑條都逐運斤風。',32,'全唐诗/poet.song.120000.json','["罨畫溪頭事已空，桑條都逐運斤風。", "東君綠遍當時岸，只欠低垂照水紅。"]'),
('431d5c9f-c391-47fd-ae08-e4410c3472ca','遊罨畫溪  其三','曾協','宋','宋诗','song-poetry','','[]','罨畫聲名遠近知，水光花影巧相宜。',32,'全唐诗/poet.song.120000.json','["罨畫聲名遠近知，水光花影巧相宜。", "不知此去幾多日，重見斕斑似舊時。"]'),
('9df33da5-d176-4150-bbb7-0ec1ca037442','芭蕉','曾協','宋','宋诗','song-poetry','','[]','炎蒸誰解換清凉，扇影摇摇上竹窗。',32,'全唐诗/poet.song.120000.json','["炎蒸誰解換清凉，扇影摇摇上竹窗。", "準擬小軒添睡美，夢成風雨夜翻江。"]'),
('9196686b-cded-41b4-8256-722fb776418f','西溪冬夜','曾協','宋','宋诗','song-poetry','','[]','並堤松柏與雲齊，月夜青山一望低。',32,'全唐诗/poet.song.120000.json','["並堤松柏與雲齊，月夜青山一望低。", "山鳥不驚人迹絕，步隨流水到前溪。"]'),
('cf2a8b8d-c3ed-4e92-a676-3597a49cbda0','偶作二首  其一','曾協','宋','宋诗','song-poetry','','[]','身閒贏得閉齋房，不向塵中染色香。',32,'全唐诗/poet.song.120000.json','["身閒贏得閉齋房，不向塵中染色香。", "靜處試尋真面目，光陰非短亦非長。"]'),
('15467c77-147c-4597-a194-6ed13ec1be4f','偶作二首  其二','曾協','宋','宋诗','song-poetry','','[]','世人言語盡君房，一一班聯玉殿香。',32,'全唐诗/poet.song.120000.json','["世人言語盡君房，一一班聯玉殿香。", "解識逍遥渾一致，水鳧非短鶴非長。"]'),
('1daf2b98-bc63-41ef-9b66-7b4098ea3758','和史侍郎遊澹巖韻六首  其一','曾協','宋','宋诗','song-poetry','','[]','底歎茲巖省見稀，慣居故國看山圍。',32,'全唐诗/poet.song.120000.json','["底歎茲巖省見稀，慣居故國看山圍。", "應緣此日慰岑寂，聊遣清詩爲發揮。"]'),
('a83cdd5e-12c3-476c-ab74-a9964091ad50','和史侍郎遊澹巖韻六首  其二','曾協','宋','宋诗','song-poetry','','[]','瀟湘少駐便經年，自信孤忠莫問天。',32,'全唐诗/poet.song.120000.json','["瀟湘少駐便經年，自信孤忠莫問天。", "果爲冕旒勤注想，不容泉石得高眠。"]'),
('556f97d0-17e0-48f4-ba4c-e6a09d6be025','和史侍郎遊澹巖韻六首  其三','曾協','宋','宋诗','song-poetry','','[]','隱士洪崖可拍肩，尚留陳迹此山巔。',32,'全唐诗/poet.song.120000.json','["隱士洪崖可拍肩，尚留陳迹此山巔。", "祇應千古人如在，陵谷高深却變遷。"]'),
('1fddb3c5-795e-4d7c-b31a-da3bd2eb9af4','和史侍郎遊澹巖韻六首  其四','曾協','宋','宋诗','song-poetry','','[]','九重溫詔下江邊，應覽甘泉舊奏篇。',32,'全唐诗/poet.song.120000.json','["九重溫詔下江邊，應覽甘泉舊奏篇。", "却背煙嵐理歸棹，曉猿夜鶴總凄然。"]'),
('dfda487b-ea06-4f32-bd9f-a97584f3ad9e','和史侍郎遊澹巖韻六首  其五','曾協','宋','宋诗','song-poetry','','[]','我公得入如來室，心鏡常明不用磨。',32,'全唐诗/poet.song.120000.json','["我公得入如來室，心鏡常明不用磨。", "好倚懸崖結趺座，任從來者問云何。"]'),
('003b6d78-e6e2-44b5-8682-8582eaac0dac','和史侍郎遊澹巖韻六首  其六','曾協','宋','宋诗','song-poetry','','[]','眼看巖石千尋起，面對爐煙一縷輕。',32,'全唐诗/poet.song.120000.json','["眼看巖石千尋起，面對爐煙一縷輕。", "頓覺世緣無染著，箇中消息有誰明。"]'),
('0a9213d4-a0c5-4e0b-93f6-03f2915e4724','督幾先畫','曾協','宋','宋诗','song-poetry','','[]','北固江山自有餘，不分清景到繩樞。',32,'全唐诗/poet.song.120000.json','["北固江山自有餘，不分清景到繩樞。", "憑君筆底真三昧，幻出雲煙入坐隅。"]'),
('7ac631f3-7245-4daa-81c0-b75d30b8be54','李粹伯命賦枕流已讀佳篇不容著語戲書二伽陀問之  其一','曾協','宋','宋诗','song-poetry','','[]','六尺玲瓏日日開，箇中那解著纖埃。',32,'全唐诗/poet.song.120000.json','["六尺玲瓏日日開，箇中那解著纖埃。", "主人無耳誰求洗，試問聲從何處來。"]'),
('a7e87ebf-e978-4ddf-afa1-2604cfe5c846','李粹伯命賦枕流已讀佳篇不容著語戲書二伽陀問之  其二','曾協','宋','宋诗','song-poetry','','[]','水軒宴坐死灰同，一息呼號萬竅風。',32,'全唐诗/poet.song.120000.json','["水軒宴坐死灰同，一息呼號萬竅風。", "縱有溪流清似鏡，不知何處洗虛空。"]'),
('417a662f-e807-4096-b6f0-86de3f8fcd95','和剡宰二首  其一','曾協','宋','宋诗','song-poetry','','[]','綠陰匼匝欲周阿，正午庭空雀可羅。',32,'全唐诗/poet.song.120000.json','["綠陰匼匝欲周阿，正午庭空雀可羅。", "更許瘦筇支病骨，玉山影裏聽絃歌。"]'),
('2f856eda-3883-4743-b62a-877afc3afe31','和剡宰二首  其二','曾協','宋','宋诗','song-poetry','','[]','點數詩流一唯阿，胸中星斗想森羅。',32,'全唐诗/poet.song.120000.json','["點數詩流一唯阿，胸中星斗想森羅。", "新篇莫浪傳紅粉，堪與朱絃薦詠歌。"]'),
('932f8273-c6af-4f21-9184-fbf06a954a9f','月夜再和','曾協','宋','宋诗','song-poetry','','[]','月當亭午憩纖阿，擬逐香風到大羅。',32,'全唐诗/poet.song.120000.json','["月當亭午憩纖阿，擬逐香風到大羅。", "急作新詩報天上，更憑阿監一聲歌。"]'),
('5b19abd4-be4d-4d86-9fd5-d568ed2a5ab8','和韓子文五首  其一','曾協','宋','宋诗','song-poetry','','[]','密雲閣雨靳春晴，不放芒鞋取次行。',32,'全唐诗/poet.song.120000.json','["密雲閣雨靳春晴，不放芒鞋取次行。", "却坐蒲團政無賴，好詩端爲破愁城。"]'),
('daae49dd-4249-4fd2-9bb5-aa61d436bb8d','和韓子文五首  其二','曾協','宋','宋诗','song-poetry','','[]','雪痕尚使石泉潤，山色不堪煙雨昏。',32,'全唐诗/poet.song.120000.json','["雪痕尚使石泉潤，山色不堪煙雨昏。", "見說樹頭春意動，從頭花柳看村村。"]'),
('78ea5e34-19b4-4d3a-b8ee-899ed0fd01b9','和韓子文五首  其三','曾協','宋','宋诗','song-poetry','','[]','與君聯轡聽冬瓏，下馬荀陳列座中。',32,'全唐诗/poet.song.120000.json','["與君聯轡聽冬瓏，下馬荀陳列座中。", "南北東西鄉國異，笑談天與一尊同。"]'),
('26c8d6ee-eee5-49fa-84f4-fd3c1d0b7ca6','和韓子文五首  其四','曾協','宋','宋诗','song-poetry','','[]','誰人解遣醉時醒，始變鳴禽第一聲。',32,'全唐诗/poet.song.120000.json','["誰人解遣醉時醒，始變鳴禽第一聲。", "似向幽人催蠟屐，水邊沙際看春生。"]'),
('4e3ed3c1-45a5-4b64-a9fd-6aed419eb2fb','和韓子文五首  其五','曾協','宋','宋诗','song-poetry','','[]','寒淺定知春已至，意閑仍覺日初長。',32,'全唐诗/poet.song.120000.json','["寒淺定知春已至，意閑仍覺日初長。", "已諳榮謝如空幻，一室蕭然且坐忘。"]'),
('35d6577b-560e-42ee-9418-97ab5663aca7','和翁士秀瑞香水仙二首  其一','曾協','宋','宋诗','song-poetry','','[]','蝶遶蜂團碧玉叢，紫羅囊小透香風。',32,'全唐诗/poet.song.120000.json','["蝶遶蜂團碧玉叢，紫羅囊小透香風。", "自從鼻觀銷煩惱，疑在維摩丈室中。"]'),
('1315a0e2-4259-4b9c-a2c3-d60302b11d29','和翁士秀瑞香水仙二首  其二','曾協','宋','宋诗','song-poetry','','[]','正白深黄態自濃，不將紅粉作華容。',32,'全唐诗/poet.song.120000.json','["正白深黄態自濃，不將紅粉作華容。", "却疑洛浦波心見，合向瑶臺月下逢。"]'),
('5dc756a9-82b2-471f-aeb9-4798eed0ed7b','上平江徐侍郎十絕句  其一','曾協','宋','宋诗','song-poetry','','[]','露華先遣麴塵收，要產英豪奠九州。',32,'全唐诗/poet.song.120000.json','["露華先遣麴塵收，要產英豪奠九州。", "織女槎迴逢八月，老人星見恰中秋。"]'),
('37075a06-9bae-466c-b72f-4d4c9e76912c','上平江徐侍郎十絕句  其二','曾協','宋','宋诗','song-poetry','','[]','聲華奕世擅江南，誰似公家伯仲間。',32,'全唐诗/poet.song.120000.json','["聲華奕世擅江南，誰似公家伯仲間。", "想見當年育英物，高秋爽氣滿西山。"]'),
('98451233-b1ef-414e-95d7-3d7230948394','上平江徐侍郎十絕句  其三','曾協','宋','宋诗','song-poetry','','[]','盛德由來自邈綿，偃王功德至今傳。',32,'全唐诗/poet.song.120000.json','["盛德由來自邈綿，偃王功德至今傳。", "朱弓赤矢符嘉瑞，留得陰功不計年。"]'),
('2c875802-153c-4cb7-b0e1-66affb8b0dbe','上平江徐侍郎十絕句  其四','曾協','宋','宋诗','song-poetry','','[]','並列西京侍從多，吾丘司馬豈同科。',32,'全唐诗/poet.song.120000.json','["並列西京侍從多，吾丘司馬豈同科。", "孤忠祇有囊書在，獨見丁寧爲偃戈。"]'),
('b3fad6ac-779d-4a63-9a3a-d3150fa6eb9f','上平江徐侍郎十絕句  其五','曾協','宋','宋诗','song-poetry','','[]','五湖城郭带重樓，幕府初開第一州。',32,'全唐诗/poet.song.120000.json','["五湖城郭带重樓，幕府初開第一州。", "燕寢香凝了無事，四郊禾穗自盈疇。"]'),
('7354b20e-86f7-47b9-a5cf-ecd515726fc6','上平江徐侍郎十絕句  其六','曾協','宋','宋诗','song-poetry','','[]','繞郭舊稱家十萬，朝天常恨驛三千。',32,'全唐诗/poet.song.120000.json','["繞郭舊稱家十萬，朝天常恨驛三千。", "而今已是繁華倍，更覺旌麾近日邊。"]'),
('5e322d0b-4020-42ba-b0e9-558490012eb3','上平江徐侍郎十絕句  其七','曾協','宋','宋诗','song-poetry','','[]','不但寬平似有功，筆端重睹建安風。',32,'全唐诗/poet.song.120000.json','["不但寬平似有功，筆端重睹建安風。", "邦人競勸金鍾釂，願見君侯聖一中。"]'),
('f03cd603-2e91-4793-a87b-d34f88bfd49a','上平江徐侍郎十絕句  其八','曾協','宋','宋诗','song-poetry','','[]','雅歌字字巧安排，爭頌君王治道諧。',32,'全唐诗/poet.song.120000.json','["雅歌字字巧安排，爭頌君王治道諧。", "好把抉猊奔驥手，大書深刻著懸崖。"]'),
('fa165949-74c3-4c83-a0a0-e8c0a2bd11e3','上平江徐侍郎十絕句  其九','曾協','宋','宋诗','song-poetry','','[]','擁麾仗節往來頻，撫字澄清處處新。',32,'全唐诗/poet.song.120000.json','["擁麾仗節往來頻，撫字澄清處處新。", "想見茲辰介眉壽，遥應驩動幾州人。"]'),
('2acc2fa4-01d3-43b8-9eaa-6f30d95c6f4f','上平江徐侍郎十絕句  其一○','曾協','宋','宋诗','song-poetry','','[]','槐鼎虛班側席求，已應難遂寇恂留。',32,'全唐诗/poet.song.120000.json','["槐鼎虛班側席求，已應難遂寇恂留。", "不如黄髮貂蟬底，長占青雲最上頭。"]'),
('cfd4258e-6c21-4781-bed5-ef86a779d536','老農十首  其一','曾協','宋','宋诗','song-poetry','','[]','雨带好風勻浄綠，雲開暖日染嬌黄。',32,'全唐诗/poet.song.120000.json','["雨带好風勻浄綠，雲開暖日染嬌黄。", "今年不識農家苦，總把陰晴屬上蒼。"]'),
('f61a8845-e68c-4273-94fc-8a3821ca5de6','老農十首  其二','曾協','宋','宋诗','song-poetry','','[]','荷笠腰鐮醉裏回，和衣卧處息如雷。',32,'全唐诗/poet.song.120000.json','["荷笠腰鐮醉裏回，和衣卧處息如雷。", "定無門外催租吏，贏得柴荆日晏開。"]'),
('9b6b9803-5b07-4987-8f18-95e774218119','老農十首  其三','曾協','宋','宋诗','song-poetry','','[]','朝家寬詔年年下，天上秋陽日日明。',32,'全唐诗/poet.song.120000.json','["朝家寬詔年年下，天上秋陽日日明。", "租稅入官公事了，壤歌遞與子孫賡。"]'),
('1aee9548-9878-4e91-a49e-c9e927b7c446','老農十首  其四','曾協','宋','宋诗','song-poetry','','[]','聞說邊隅長草萊，漢家膚使漠南迴。',32,'全唐诗/poet.song.120000.json','["聞說邊隅長草萊，漢家膚使漠南迴。", "黍苗正自歸倉廩，不怕西風卷地來。"]'),
('893839c9-5d65-4257-9489-92dfafcdab79','老農十首  其五','曾協','宋','宋诗','song-poetry','','[]','田疇總是十分苗，處處逢人意氣驕。',32,'全唐诗/poet.song.120000.json','["田疇總是十分苗，處處逢人意氣驕。", "不問神祠賽簫鼓，君臣有道四時調。"]'),
('03a09cb2-9f41-47f9-98fb-c7da7b2b44ce','老農十首  其六','曾協','宋','宋诗','song-poetry','','[]','敢將體足憚霑塗，日日高原带雨鋤。',32,'全唐诗/poet.song.120000.json','["敢將體足憚霑塗，日日高原带雨鋤。", "乞與豐年酬作苦，也知天意解乘除。"]'),
('c298cdcc-af1d-4fc4-94f8-185c1479b3c2','老農十首  其七','曾協','宋','宋诗','song-poetry','','[]','歸牛將犢茅簷晚，饑鳥窺人稻圃秋。',32,'全唐诗/poet.song.120000.json','["歸牛將犢茅簷晚，饑鳥窺人稻圃秋。", "准擬明年大作社，雞豚須養秫須留。"]'),
('a7513bfe-569d-4f5f-acdd-bee73177caaa','老農十首  其八','曾協','宋','宋诗','song-poetry','','[]','飽食豐年酒不空，水村山崦老於農。',32,'全唐诗/poet.song.120000.json','["飽食豐年酒不空，水村山崦老於農。", "囷倉在眼心無事，鄰里經過樂歲窮。"]'),
('8847d7f9-9ac4-437f-832b-989b6b0124b3','老農十首  其九','曾協','宋','宋诗','song-poetry','','[]','兒孫力作莫辭勤，仁政如天四海春。',32,'全唐诗/poet.song.120000.json','["兒孫力作莫辭勤，仁政如天四海春。", "盡說干湯功已就，澤流莘野並耕人。"]'),
('eaad3703-1900-41e8-b6ce-3f24adc84494','老農十首  其一○','曾協','宋','宋诗','song-poetry','','[]','淮上營屯盡偃戈，官軍從此罷經過。',32,'全唐诗/poet.song.120000.json','["淮上營屯盡偃戈，官軍從此罷經過。", "且書太史豐年瑞，不數周公異畝禾。"]'),
('1622336f-b25b-4b2b-bcbf-e14a5d5126ca','和叔武逢梅二首  其一','曾協','宋','宋诗','song-poetry','','[]','愛花不厭百迴看，細數香鬚定若干。',32,'全唐诗/poet.song.120000.json','["愛花不厭百迴看，細數香鬚定若干。", "莫怨東風消息早，爲憑佳句喚司寒。"]'),
('f4f8f8e0-3a7f-4960-bb83-706c2fe02de0','和叔武逢梅二首  其二','曾協','宋','宋诗','song-poetry','','[]','愁中相對病中看，喜慍都忘非意干。',32,'全唐诗/poet.song.120000.json','["愁中相對病中看，喜慍都忘非意干。", "從此定交形迹外，只羞冰玉照人寒。"]'),
('c916687d-c591-4d60-92d7-84f8f8c11ee0','再和前韻三首  其一','曾協','宋','宋诗','song-poetry','','[]','騷人豈作腐儒酸，逸氣清霄坐可干。',32,'全唐诗/poet.song.120000.json','["騷人豈作腐儒酸，逸氣清霄坐可干。", "東閣只今詩興動，韓豪元不似郊寒。"]'),
('7241d596-5672-4642-96d5-f546e4eced5b','再和前韻三首  其二','曾協','宋','宋诗','song-poetry','','[]','幽姿健骨兩相看，二絕真成聚莫干。',32,'全唐诗/poet.song.120000.json','["幽姿健骨兩相看，二絕真成聚莫干。", "好學紉蘭供楚佩，瓊琚端可勝金寒。"]'),
('e8ddb172-c1fa-4b0a-a75f-de3e09e7a251','再和前韻三首  其三','曾協','宋','宋诗','song-poetry','','[]','猛士相逢亦破顔，恰如組練壯師干。',32,'全唐诗/poet.song.120000.json','["猛士相逢亦破顔，恰如組練壯師干。", "誰令野宿三更月，綴鐵成衣徹骨寒。"]'),
('0fe89d59-1d24-485f-ade7-562b284ac959','春至無梅追用前韻一首','曾協','宋','宋诗','song-poetry','','[]','爲覓梢頭一點酸，縹枝紅萼謾闌干。',32,'全唐诗/poet.song.120000.json','["爲覓梢頭一點酸，縹枝紅萼謾闌干。", "東君已誤當時約，猶歛幽芳待歲寒。"]'),
('68688aab-dbb3-4622-b44e-78704119efc5','和粹伯七夕韻  其一','曾協','宋','宋诗','song-poetry','','[]','常時淚雨久漣洳，准擬晴窗叫勃姑。',32,'全唐诗/poet.song.120000.json','["常時淚雨久漣洳，准擬晴窗叫勃姑。", "報答月華思善畫，便和風露入新圖。"]'),
('bb3e8d3a-a9e7-4b3a-bdcb-d70cda8552de','和粹伯七夕韻  其二','曾協','宋','宋诗','song-poetry','','[]','天上相逢絕點塵，莫將世態測高真。',32,'全唐诗/poet.song.120000.json','["天上相逢絕點塵，莫將世態測高真。", "深閨兒女傳聞誤，見說秋期便妬人。"]'),
('b3bf66ac-63b7-4fee-b33d-6ae213ff00a3','和粹伯七夕韻  其三','曾協','宋','宋诗','song-poetry','','[]','誰紀天孫謫墮時，浪言能致古宣尼。',32,'全唐诗/poet.song.120000.json','["誰紀天孫謫墮時，浪言能致古宣尼。", "只今天上秋宵短，莫近雞星聽喔咿。"]'),
('03a2cbfc-59a2-49a0-b210-568cd63c4b77','和史志道侍郎  其一','曾協','宋','宋诗','song-poetry','','[]','經行犖确看嶙峋，曳履枝筇躡後塵。',64,'全唐诗/poet.song.120000.json','["經行犖确看嶙峋，曳履枝筇躡後塵。", "自是高懷元落落，向來喜色見津津。", "宜搜今古風流遠，得助江山句法新。", "好逐秋風上霄漢，却留盛事付州人。"]'),
('732dde85-eca4-4e8b-a99b-ba4d2a96fd4b','和史志道侍郎  其二','曾協','宋','宋诗','song-poetry','','[]','簿書堆案阻尋幽，想像高人物外遊。',64,'全唐诗/poet.song.120000.json','["簿書堆案阻尋幽，想像高人物外遊。", "自昔品題多北客，故知物象勝中州。", "雲經亂石餘膏潤，煙過懸崖自去留。", "暫俯澄潭倚蒼壁，已疑身世在鼇頭。"]'),
('ee946ffc-9dbc-4cc1-892d-a97f9fdf3f01','和史志道侍郎  其三','曾協','宋','宋诗','song-poetry','','[]','興來小渡喚方舟，霽色天教足勝游。',64,'全唐诗/poet.song.120000.json','["興來小渡喚方舟，霽色天教足勝游。", "但覺賞心追昔事，不知飛詔下皇州。", "班行便覺九天近，登覽何辭一日留。", "懸想他時百僚上，亦思清景幾回頭。"]'),
('fae03acb-9b4e-454c-97a8-d449dfcfbd5d','句','嵊縣令','宋','宋诗','song-poetry','','[]','一時分付雪兒歌。',8,'全唐诗/poet.song.120000.json','["一時分付雪兒歌。"]'),
('fd51287b-3ad5-4d4d-8dae-d977e1de6429','偈頌九首  其一','釋玿','宋','宋诗','song-poetry','','[]','鵲既鳴鵲鵲，鴉則鳴鴉鴉。',52,'全唐诗/poet.song.120000.json','["鵲既鳴鵲鵲，鴉則鳴鴉鴉。", "禾山四打鼓，趙州三喫茶。", "春來花處處，雲散月家家。", "達磨當年無板齒，祇應特地過流沙。"]'),
('0bb86bae-6099-4601-b649-e0713bf838e0','偈頌九首  其二','釋玿','宋','宋诗','song-poetry','','[]','五五二十五，乖龍不爲雨。',70,'全唐诗/poet.song.120000.json','["五五二十五，乖龍不爲雨。", "沙石欲生煙，稻麻將槁死。", "山僧有箇七字頂輪王陀羅尼，能破龍宮。", "開蟄戶，斥雷師，驅電母，布慈雲而洒甘露。", "唵囌嚕悉唎囌嚕。"]'),
('027120d4-19cf-49d4-977a-ca7f1e9c9e22','偈頌九首  其三','釋玿','宋','宋诗','song-poetry','','[]','雲山偶爾遭攧，臂痛不可勝言。',277,'全唐诗/poet.song.120000.json','["雲山偶爾遭攧，臂痛不可勝言。", "府教揮金辦供，殷勤咨請談禪。", "禪禪，不在拈槌豎拂，亦非作用周旋。", "不在揚眉瞬目，亦非文字語言。", "祇據現成公案，自然七方八圓。", "在雲門得之，則曰一句三句。", "在法眼得之，則曰惟心法門。", "在溈仰得之，則曰父慈子孝。", "在臨濟得之，則曰三要三玄。", "在曹洞得之，則有偏正回互。", "在天下老和尚得之，則有問答機緣。", "在雲山得之，則全提正令於人天之上。", "在府教學士得之，則致吾君於堯舜之前。", "在現前大眾得之，則隨宜應用。", "在太孺人黄氏得之，則生於忉利諸天。", "禪禪，綿綿密密，密密綿綿。", "渡水胡僧無膝褲，東村王老屋頭穿。", "拈來一一中的，不妨似箭離絃。", "脫或躊躇擬議，迢迢十萬八千。"]'),
('1fb81787-168f-4368-a720-7990f0091874','偈頌九首  其四','釋玿','宋','宋诗','song-poetry','','[]','語是謗，寂是誑。',34,'全唐诗/poet.song.120000.json','["語是謗，寂是誑。", "不語不寂，轉增虛妄。", "春風吹落桃李花，淡煙疎雨籠青嶂。"]'),
('0ba9edc3-0f83-4aa6-8f90-725f81a31ad7','偈頌九首  其五','釋玿','宋','宋诗','song-poetry','','[]','向來雲岫訪雷峰，朔風吹雪落長松。',48,'全唐诗/poet.song.120000.json','["向來雲岫訪雷峰，朔風吹雪落長松。", "今日雷峰訪雲岫，無限春光滿巖竇。", "機鋒互換主賓分，八兩元來重半斤。"]'),
('5e087198-caba-4c4a-a701-a1d1e28184f8','偈頌九首  其六','釋玿','宋','宋诗','song-poetry','','[]','墾土誅茆作佛宮，栽田博飯與君同。',76,'全唐诗/poet.song.120000.json','["墾土誅茆作佛宮，栽田博飯與君同。", "夢中十載因緣盡，又拄烏藤過別峰。", "臨岐一句如何說，此去平分江上月。", "千里同風事宛然，雲山雖別何曾別。", "別不別，鷺鷥飛入寒江雪。"]'),
('18f37e4d-30d3-4930-92d2-0522a9b603bb','偈頌九首  其七','釋玿','宋','宋诗','song-poetry','','[]','與麽文彩，甚生標格。',20,'全唐诗/poet.song.120000.json','["與麽文彩，甚生標格。", "直下承當，迥超言默。"]'),
('2b60162a-ccde-4745-add4-1b1aad4ca0b1','偈頌九首  其八','釋玿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u6ed5\u738b\u9601"]','休卜度，世間那有揚州鶴。',76,'全唐诗/poet.song.120000.json','["休卜度，世間那有揚州鶴。", "一身與世等委蛇，萬事隨緣即安樂。", "無意來時却宛然，有心用處還應錯。", "錯錯錯，莫莫莫，近日秋林多葉落。", "鐵牛飛過洞庭湖，西山走入滕王閣。"]'),
('75bec81e-568b-4e44-9409-2c1d7a35ad1f','偈頌九首  其九','釋玿','宋','宋诗','song-poetry','','[]','一拳拳到黄鶴樓，一踢踢翻鸚鵡洲。',32,'全唐诗/poet.song.120000.json','["一拳拳到黄鶴樓，一踢踢翻鸚鵡洲。", "玉麟掣斷黄金鎖，大丈夫兒得自由。"]'),
('260682ad-c789-4ef2-96a1-aad2b0bcf0aa','頌古三十一首  其一','釋玿','宋','宋诗','song-poetry','','[]','文死罔明休卜度，瞿曇女子謾鍼錐。',32,'全唐诗/poet.song.120000.json','["文死罔明休卜度，瞿曇女子謾鍼錐。", "推倒鐵山歸去也，縱橫十字更由誰。"]'),
('5e9ea910-9fc7-4d50-ae12-0ed3450d27bc','頌古三十一首  其二','釋玿','宋','宋诗','song-poetry','','[]','相逢打鼓弄琵琶，須是還他兩會家。',32,'全唐诗/poet.song.120000.json','["相逢打鼓弄琵琶，須是還他兩會家。", "曲罷不知何處去，夕陽斜映暮天霞。"]'),
('34ffe1d7-eabc-49f9-b96c-8000babf8a02','頌古三十一首  其三','釋玿','宋','宋诗','song-poetry','','[]','身世悠悠不繫舟，得隨流處且隨流。',32,'全唐诗/poet.song.120000.json','["身世悠悠不繫舟，得隨流處且隨流。", "今朝有酒今朝醉，明日無錢明日愁。"]'),
('8b0c3230-afd5-4a03-9050-7717e4aa5062','頌古三十一首  其四','釋玿','宋','宋诗','song-poetry','','[]','夢中要渡深溪水，伎倆多般進不能。',32,'全唐诗/poet.song.120000.json','["夢中要渡深溪水，伎倆多般進不能。", "驀地覺來伎倆盡，牀頭山月已三更。"]');
